# Data source to get current AWS account ID and region
data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "primary"
}

# CloudWatch Log Group for Route 53 query logs
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/aws_route53_example_com"
  retention_in_days = 7
}

# CloudWatch Logs Resource Policy to allow Route 53 to write logs
resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Route53LogsToCloudWatchLogs"
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.aws_route53_example_com.arn}:*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
          ArnLike = {
            "aws:SourceArn" = "arn:aws:route53:::hostedzone/${aws_route53_zone.primary.zone_id}"
          }
        }
      }
    ]
  })
}

# Route 53 Query Logging Configuration
resource "aws_route53_query_log" "primary" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53_query_logging_policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

