# VPC for the hosted zone association
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Private Route 53 Hosted Zone
resource "aws_route53_zone" "private" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  tags = {
    Name = "private-hosted-zone"
  }
}

# Secondary VPC to associate with the hosted zone
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secondary-vpc"
  }
}

# Route 53 Hosted Zone Association
resource "aws_route53_zone_association" "secondary" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}

# Example DNS record in the private hosted zone
resource "aws_route53_record" "example" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "app.example.internal"
  type    = "A"
  ttl     = 300
  records = ["10.0.1.10"]
}

