resource "aws_route53_health_check" "replica_us_east" {
  provider          = aws.main
  fqdn              = aws_db_instance.replica_us_east.address
  port              = 3306
  type              = "TCP"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "replica-us-east-health-check"
  }
}

resource "aws_route53_health_check" "replica_eu_central" {
  provider          = aws.main
  fqdn              = aws_db_instance.replica_eu_central.address
