provider "aws" {
  region = "us-east-1"
}

# Reverse DNS Zone (for PTR records, typically in-addr.arpa format)
# Example: 1.0.10.in-addr.arpa for 10.0.1.0/24 network
resource "aws_route53_zone" "reverse_zone" {
  name = "1.0.10.in-addr.arpa"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  tags = {
    Name = "reverse_zone"
  }
}

# VPC for the private hosted zone
resource "aws_vpc" "main" {
  cidr_block           = "10.0.1.0/24"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# PTR Record for reverse DNS
# Example IP: 10.0.1.10 -> PTR record at 10.1.0.10.in-addr.arpa
resource "aws_route53_record" "ptr" {
  zone_id = aws_route53_zone.reverse_zone.zone_id
  name    = "10.1.0.10.in-addr.arpa"
  type    = "PTR"
  ttl     = 300
  records = ["host.example53.com"]
}

