# US-EAST-1 RESOURCES

# Security Group for RDS in US-EAST-1
resource "aws_security_group" "rds_sg_us_east" {
  provider    = aws.us-east-1
  name        = "rds-sg-us-east"
  description = "Security group for RDS in us-east-1"

  ingress {
