  name       = "rds-subnet-group-eu-west"
  subnet_ids = data.aws_subnets.default_eu_west.ids
}

# RDS Database in EU-WEST-1
resource "aws_db_instance" "main_db_eu_west" {
  provider               = aws.eu-west-1
  identifier             = "main-db-eu-west"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "main_db_eu_west"
  username               = "admin"
  password               = "changeme123456"
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group_eu_west.name
  vpc_security_group_ids = [aws_security_group.rds_sg_eu_west.id]
  skip_final_snapshot    = true
  publicly_accessible    = false
}

# Elastic Beanstalk Application in EU-WEST-1
resource "aws_elastic_beanstalk_application" "myapp_eu_west" {
  provider    = aws.eu-west-1
  name        = "myapp_eu_west"
  description = "Application in eu-west-1"
}

# Elastic Beanstalk Environment in EU-WEST-1
resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider            = aws.eu-west-1
  name                = "myenv-eu-west"
  application         = aws_elastic_beanstalk_application.myapp_eu_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PORT"
    value     = "3306"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.main_db_eu_west.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.main_db_eu_west.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_eu_west.password
  }
}

# ROUTE 53 HOSTED ZONE AND RECORDS

resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Route53 Health Check for US-EAST-1
resource "aws_route53_health_check" "us_east_health" {
  provider          = aws.us-east-1
  fqdn              = aws_elastic_beanstalk_environment.myenv_us_east.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "us-east-health-check"
  }
}

# Route53 Health Check for EU-WEST-1
resource "aws_route53_health_check" "eu_west_health" {
  provider          = aws.us-east-1
  fqdn              = aws_elastic_beanstalk_environment.myenv_eu_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "eu-west-health-check"
  }
}

# Route53 Record for US-EAST-1 (Latency-based routing)
resource "aws_route53_record" "us_east" {
  zone_id        = aws_route53_zone.main.zone_id
  name           = "example.com"
  type           = "CNAME"
  ttl            = 60
  records        = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  set_identifier = "us-east-1"

  latency_routing_policy {
    region = "us-east-1"
  }

  health_check_id = aws_route53_health_check.us_east_health.id
}

# Route53 Record for EU-WEST-1 (Latency-based routing)
resource "aws_route53_record" "eu_west" {
  zone_id        = aws_route53_zone.main.zone_id
  name           = "example.com"
  type           = "CNAME"
  ttl            = 60
  records        = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  set_identifier = "eu-west-1"

  latency_routing_policy {
    region = "eu-west-1"
  }

  health_check_id = aws_route53_health_check.eu_west_health.id
}

# OUTPUTS

output "route53_zone_id" {
  value       = aws_route53_zone.main.zone_id
  description = "Route53 hosted zone ID"
}

output "route53_nameservers" {
  value       = aws_route53_zone.main.name_servers
  description = "Route53 nameservers"
}

output "us_east_eb_environment_url" {
  value       = aws_elastic_beanstalk_environment.myenv_us_east.cname
  description = "Elastic Beanstalk environment URL for US-EAST-1"
}

output "eu_west_eb_environment_url" {
  value       = aws_elastic_beanstalk_environment.myenv_eu_west.cname
  description = "Elastic Beanstalk environment URL for EU-WEST-1"
}

output "us_east_rds_endpoint" {
  value       = aws_db_instance.main_db_us_east.endpoint
  description = "RDS endpoint for US-EAST-1"
}

output "eu_west_rds_endpoint" {
  value       = aws_db_instance.main_db_eu_west.endpoint
  description = "RDS endpoint for EU-WEST-1"
}
