        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for CodeBuild Cache
resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "codebuild-sample-cache-bucket"
}

# CodeBuild Project
resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with GitHub source"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode            = false

    environment_variable {
      name  = "ENV"
      value = "production"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "AWS_REGION"
      value = "us-east-1"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "API_KEY"
      value = "sample-parameter-name"
      type  = "PARAMETER_STORE"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/sample-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }

    buildspec = "buildspec.yml"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/sample-project"
      stream_name = "build-log"
      status      = "ENABLED"
    }

    s3_logs {
      status = "DISABLED"
    }
  }

  tags = {
    Environment = "Development"
    Project     = "Sample"
  }
}

