# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-project-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-project-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codecommit:GitPull"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for CodeBuild Artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "codebuild-project-artifacts-bucket"
}

# CodeBuild Project with Secondary Sources
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with secondary sources"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    path     = "build-output"
    packaging = "ZIP"
  }

  cache {
    type     = "S3"
    location = "${aws_s3_bucket.codebuild_artifacts.bucket}/cache"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode            = false

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "BUILD_NUMBER"
      value = "1.0.0"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "SECRET_KEY"
      value = "arn:aws:secretsmanager:us-east-1:123456789012:secret:example-secret"
      type  = "SECRETS_MANAGER"
    }
  }

  # Primary Source
  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    git_submodules_config {
      fetch_submodules = true
    }
  }

  # Secondary Source 1 - Additional library code
  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/library-repo.git"
    source_identifier = "LibrarySource"
    git_clone_depth   = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Secondary Source 2 - Configuration files
  secondary_sources {
    type              = "CODECOMMIT"
    location          = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/config-repo"
    source_identifier = "ConfigSource"
    git_clone_depth   = 1
  }

  # Secondary Source 3 - S3 source
  secondary_sources {
    type              = "S3"
    location          = "${aws_s3_bucket.codebuild_artifacts.bucket}/dependencies/dependencies.zip"
    source_identifier = "DependenciesSource"
  }

  # Secondary Source Versions (optional, for specifying specific versions)
  secondary_source_version {
    source_identifier = "LibrarySource"
    source_version    = "main"
  }

  secondary_source_version {
    source_identifier = "ConfigSource"
    source_version    = "refs/heads/production"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.bucket}/build-logs"
    }
  }

  vpc_config {
    vpc_id = "vpc-12345678"
    subnets = [
      "subnet-12345678",
      "subnet-87654321"
    ]
    security_group_ids = [
      "sg-12345678"
    ]
  }

  tags = {
    Environment = "Production"
    Project     = "Example"
    ManagedBy   = "Terraform"
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/example-project"
  retention_in_days = 7
}
