    artifact_identifier = "secondary-artifact-1"
    type               = "S3"
    location           = aws_s3_bucket.codebuild_artifacts.bucket
    path              = "secondary1/"
    name              = "secondary-artifact-1"
    packaging         = "ZIP"
  }

