resource "aws_lexv2models_bot" "chatbot" {
  name     = "my-chatbot"
  role_arn = aws_iam_role.lex_bot_role.arn

  idle_session_ttl_in_seconds = 300

  data_privacy {
    child_directed = false
  }
}

# Bot Locale
resource "aws_lexv2models_bot_locale" "chatbot_locale" {
  bot_id      = aws_lexv2models_bot.chatbot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"

  n_lu_intent_confidence_threshold = 0.40
}

# Intent
resource "aws_lexv2models_intent" "greeting_intent" {
  bot_id      = aws_lexv2models_bot.chatbot.id
  bot_version = aws_lexv2models_bot_locale.chatbot_locale.bot_version
  locale_id   = aws_lexv2models_bot_locale.chatbot_locale.locale_id
  name        = "GreetingIntent"

  sample_utterance {
    utterance = "Hello"
  }

  sample_utterance {
    utterance = "Hi"
  }

  sample_utterance {
    utterance = "Hey"
  }

  fulfillment_code_hook {
    enabled = false
  }

  confirmation_setting {
    active = false
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! How can I help you today?"
          }
        }
      }
    }
  }
}

# Bot Version
resource "aws_lexv2models_bot_version" "chatbot_version" {
  bot_id = aws_lexv2models_bot.chatbot.id

  locale_specification = {
    (aws_lexv2models_bot_locale.chatbot_locale.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.greeting_intent
  ]
}

