terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_ordering_lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Order pizza",
    "I'd like to order a {Size} {PizzaType} pizza",
    "Can I get a pizza",
    "Order a {PizzaType} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "Type of pizza to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? We have Margherita, Pepperoni, Vegetarian, and Hawaiian."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Size"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Quantity"
    description = "Number of pizzas"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many pizzas would you like?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have {Quantity} {Size} {PizzaType} pizza(s). Should I place your order?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "pizza_ordering_bot" {
  name                        = "PizzaOrderingBot"
  description                 = "Bot to handle pizza ordering"
  idle_session_ttl_in_seconds = 300
  process_behavior            = "BUILD"
  locale                      = "en-US"
  voice_id                    = "Joanna"
  child_directed              = false

  abort_statement {
    message {
      content      = "Sorry, I am unable to assist you at this time. Please try again later."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand you. Would you like to order a pizza?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  create_version = false

  depends_on = [
    aws_iam_role_policy_attachment.lex_bot_policy
  ]
}

resource "aws_lex_bot_alias" "pizza_bot_alias" {
  bot_name    = aws_lex_bot.pizza_ordering_bot.name
  bot_version = "$LATEST"
  name        = "PizzaBotProd"
  description = "Production alias for Pizza Ordering Bot"

  conversation_logs {
    iam_role_arn = aws_iam_role.lex_bot_role.arn

    log_settings {
      destination  = "CLOUDWATCH_LOGS"
      log_type     = "TEXT"
      resource_arn = aws_cloudwatch_log_group.lex_bot_logs.arn
    }
  }
}

resource "aws_cloudwatch_log_group" "lex_bot_logs" {
  name              = "/aws/lex/PizzaOrderingBot"
  retention_in_days = 7
}

output "bot_name" {
  value       = aws_lex_bot.pizza_ordering_bot.name
  description = "Name of the Lex bot"
}

output "bot_alias" {
  value       = aws_lex_bot_alias.pizza_bot_alias.name
  description = "Alias of the Lex bot"
}

output "bot_checksum" {
  value       = aws_lex_bot.pizza_ordering_bot.checksum
  description = "Checksum of the Lex bot"
}

