terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

resource "aws_lex_intent" "book_trip" {
  name        = "BookTrip"
  description = "Intent to book a trip reservation"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to book a trip",
    "Book a trip to {Destination}",
    "I need to reserve a trip",
    "Make a reservation for {TripType}",
    "Book a {TripType} trip to {Destination}"
  ]

  slot {
    name        = "Destination"
    description = "Destination city for the trip"
    slot_constraint = "Required"
    slot_type   = "AMAZON.US_CITY"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content      = "What city would you like to visit?"
        content_type = "PlainText"
      }

      message {
        content      = "Where do you want to go?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name              = "TripType"
    description       = "Type of trip"
    slot_constraint   = "Required"
    slot_type         = "TripTypeSlot"
    slot_type_version = "$LATEST"
    priority          = 2

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content      = "What type of trip are you planning? (Business or Vacation)"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name            = "CheckInDate"
    description     = "Check-in date for the trip"
    slot_constraint = "Required"
    slot_type       = "AMAZON.DATE"
    priority        = 3

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content      = "When would you like to check in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name            = "Nights"
    description     = "Number of nights for the stay"
    slot_constraint = "Required"
    slot_type       = "AMAZON.NUMBER"
    priority        = 4

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content      = "How many nights will you be staying?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, I have you down for a {Nights} night {TripType} trip to {Destination} starting on {CheckInDate}. Should I book the reservation?"
      content_type = "PlainText"
    }

    message {
      content      = "Can you confirm your {TripType} trip to {Destination} for {Nights} nights starting {CheckInDate}?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation in progress."
      content_type = "PlainText"
    }

    message {
      content      = "Your reservation has been cancelled."
      content_type = "PlainText"
    }
  }

  conclusion_statement {
    message {
      content      = "Great! Your trip reservation has been successfully booked."
      content_type = "PlainText"
    }
  }

  dialog_code_hook {
    message_version = "1.0"
    uri             = aws_lambda_function.lex_fulfillment.arn
  }

  follow_up_prompt {
    prompt {
      max_attempts = 3

      message {
        content      = "Would you like to make another reservation?"
        content_type = "PlainText"
      }
    }

    rejection_statement {
      message {
        content      = "Thank you for using our trip booking service!"
        content_type = "PlainText"
      }
    }
  }

  create_version                = true
  parent_intent_signature       = null
}

resource "aws_lex_slot_type" "trip_type" {
  name        = "TripTypeSlot"
  description = "Types of trips available for booking"

  enumeration_value {
    value = "Business"
    synonyms = [
      "Work",
      "Corporate",
      "Professional"
    ]
  }

  enumeration_value {
    value = "Vacation"
    synonyms = [
      "Holiday",
      "Leisure",
      "Personal"
    ]
  }

  create_version          = true
  value_selection_strategy = "TOP_RESOLUTION"
}

resource "aws_lambda_function" "lex_fulfillment" {
  filename      = "lambda_function.zip"
  function_name = "lex_trip_fulfillment"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"
  timeout       = 30

  source_code_hash = filebase64sha256("lambda_function.zip")
}

resource "aws_iam_role" "lambda_role" {
  name = "lex_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_lambda_permission" "lex_lambda_permission" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.lex_fulfillment.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = "${aws_lex_bot.trip_reservation.arn}/*"
}

resource "aws_lex_bot" "trip_reservation" {
  name                          = "TripReservationBot"
  description                   = "Bot to handle trip reservations with comprehensive parameters"
  locale                        = "en-US"
  child_directed                = false
  detect_sentiment              = true
  enable_model_improvements     = true
  idle_session_ttl_in_seconds   = 600
  process_behavior              = "BUILD"
  voice_id                      = "Joanna"
  create_version                = true
  nlu_intent_confidence_threshold = 0.5

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time. Please try again later."
      content_type = "PlainText"
      group_number = 1
    }

