      content      = "I apologize, but I cannot complete your request right now."
      content_type = "PlainText"
      group_number = 1
    }
  }

  clarification_prompt {
    max_attempts = 3

    message {
      content      = "I didn't understand you. What would you like to do?"
      content_type = "PlainText"
      group_number = 1
    }

    message {
      content      = "Sorry, can you please repeat that?"
      content_type = "PlainText"
      group_number = 1
    }

    response_card = jsonencode({
      version = 1
      contentType = "application/vnd.amazonaws.card.generic"
      genericAttachments = [
        {
          title = "What can I help you with?"
          buttons = [
            {
              text  = "Book a Trip"
              value = "Book a trip"
            },
            {
              text  = "Cancel"
              value = "Cancel"
            }
          ]
        }
      ]
    })
  }

  intent {
    intent_name    = aws_lex_intent.book_trip.name
    intent_version = aws_lex_intent.book_trip.version
  }

  depends_on = [
    aws_iam_role_policy_attachment.lex_bot_policy,
    aws_lex_intent.book_trip,
    aws_lex_slot_type.trip_type
  ]
}

resource "aws_lex_bot_alias" "trip_bot_prod" {
  bot_name    = aws_lex_bot.trip_reservation.name
