      resource_arn = aws_s3_bucket.lex_audio_logs.arn
      kms_key_arn  = aws_kms_key.lex_logs_key.arn
    }
  }
}

resource "aws_cloudwatch_log_group" "lex_bot_logs" {
  name              = "/aws/lex/TripReservationBot"
  retention_in_days = 7
}

resource "aws_s3_bucket" "lex_audio_logs" {
  bucket = "lex-trip-bot-audio-logs-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_public_access_block" "lex_audio_logs" {
  bucket = aws_s3_bucket.lex_audio_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_kms_key" "lex_logs_key" {
