terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_ordering_lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

# Pizza Ordering Lex Bot
resource "aws_lex_bot" "pizza_ordering_bot" {
  name           = "PizzaOrderingBot"
  description    = "Bot for ordering pizzas with multiple ordering options"
  idle_session_ttl_in_seconds = 300
  voice_id       = "Joanna"
  process_behavior = "BUILD"
  locale         = "en-US"
  child_directed = false

  abort_statement {
    message {
      content      = "Sorry, I am unable to process your order at this time. Please try again later."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I'm sorry, I didn't understand that. Can you please rephrase?"
      content_type = "PlainText"
    }
  }

  # Intent 1: Order Pizza
  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  # Intent 2: Modify Order
  intent {
    intent_name    = aws_lex_intent.modify_order.name
    intent_version = aws_lex_intent.modify_order.version
  }

  # Intent 3: Cancel Order
  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = aws_lex_intent.cancel_order.version
  }

  # Intent 4: Track Order
  intent {
    intent_name    = aws_lex_intent.track_order.name
    intent_version = aws_lex_intent.track_order.version
  }

  # Intent 5: View Menu
  intent {
    intent_name    = aws_lex_intent.view_menu.name
    intent_version = aws_lex_intent.view_menu.version
  }
}

# Intent 1: Order Pizza
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "Can I get a pizza",
    "I'd like to order a {Size} {PizzaType} pizza",
    "Get me a {Size} pizza with {Toppings}"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name        = "PizzaType"
    description = "Type of pizza to order"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_type.name
    slot_type_version = aws_lex_slot_type.pizza_type.version
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? We have Margherita, Pepperoni, Vegetarian, Hawaiian, and Meat Lovers."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Size"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_size.name
    slot_type_version = aws_lex_slot_type.pizza_size.version
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Toppings"
    description = "Additional toppings"
    slot_constraint = "Optional"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Would you like any additional toppings?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Would you like to order a {Size} {PizzaType} pizza?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I've cancelled your pizza order."
      content_type = "PlainText"
    }
  }
}

# Intent 2: Modify Order
resource "aws_lex_intent" "modify_order" {
  name        = "ModifyOrder"
  description = "Intent to modify an existing order"

  sample_utterances = [
    "I want to change my order",
    "Modify my order",
    "Can I update my order",
    "Change order number {OrderNumber}",
    "Update my pizza order"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name        = "OrderNumber"
    description = "Order number to modify"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Number"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Modification"
    description = "What to modify"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What would you like to change in your order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "I will modify order {OrderNumber} with {Modification}. Is this correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I won't modify your order."
      content_type = "PlainText"
    }
  }
}

# Intent 3: Cancel Order
resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel an order"

  sample_utterances = [
    "Cancel my order",
    "I want to cancel order {OrderNumber}",
    "Cancel order",
    "Stop my order",
    "I don't want my pizza anymore"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name        = "OrderNumber"
    description = "Order number to cancel"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Number"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number that you'd like to cancel?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Are you sure you want to cancel order {OrderNumber}?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I won't cancel your order."
      content_type = "PlainText"
    }
  }
}

# Intent 4: Track Order
resource "aws_lex_intent" "track_order" {
  name        = "TrackOrder"
  description = "Intent to track order status"

  sample_utterances = [
    "Track my order",
    "Where is my pizza",
    "Order status",
    "Track order {OrderNumber}",
    "What's the status of my order"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name        = "OrderNumber"
    description = "Order number to track"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Number"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  conclusion_statement {
    message {
      content      = "Let me check the status of order {OrderNumber} for you."
      content_type = "PlainText"
    }
  }
}

# Intent 5: View Menu
resource "aws_lex_intent" "view_menu" {
  name        = "ViewMenu"
  description = "Intent to view pizza menu"

  sample_utterances = [
    "Show me the menu",
    "What pizzas do you have",
    "What's on the menu",
    "Menu options",
    "What can I order"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
