    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

# Lex Bot
resource "aws_lex_bot" "pizza_order_bot" {
  name           = "KidsPizzaOrderBot"
  description    = "A friendly bot for children to order pizza"
  idle_session_ttl_in_seconds = 600
  child_directed = true
  locale         = "en-US"
  voice_id       = "Joanna"
  process_behavior = "BUILD"

  abort_statement {
    message {
      content      = "Sorry, I'm not able to help with that right now. Please try again later!"
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand that. Can you tell me what kind of pizza you'd like?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = aws_lex_intent.cancel_order.version
  }

  depends_on = [aws_iam_role_policy_attachment.lex_bot_policy]
}

# Order Pizza Intent
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Great! So you want a {Size} {PizzaType} pizza with {Crust} crust. Should I place the order?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I won't place the order. You can start over anytime!"
      content_type = "PlainText"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "Can I get a pizza",
    "I'd like a pizza please",
    "Order pizza",
    "Pizza time",
    "I want pizza",
    "Can I have a {PizzaType} pizza",
    "I want a {Size} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "Type of pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_type.name
    slot_type_version = aws_lex_slot_type.pizza_type.version
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What kind of pizza would you like? We have cheese, pepperoni, veggie, or supreme!"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Size"
    description = "Size of pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_size.name
    slot_type_version = aws_lex_slot_type.pizza_size.version
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza do you want? Small, medium, or large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Crust"
    description = "Type of crust"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_crust.name
    slot_type_version = aws_lex_slot_type.pizza_crust.version
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What kind of crust would you like? Thin, thick, or regular?"
        content_type = "PlainText"
      }
    }
  }
}

# Cancel Order Intent
resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel the order"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content      = "Okay, I've cancelled your order. Come back anytime you want pizza!"
      content_type = "PlainText"
    }
  }

  sample_utterances = [
    "Cancel",
    "Cancel my order",
    "I don't want it anymore",
    "Stop",
    "Never mind",
    "I changed my mind"
  ]
}

# Slot Type for Pizza Type
resource "aws_lex_slot_type" "pizza_type" {
  name        = "PizzaType"
  description = "Types of pizza available"

  enumeration_value {
    value = "cheese"
    synonyms = ["cheese pizza", "plain"]
  }

  enumeration_value {
    value = "pepperoni"
    synonyms = ["pepperoni pizza"]
  }

  enumeration_value {
    value = "veggie"
    synonyms = ["vegetable", "vegetarian", "veggie pizza"]
  }

  enumeration_value {
    value = "supreme"
    synonyms = ["everything", "supreme pizza"]
  }

  value_selection_strategy = "TOP_RESOLUTION"
}

# Slot Type for Pizza Size
resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  description = "Size of pizza"

  enumeration_value {
    value = "small"
    synonyms = ["little", "tiny"]
  }

  enumeration_value {
    value = "medium"
    synonyms = ["regular", "normal"]
  }

  enumeration_value {
    value = "large"
    synonyms = ["big", "extra large", "xl"]
  }

  value_selection_strategy = "TOP_RESOLUTION"
}

# Slot Type for Pizza Crust
resource "aws_lex_slot_type" "pizza_crust" {
  name        = "PizzaCrust"
  description = "Type of pizza crust"

  enumeration_value {
    value = "thin"
    synonyms = ["thin crust", "crispy"]
  }

  enumeration_value {
    value = "thick"
    synonyms = ["thick crust", "deep dish"]
  }

  enumeration_value {
    value = "regular"
    synonyms = ["normal", "standard", "regular crust"]
  }

  value_selection_strategy = "TOP_RESOLUTION"
}

# Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  bot_name    = aws_lex_bot.pizza_order_bot.name
  bot_version = aws_lex_bot.pizza_order_bot.version
  name        = "Production"
  description = "Production alias for Kids Pizza Order Bot"
}

output "bot_name" {
  value       = aws_lex_bot.pizza_order_bot.name
  description = "Name of the Lex bot"
}

output "bot_alias" {
  value       = aws_lex_bot_alias.pizza_bot_alias.name
  description = "Bot alias name"
}

