provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "pizza-ordering-lex-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
  role       = aws_iam_role.lex_bot_role.name
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "I'd like to order a {Size} {Type} pizza",
    "Can I get a pizza",
    "I want a {Type} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "Type of pizza to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaSize"
    description = "Size of pizza to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Quantity"
    description = "Number of pizzas to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "How many pizzas would you like?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "You want to order {Quantity} {PizzaSize} {PizzaType} pizza(s). Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I've cancelled your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "pizza_ordering_bot" {
  name                         = "PizzaOrderingBot"
  description                  = "Bot for ordering pizzas"
  idle_session_ttl_in_seconds  = 600
  process_behavior             = "BUILD"
  locale                       = "en-US"
  child_directed               = false
  voice_id                     = "Joanna"
  nlu_intent_confidence_threshold = 0.5

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  depends_on = [aws_iam_role_policy_attachment.lex_bot_policy]
}

resource "aws_lex_bot_alias" "pizza_bot_alias" {
  bot_name    = aws_lex_bot.pizza_ordering_bot.name
  bot_version = "$LATEST"
  name        = "PizzaBotProduction"
  description = "Production alias for pizza ordering bot"
}

