data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
import json

def lambda_handler(event, context):
    intent_name = event['sessionState']['intent']['name']
    slots = event['sessionState']['intent']['slots']

    if intent_name == 'OrderPizza':
        pizza_type = slots.get('PizzaType', {}).get('value', {}).get('interpretedValue', 'Unknown')
        pizza_size = slots.get('PizzaSize', {}).get('value', {}).get('interpretedValue', 'Unknown')
        pizza_crust = slots.get('PizzaCrust', {}).get('value', {}).get('interpretedValue', 'Unknown')

        message = f"Great! I've placed your order for a {pizza_size} {pizza_type} pizza with {pizza_crust} crust. Your order will be ready in 30 minutes."

        return {
            'sessionState': {
                'dialogAction': {
                    'type': 'Close'
                },
                'intent': {
                    'name': intent_name,
                    'state': 'Fulfilled'
                }
            },
            'messages': [
                {
                    'contentType': 'PlainText',
                    'content': message
                }
            ]
        }

    return {
        'sessionState': {
            'dialogAction': {
                'type': 'Close'
            },
            'intent': {
                'name': intent_name,
                'state': 'Failed'
            }
        }
    }
EOF
    filename = "lambda_function.py"
  }
}

