  locale_id   = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }

  sample_utterance {
    utterance = "Can I get a pizza"
  }

  sample_utterance {
    utterance = "I'd like to order a {PizzaSize} {PizzaType} pizza"
  }

  sample_utterance {
    utterance = "Order a pizza"
  }

  fulfillment_code_hook {
    enabled = true
  }

  confirmation_setting {
    active = true

    prompt_specification {
      max_retries                 = 3
      message_selection_strategy  = "Random"

      message_group {
        message {
          plain_text_message {
            value = "Would you like to confirm your order for a {PizzaSize} {PizzaType} pizza with {PizzaCrust} crust?"
          }
        }
      }
    }

    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "Okay, I've cancelled your pizza order."
          }
        }
      }
    }
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Thank you for your order!"
          }
        }
      }
    }
  }
}

# Slots for the Intent
resource "aws_lexv2models_slot" "pizza_type_slot" {
  bot_id      = aws_lexv2models_bot.pizza_order_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  name        = "PizzaType"
  slot_type_id = aws_lexv2models_slot_type.pizza_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"

    prompt_specification {
      max_retries                = 3
      message_selection_strategy = "Random"

      message_group {
        message {
          plain_text_message {
            value = "What type of pizza would you like? We have Margherita, Pepperoni, Hawaiian, Vegetarian, and Meat Lovers."
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_slot" "pizza_size_slot" {
  bot_id      = aws_lexv2models_bot.pizza_order_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  name        = "PizzaSize"
  slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"

    prompt_specification {
      max_retries                = 3
      message_selection_strategy = "Random"

      message_group {
        message {
          plain_text_message {
            value = "What size would you like? Small, Medium, Large, or Extra Large?"
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_slot" "pizza_crust_slot" {
  bot_id      = aws_lexv2models_bot.pizza_order_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  name        = "PizzaCrust"
  slot_type_id = aws_lexv2models_slot_type.pizza_crust.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"

    prompt_specification {
      max_retries                = 3
      message_selection_strategy = "Random"

      message_group {
        message {
          plain_text_message {
            value = "What type of crust would you prefer? Thin, Thick, or Stuffed?"
          }
        }
      }
    }
  }
}

# Bot Version
resource "aws_lexv2models_bot_version" "pizza_bot_version" {
  bot_id = aws_lexv2models_bot.pizza_order_bot.id

  locale_specification = {
    (aws_lexv2models_bot_locale.pizza_bot_locale.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.order_pizza,
    aws_lexv2models_slot.pizza_type_slot,
    aws_lexv2models_slot.pizza_size_slot,
    aws_lexv2models_slot.pizza_crust_slot
  ]
}

# Bot Alias with Lambda integration
resource "aws_lexv2models_bot_alias" "pizza_bot_alias" {
  bot_id          = aws_lexv2models_bot.pizza_order_bot.id
  bot_alias_name  = "ProductionAlias"
  bot_version     = aws_lexv2models_bot_version.pizza_bot_version.bot_version

  bot_alias_locale_settings {
    bot_alias_locale_setting {
      locale_id = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
      enabled   = true

      code_hook_specification {
        lambda_code_hook {
          lambda_arn           = aws_lambda_function.pizza_order_fulfillment.arn
          code_hook_interface_version = "1.0"
        }
      }
    }
  }

  depends_on = [aws_lambda_permission.allow_lex]
}

