}

# Lex V2 Bot for Kids
resource "aws_lexv2models_bot" "kids_bot" {
  name     = "KidsFriendlyBot"
  role_arn = aws_iam_role.lex_bot_role.arn

  idle_session_ttl_in_seconds = 300

  data_privacy {
    child_directed = true
  }

  description = "A friendly bot designed for children with COPPA compliance"

  tags = {
    Environment = "production"
    Audience    = "kids"
    Compliance  = "COPPA"
  }
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id      = aws_lexv2models_bot.kids_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"

  n_lu_intent_confidence_threshold = 0.40

  voice_settings {
    voice_id = "Joanna"
  }

  description = "English locale for kids bot"
}

# Intent: Greeting
resource "aws_lexv2models_intent" "greeting" {
  bot_id      = aws_lexv2models_bot.kids_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "GreetingIntent"

  description = "Intent for greeting children"

  sample_utterance {
    utterance = "Hi"
  }

  sample_utterance {
    utterance = "Hello"
  }

  sample_utterance {
    utterance = "Hey there"
  }

  fulfillment_code_hook {
    enabled = false
  }

  confirmation_setting {
    prompt_specification {
      message_group {
        message {
          plain_text_message {
            value = "Hello! How can I help you today?"
          }
        }
      }
      max_retries = 2
    }

    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "Okay, let me know if you need anything!"
          }
        }
      }
    }
  }
}

# Bot Version
resource "aws_lexv2models_bot_version" "kids_bot_version" {
  bot_id = aws_lexv2models_bot.kids_bot.id

  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lexv2models_intent.greeting
  ]
}

output "bot_id" {
