provider "aws" {
  region = "us-east-1"
}

# Amazon Connect Instance
resource "aws_connect_instance" "example" {
  identity_management_type = "CONNECT_MANAGED"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "example-connect-instance"
}

# Amazon Lex Bot
resource "aws_lex_bot" "example" {
  name           = "example_bot"
  description    = "Example bot for Connect integration"
  process_behavior = "BUILD"
  locale         = "en-US"
  child_directed = false

  abort_statement {
    message {
      content      = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.example.name
    intent_version = aws_lex_intent.example.version
  }

  voice_id           = "Joanna"
  idle_session_ttl_in_seconds = 300
}

resource "aws_lex_intent" "example" {
  name           = "example_intent"
  description    = "Example intent"
  create_version = true

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to talk to someone",
    "I need help"
  ]
}

resource "aws_lex_bot_alias" "example" {
  bot_name    = aws_lex_bot.example.name
  bot_version = aws_lex_bot.example.version
  name        = "example_alias"
  description = "Example bot alias"
}

# Amazon Connect Bot Association
resource "aws_connect_bot_association" "example" {
  instance_id = aws_connect_instance.example.id

  lex_bot {
    lex_region = "us-east-1"
    name       = aws_lex_bot.example.name
  }
}

