  }
}

provider "aws" {
  region = "us-east-1"
}

# SAML Identity Provider
resource "aws_iam_saml_provider" "connect_saml" {
  name                   = "connect-saml-provider"
  saml_metadata_document = file("saml-metadata.xml")
}

# IAM Role for SAML authentication
resource "aws_iam_role" "connect_saml_role" {
  name = "ConnectSAMLRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Federated = aws_iam_saml_provider.connect_saml.arn
        }
        Action = "sts:AssumeRoleWithSAML"
        Condition = {
          StringEquals = {
            "SAML:aud" = "https://signin.aws.amazon.com/saml"
          }
        }
      }
    ]
  })
}

# Attach necessary policies to the SAML role
resource "aws_iam_role_policy_attachment" "connect_saml_policy" {
  role       = aws_iam_role.connect_saml_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonConnect_FullAccess"
}

# Amazon Connect Instance with SAML authentication
resource "aws_connect_instance" "main" {
  identity_management_type = "SAML"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "my-connect-instance"
}

# Lex Bot
resource "aws_lex_bot" "connect_bot" {
  name           = "ConnectChatBot"
  description    = "Bot for Amazon Connect integration"
  process_behavior = "BUILD"
  idle_session_ttl_in_seconds = 300
  child_directed = false
  locale         = "en-US"
  voice_id       = "Joanna"

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = "HelpIntent"
    intent_version = "1"
  }
}

# Connect Bot Association
resource "aws_connect_bot_association" "main" {
  instance_id = aws_connect_instance.main.id

  lex_bot {
    lex_region = "us-east-1"
    name       = aws_lex_bot.connect_bot.name
  }
}

