extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Kinesis Data Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-application-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Kinesis Data Analytics
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-application-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      }
    ]
  })
}

# Kinesis Data Stream (input)
resource "aws_kinesis_stream" "input_stream" {
  name             = "analytics-input-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }

  tags = {
    Name        = "analytics-input-stream"
    Environment = "dev"
  }
}

# CloudWatch Log Group for Kinesis Analytics
resource "aws_cloudwatch_log_group" "kinesis_analytics_log_group" {
  name              = "/aws/kinesis-analytics/simple-application"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "kinesis_analytics_log_stream" {
  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.kinesis_analytics_log_group.name
}

# Kinesis Data Analytics Application
resource "aws_kinesis_analytics_application" "analytics_app" {
  name = "simple-kinesis-analytics-app"

  code = <<CODE
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
  record_data VARCHAR(512)
);

CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM record_data
FROM "SOURCE_SQL_STREAM_001";
CODE

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.data"
        name     = "record_data"
        sql_type = "VARCHAR(512)"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.kinesis_analytics_log_stream.arn
    role_arn       = aws_iam_role.kinesis_analytics_cloudwatch_role.arn
  }

  tags = {
    Name        = "simple-kinesis-analytics-app"
    Environment = "dev"
  }
}

# IAM role for CloudWatch logging
resource "aws_iam_role" "kinesis_analytics_cloudwatch_role" {
  name = "kinesis-analytics-cloudwatch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kinesis_analytics_cloudwatch_policy" {
  name = "kinesis-analytics-cloudwatch-policy"
  role = aws_iam_role.kinesis_analytics_cloudwatch_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.kinesis_analytics_log_group.arn}:log-stream:${aws_cloudwatch_log_stream.kinesis_analytics_log_stream.name}"
      }
    ]
  })
}

output "kinesis_stream_name" {
  description = "Name of the Kinesis input stream"
  value       = aws_kinesis_stream.input_stream.name
}

output "analytics_application_name" {
  description = "Name of the Kinesis Analytics application"
  value       = aws_kinesis_analytics_application.analytics_app.name
}

output "analytics_application_status" {
  description = "Status of the Kinesis Analytics application"
  value       = aws_kinesis_analytics_application.analytics_app.status
}

