terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-serverless-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose to access OpenSearch Serverless
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-serverless-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = aws_opensearchserverless_collection.collection.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

# S3 bucket for backup/failed records
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "firehose-opensearch-backup-bucket-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_ownership_controls" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "backup_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.backup_bucket]
  bucket     = aws_s3_bucket.backup_bucket.id
  acl        = "private"
}

# OpenSearch Serverless encryption policy
resource "aws_opensearchserverless_security_policy" "encryption_policy" {
  name = "firehose-collection-encryption"
  type = "encryption"
  policy = jsonencode({
    Rules = [
      {
        Resource = [
          "collection/firehose-collection"
        ]
        ResourceType = "collection"
      }
    ]
    AWSOwnedKey = true
  })
}

# OpenSearch Serverless network policy
resource "aws_opensearchserverless_security_policy" "network_policy" {
  name = "firehose-collection-network"
  type = "network"
  policy = jsonencode([
    {
      Rules = [
        {
          Resource = [
            "collection/firehose-collection"
          ]
          ResourceType = "collection"
        }
      ]
      AllowFromPublic = true
    }
  ])
}

# OpenSearch Serverless data access policy
resource "aws_opensearchserverless_access_policy" "data_policy" {
  name = "firehose-collection-access"
  type = "data"
  policy = jsonencode([
    {
      Rules = [
        {
          Resource = [
            "collection/firehose-collection"
          ]
          Permission = [
            "aoss:CreateCollectionItems",
            "aoss:UpdateCollectionItems",
            "aoss:DescribeCollectionItems"
          ]
          ResourceType = "collection"
        },
        {
          Resource = [
            "index/firehose-collection/*"
          ]
          Permission = [
            "aoss:CreateIndex",
            "aoss:UpdateIndex",
            "aoss:DescribeIndex",
            "aoss:ReadDocument",
            "aoss:WriteDocument"
          ]
          ResourceType = "index"
        }
      ]
      Principal = [
        aws_iam_role.firehose_role.arn,
        data.aws_caller_identity.current.arn
      ]
    }
  ])
}

# OpenSearch Serverless collection
resource "aws_opensearchserverless_collection" "collection" {
  name = "firehose-collection"
  type = "TIMESERIES"

  depends_on = [
    aws_opensearchserverless_security_policy.encryption_policy,
    aws_opensearchserverless_security_policy.network_policy
  ]
}

# Kinesis Firehose delivery stream
resource "aws_kinesis_firehose_delivery_stream" "firehose_to_opensearch" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.collection.collection_endpoint
    index_name          = "firehose-index"
    role_arn            = aws_iam_role.firehose_role.arn

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.backup_bucket.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "UNCOMPRESSED"
    }

    buffering_interval = 300
    buffering_size     = 5

    retry_duration = 300

    cloudwatch_logging_options {
      enabled = false
    }
  }

  depends_on = [
    aws_opensearchserverless_access_policy.data_policy
  ]
}

data "aws_caller_identity" "current" {}

output "firehose_arn" {
  value       = aws_kinesis_firehose_delivery_stream.firehose_to_opensearch.arn
  description = "ARN of the Kinesis Firehose delivery stream"
}

output "opensearch_collection_endpoint" {
  value       = aws_opensearchserverless_collection.collection.collection_endpoint
  description = "OpenSearch Serverless collection endpoint"
}

output "backup_bucket_name" {
  value       = aws_s3_bucket.backup_bucket.id
  description = "S3 bucket for failed records"
}

