terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "opensearch_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "opensearch-vpc"
  }
}

resource "aws_subnet" "opensearch_subnet" {
  count             = 2
  vpc_id            = aws_vpc.opensearch_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "opensearch-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group for OpenSearch
resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-sg"
  description = "Security group for OpenSearch"
  vpc_id      = aws_vpc.opensearch_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.opensearch_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-sg"
  }
}

# IAM Role for OpenSearch
resource "aws_iam_role" "opensearch_role" {
  name = "opensearch-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "es.amazonaws.com"
        }
      }
    ]
  })
}

# OpenSearch Domain in VPC
resource "aws_opensearch_domain" "firehose_destination" {
  domain_name    = "firehose-opensearch-domain"
  engine_version = "OpenSearch_2.11"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 2
    zone_awareness_enabled = true

    zone_awareness_config {
      availability_zone_count = 2
    }
  }

  vpc_options {
    subnet_ids         = aws_subnet.opensearch_subnet[*].id
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp3"
  }

  advanced_security_options {
    enabled                        = true
    internal_user_database_enabled = true
    master_user_options {
      master_user_name     = "admin"
      master_user_password = "Admin123!@#"
    }
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "es:*"
        Resource = "arn:aws:es:us-east-1:*:domain/firehose-opensearch-domain/*"
      }
    ]
  })

  tags = {
    Name = "firehose-opensearch-domain"
  }
}

# S3 Bucket for Firehose Backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-backup-bucket-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "firehose-backup-bucket"
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

data "aws_caller_identity" "current" {}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-delivery-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_opensearch_domain.firehose_destination.arn,
          "${aws_opensearch_domain.firehose_destination.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpGet"
        ]
        Resource = [
          "${aws_opensearch_domain.firehose_destination.arn}/_all/_settings",
          "${aws_opensearch_domain.firehose_destination.arn}/_cluster/stats",
          "${aws_opensearch_domain.firehose_destination.arn}/index-name*/_mapping/type-name",
          "${aws_opensearch_domain.firehose_destination.arn}/_nodes",
          "${aws_opensearch_domain.firehose_destination.arn}/_nodes/stats",
          "${aws_opensearch_domain.firehose_destination.arn}/_nodes/*/stats",
          "${aws_opensearch_domain.firehose_destination.arn}/_stats",
          "${aws_opensearch_domain.firehose_destination.arn}/index-name*/_stats"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:us-east-1:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesisfirehose/*:log-stream:*"
        ]
      }
    ]
  })
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/opensearch-delivery-stream"
  retention_in_days = 7

  tags = {
    Name = "firehose-log-group"
  }
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "opensearch-delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.firehose_destination.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"

    buffering_interval = 300
    buffering_size     = 5

    vpc_config {
      subnet_ids         = aws_subnet.opensearch_subnet[*].id
      security_group_ids = [aws_security_group.opensearch_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }

    index_rotation_period = "OneDay"
    retry_duration        = 300

    s3_backup_mode = "AllDocuments"
  }

  tags = {
    Name = "opensearch-delivery-stream"
  }

  depends_on = [
    aws_iam_role_policy.firehose_policy,
    aws_opensearch_domain.firehose_destination
  ]
}

output "firehose_stream_name" {
  value       = aws_kinesis_firehose_delivery_stream.opensearch_stream.name
  description = "Name of the Kinesis Firehose delivery stream"
}

output "firehose_stream_arn" {
  value       = aws_kinesis_firehose_delivery_stream.opensearch_stream.arn
  description = "ARN of the Kinesis Firehose delivery stream"
}

output "opensearch_endpoint" {
  value       = aws_opensearch_domain.firehose_destination.endpoint
  description = "Endpoint of the OpenSearch domain"
}

output "opensearch_dashboard_endpoint" {
  value       = aws_opensearch_domain.firehose_destination.dashboard_endpoint
  description = "Dashboard endpoint of the OpenSearch domain"
}

