provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-application-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis Analytics Application
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-application-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "kinesis_analytics_log_group" {
  name              = "/aws/kinesis-analytics/sql-application"
  retention_in_days = 7
}

# CloudWatch Log Stream
resource "aws_cloudwatch_log_stream" "kinesis_analytics_log_stream" {
  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.kinesis_analytics_log_group.name
}

# Kinesis Data Analytics Application V2 (SQL-based)
resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name                   = "sql-kinesis-analytics-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_code_configuration {
      code_content_type = "PLAINTEXT"

      code_content {
        text_content = <<-EOT
          CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
            column1 VARCHAR(16),
            column2 VARCHAR(16)
          );

          CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
          INSERT INTO "DESTINATION_SQL_STREAM"
          SELECT STREAM 'value1', 'value2'
          FROM "SOURCE_SQL_STREAM_001";
        EOT
      }
    }

    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_column {
            name     = "COL1"
            sql_type = "VARCHAR(64)"
            mapping  = "$.column1"
          }

          record_column {
            name     = "COL2"
            sql_type = "VARCHAR(64)"
            mapping  = "$.column2"
          }

          record_format {
            record_format_type = "JSON"

            mapping_parameters {
              json_mapping_parameters {
                record_row_path = "$"
              }
            }
          }
        }

        input_parallelism {
          count = 1
        }
      }

      output {
        name = "DESTINATION_SQL_STREAM"

        destination_schema {
          record_format_type = "JSON"
        }

        lambda_output {
          resource_arn = aws_lambda_function.output_lambda.arn
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.kinesis_analytics_log_stream.arn
  }
}

# Lambda Function for Output (example placeholder)
resource "aws_lambda_function" "output_lambda" {
  filename      = "lambda_function.zip"
  function_name = "kinesis-analytics-output-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  source_code_hash = filebase64sha256("lambda_function.zip")
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "kinesis-analytics-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Lambda Basic Execution Policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_role.name
}

output "application_name" {
  value = aws_kinesisanalyticsv2_application.sql_application.name
}

output "application_arn" {
  value = aws_kinesisanalyticsv2_application.sql_application.arn
}
