provider "aws" {
  region = "us-east-1"
}

# IAM role for Kendra index
resource "aws_iam_role" "kendra_index_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_index_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_index_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      }
    ]
  })
}

# IAM role for Kendra data source
resource "aws_iam_role" "kendra_data_source_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_data_source_policy" {
  name = "kendra-data-source-policy"
  role = aws_iam_role.kendra_data_source_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.kendra_bucket.arn}",
          "${aws_s3_bucket.kendra_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kendra:BatchPutDocument",
          "kendra:BatchDeleteDocument"
        ]
        Resource = aws_kendra_index.example.arn
      }
    ]
  })
}

# S3 bucket for Kendra data source
resource "aws_s3_bucket" "kendra_bucket" {
  bucket = "kendra-data-source-bucket-${data.aws_caller_identity.current.account_id}"
}

data "aws_caller_identity" "current" {}

# Kendra index
resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra_index_role.arn

  edition = "DEVELOPER_EDITION"
}

# Kendra data source with proxy settings
resource "aws_kendra_data_source" "example" {
  index_id = aws_kendra_index.example.id
  name     = "example-data-source"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_data_source_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = [
            "https://example.com",
            "https://docs.example.com"
          ]
        }
      }

      crawl_depth                = 2
      max_links_per_page         = 100
      max_urls_per_minute_crawl_rate = 300

      url_inclusion_patterns = [
        ".*https://example\.com.*",
        ".*https://docs\.example\.com.*"
      ]

      # Proxy configuration
      proxy_configuration {
        host = "proxy.example.com"
        port = 8080
        credentials = aws_secretsmanager_secret.proxy_credentials.arn
      }

      authentication_configuration {
        basic_authentication {
          host        = "example.com"
          port        = 443
          credentials = aws_secretsmanager_secret.web_credentials.arn
        }
      }
    }
  }

  schedule = "cron(0 1 * * ? *)"
}

# Secrets Manager secret for proxy credentials
resource "aws_secretsmanager_secret" "proxy_credentials" {
  name = "kendra-proxy-credentials"
}

resource "aws_secretsmanager_secret_version" "proxy_credentials" {
  secret_id = aws_secretsmanager_secret.proxy_credentials.id
  secret_string = jsonencode({
    username = "proxy_user"
    password = "proxy_password"
  })
}

# Secrets Manager secret for web authentication
resource "aws_secretsmanager_secret" "web_credentials" {
  name = "kendra-web-credentials"
}

resource "aws_secretsmanager_secret_version" "web_credentials" {
  secret_id = aws_secretsmanager_secret.web_credentials.id
  secret_string = jsonencode({
    username = "web_user"
    password = "web_password"
  })
}

# IAM policy to allow Kendra to access Secrets Manager
resource "aws_iam_role_policy" "kendra_secrets_policy" {
  name = "kendra-secrets-policy"
  role = aws_iam_role.kendra_data_source_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = [
          aws_secretsmanager_secret.proxy_credentials.arn,
          aws_secretsmanager_secret.web_credentials.arn
        ]
      }
    ]
  })
}

