  fqdn              = "us-east-1.primary"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30
  measure_latency   = true

  tags = {
    Name   = "us-east-1-health-check"
    Region = "us-east-1"
  }
}

resource "aws_route53_health_check" "eu_central_1" {
  provider          = aws.eu_central_1
  fqdn              = "eu-central-1.primary"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30
  measure_latency   = true

  tags = {
    Name   = "eu-central-1-health-check"
    Region = "eu-central-1"
  }
}

# Traffic policy with weighted routing based on load
resource "aws_route53_traffic_policy" "lowest_load" {
  name     = "lowest-load-policy"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    Endpoints = {
      us_east_1_endpoint = {
        Type  = "value"
        Value = "10.0.1.100"
      }
      eu_central_1_endpoint = {
        Type  = "value"
        Value = "10.0.2.100"
      }
    }
    Rules = {
      default = {
        RuleType = "weighted"
        Items = [
          {
            EndpointReference = "us_east_1_endpoint"
            Weight            = 50
            HealthCheck       = aws_route53_health_check.us_east_1.id
          },
          {
            EndpointReference = "eu_central_1_endpoint"
            Weight            = 50
            HealthCheck       = aws_route53_health_check.eu_central_1.id
          }
        ]
      }
    }
    StartRule = "default"
  })
}

# Traffic policy instance
resource "aws_route53_traffic_policy_instance" "primary_policy" {
  name                   = "primary.${aws_route53_zone.primary.name}"
  traffic_policy_id      = aws_route53_traffic_policy.lowest_load.id
  traffic_policy_version = aws_route53_traffic_policy.lowest_load.version
  hosted_zone_id         = aws_route53_zone.primary.zone_id
  ttl                    = 60
}

output "hosted_zone_id" {
  value       = aws_route53_zone.primary.zone_id
  description = "The hosted zone ID"
}

output "traffic_policy_id" {
  value       = aws_route53_traffic_policy.lowest_load.id
  description = "The traffic policy ID"
}

output "name_servers" {
  value       = aws_route53_zone.primary.name_servers
  description = "Name servers for the hosted zone"
}

