}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Application Load Balancer
resource "aws_lb" "primary" {
  name               = "primary-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Name        = "primary-alb"
    Environment = "production"
  }
}

resource "aws_lb" "secondary" {
  name               = "secondary-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Name        = "secondary-alb"
    Environment = "production"
  }
}

resource "aws_security_group" "alb" {
  name        = "alb-security-group"
  description = "Security group for ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"

  tags = {
    Name = "main-hosted-zone"
  }
}

# Health Checks
resource "aws_route53_health_check" "primary" {
  fqdn              = aws_lb.primary.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "primary-health-check"
  }
}

resource "aws_route53_health_check" "secondary" {
  fqdn              = aws_lb.secondary.dns_name
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "secondary-health-check"
  }
}

# Traffic Policy - Weighted Routing
resource "aws_route53_record" "weighted_primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "weighted.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  weighted_routing_policy {
    weight = 70
  }

  set_identifier  = "primary"
  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "weighted_secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "weighted.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }

  weighted_routing_policy {
    weight = 30
  }

  set_identifier  = "secondary"
  health_check_id = aws_route53_health_check.secondary.id
}

# Traffic Policy - Failover Routing
resource "aws_route53_record" "failover_primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "failover.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier  = "primary"
  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "failover_secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "failover.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier = "secondary"
}

# Traffic Policy - Geolocation Routing
resource "aws_route53_record" "geo_us" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "geo.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  geolocation_routing_policy {
    country = "US"
  }

  set_identifier  = "us-region"
  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "geo_eu" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "geo.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier  = "eu-region"
  health_check_id = aws_route53_health_check.secondary.id
}

resource "aws_route53_record" "geo_default" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "geo.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  geolocation_routing_policy {
    location = "*"
  }

  set_identifier = "default"
}

# Traffic Policy - Latency-based Routing
resource "aws_route53_record" "latency_us_east" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "latency.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  latency_routing_policy {
    region = "us-east-1"
  }

  set_identifier  = "us-east-1"
  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "latency_us_west" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "latency.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }

  latency_routing_policy {
    region = "us-west-1"
  }

  set_identifier  = "us-west-1"
  health_check_id = aws_route53_health_check.secondary.id
}

# Traffic Policy - Multivalue Answer Routing
resource "aws_route53_record" "multivalue_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "multivalue.example.com"
  type    = "A"
  ttl     = 60
  records = ["192.0.2.1"]

  multivalue_answer_routing_policy = true
  set_identifier                   = "multivalue-1"
  health_check_id                  = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "multivalue_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "multivalue.example.com"
  type    = "A"
  ttl     = 60
  records = ["192.0.2.2"]

  multivalue_answer_routing_policy = true
  set_identifier                   = "multivalue-2"
  health_check_id                  = aws_route53_health_check.secondary.id
}

# CloudWatch Alarms for Health Checks
resource "aws_cloudwatch_metric_alarm" "primary_health" {
  alarm_name          = "route53-primary-health-check"
  comparison_operator = "LessThanThreshold"
  evaluation_periods  = 2
  metric_name         = "HealthCheckStatus"
  namespace           = "AWS/Route53"
  period              = 60
  statistic           = "Minimum"
  threshold           = 1
  alarm_description   = "This metric monitors primary endpoint health"
  treat_missing_data  = "breaching"

  dimensions = {
    HealthCheckId = aws_route53_health_check.primary.id
  }
}

# Outputs
output "hosted_zone_id" {
  description = "The hosted zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "hosted_zone_nameservers" {
  description = "The nameservers for the hosted zone"
  value       = aws_route53_zone.main.name_servers
}

output "weighted_endpoint" {
  description = "Weighted routing endpoint"
  value       = "weighted.example.com"
}

output "failover_endpoint" {
  description = "Failover routing endpoint"
  value       = "failover.example.com"
}

output "geolocation_endpoint" {
  description = "Geolocation routing endpoint"
  value       = "geo.example.com"
}

output "latency_endpoint" {
  description = "Latency-based routing endpoint"
  value       = "latency.example.com"
}

output "multivalue_endpoint" {
  description = "Multivalue answer routing endpoint"
  value       = "multivalue.example.com"
}

output "primary_health_check_id" {
  description = "Primary health check ID"
  value       = aws_route53_health_check.primary.id
}

output "secondary_health_check_id" {
  description = "Secondary health check ID"
  value       = aws_route53_health_check.secondary.id
}
```

