}

# Data source for subnets with the required cluster tag
data "aws_subnets" "fargate" {
  filter {
    name   = "tag:kubernetes.io/cluster/${var.cluster_name}"
    values = ["shared", "owned"]
  }
}

# EKS Fargate Profile for kube-system namespace
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = data.aws_subnets.fargate.ids

  selector {
    namespace = "kube-system"
  }

  tags = {
    Name = "kube-system-fargate-profile"
  }

  depends_on = [
    aws_iam_role_policy_attachment.fargate_pod_execution_role_policy
  ]
}

# Data source for EKS cluster auth token
data "aws_eks_cluster_auth" "cluster" {
  name = var.cluster_name
}

# Null resource to patch CoreDNS deployment
resource "null_resource" "coredns_patch" {
  provisioner "local-exec" {
    command = <<-EOT
      kubectl patch deployment coredns \n        --namespace kube-system \n        --type=json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server='${data.aws_eks_cluster.cluster.endpoint}' \n        --token='${data.aws_eks_cluster_auth.cluster.token}' \n        --certificate-authority=<(echo '${data.aws_eks_cluster.cluster.certificate_authority[0].data}' | base64 -d)
    EOT

    interpreter = ["/bin/bash", "-c"]
  }

  depends_on = [
    aws_eks_fargate_profile.kube_system
  ]

  triggers = {
    fargate_profile_id = aws_eks_fargate_profile.kube_system.id
  }
}

# Variables
variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

# Outputs
output "fargate_pod_execution_role_arn" {
  description = "ARN of the Fargate pod execution role"
  value       = aws_iam_role.fargate_pod_execution_role.arn
}

output "fargate_profile_id" {
  description = "ID of the Fargate profile"
  value       = aws_eks_fargate_profile.kube_system.id
}

output "fargate_profile_status" {
  description = "Status of the Fargate profile"
  value       = aws_eks_fargate_profile.kube_system.status
}
```

