# Data source to get current AWS account ID and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Create the SNS topic
resource "aws_sns_topic" "s3_event_notification_topic" {
  name = "s3-event-notification-topic"
}

# Create the S3 bucket
resource "aws_s3_bucket" "bucket" {
  bucket = "your-bucket-name"
}

# Create IAM policy document for SNS topic
data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions = [
      "SNS:Publish"
    ]

    resources = [
      aws_sns_topic.s3_event_notification_topic.arn
    ]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.bucket.arn]
    }
  }
}

# Attach the policy to the SNS topic
resource "aws_sns_topic_policy" "s3_event_notification_policy" {
  arn    = aws_sns_topic.s3_event_notification_topic.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

# Configure S3 bucket notification to SNS topic
resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn = aws_sns_topic.s3_event_notification_topic.arn
    events    = ["s3:ObjectCreated:*"]

    filter_suffix = ".log"
  }

  depends_on = [aws_sns_topic_policy.s3_event_notification_policy]
}

