terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Primary bucket with private ACL
resource "aws_s3_bucket" "primary" {
  bucket = "my-primary-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "primary" {
  bucket = aws_s3_bucket.primary.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_public_access_block" "primary" {
  bucket = aws_s3_bucket.primary.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_acl" "primary" {
  depends_on = [
    aws_s3_bucket_ownership_controls.primary,
    aws_s3_bucket_public_access_block.primary
  ]

  bucket = aws_s3_bucket.primary.id
  acl    = "private"
}

# Logging bucket with log-delivery-write ACL
resource "aws_s3_bucket" "logging" {
  bucket = "my-logging-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "logging" {
  bucket = aws_s3_bucket.logging.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_public_access_block" "logging" {
  bucket = aws_s3_bucket.logging.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_acl" "logging" {
  depends_on = [
    aws_s3_bucket_ownership_controls.logging,
    aws_s3_bucket_public_access_block.logging
  ]

  bucket = aws_s3_bucket.logging.id
  acl    = "log-delivery-write"
}

# Enable logging on primary bucket to send logs to logging bucket
resource "aws_s3_bucket_logging" "primary_logging" {
  depends_on = [aws_s3_bucket_acl.logging]

  bucket = aws_s3_bucket.primary.id

  target_bucket = aws_s3_bucket.logging.id
  target_prefix = "logs/"
}

# Random suffix for unique bucket names
resource "random_id" "suffix" {
  byte_length = 8
}

output "primary_bucket_id" {
  description = "The ID of the primary bucket"
  value       = aws_s3_bucket.primary.id
}

output "logging_bucket_id" {
  description = "The ID of the logging bucket"
  value       = aws_s3_bucket.logging.id
}

output "primary_bucket_arn" {
  description = "The ARN of the primary bucket"
  value       = aws_s3_bucket.primary.arn
}

output "logging_bucket_arn" {
  description = "The ARN of the logging bucket"
  value       = aws_s3_bucket.logging.arn
}

