  role = aws_iam_role.ec2_fleet_role.name
}

# IAM Role for EC2 Fleet Service
resource "aws_iam_role" "fleet_role" {
  name = "ec2-fleet-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2fleet.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to Fleet Service Role
resource "aws_iam_role_policy_attachment" "fleet_policy" {
  role       = aws_iam_role.fleet_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/EC2FleetServiceRolePolicy"
}

# Launch Template
resource "aws_launch_template" "ec2_fleet" {
  name_prefix   = "ec2-fleet-template-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  iam_instance_profile {
    name = aws_iam_instance_profile.ec2_fleet.name
  }

  vpc_security_group_ids = [aws_security_group.ec2_fleet.id]

  monitoring {
    enabled = true
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
    }
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from EC2 Fleet Instance</h1>" > /var/www/html/index.html
              EOF
  )
}

# EC2 Fleet
resource "aws_ec2_fleet" "main" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_fleet.id
      version            = "$Latest"
    }

    override {
      subnet_id = aws_subnet.public_1.id
    }

    override {
      subnet_id = aws_subnet.public_2.id
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "on-demand"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  on_demand_options {
    allocation_strategy = "lowest-price"
  }

  spot_options {
    allocation_strategy = "lowest-price"
    instance_interruption_behavior = "terminate"
  }

  type                                 = "maintain"
  terminate_instances                  = true
  terminate_instances_with_expiration  = true

  tags = {
    Name = "main-ec2-fleet"
  }

  depends_on = [aws_iam_role_policy_attachment.fleet_policy]
}

