  node_type          = "dc2.large"
  number_of_nodes    = 2

  database_name = "mydb"
  master_username = "foo"
  master_password = "Mustbe8characters"

  skip_final_snapshot = true
}

resource "aws_redshift_endpoint_authorization" "example" {
  account            = "012345678910"
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
