terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "redshift_igw" {
  vpc_id = aws_vpc.redshift_vpc.id

  tags = {
    Name = "redshift-igw"
  }
}

# Subnets in different AZs
resource "aws_subnet" "redshift_subnet_1a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1a"
  }
}

resource "aws_subnet" "redshift_subnet_1b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-1b"
  }
}

# Route Table
resource "aws_route_table" "redshift_rt" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.redshift_igw.id
  }

  tags = {
    Name = "redshift-route-table"
  }
}

# Route Table Associations
resource "aws_route_table_association" "redshift_rta_1a" {
  subnet_id      = aws_subnet.redshift_subnet_1a.id
  route_table_id = aws_route_table.redshift_rt.id
}

resource "aws_route_table_association" "redshift_rta_1b" {
  subnet_id      = aws_subnet.redshift_subnet_1b.id
  route_table_id = aws_route_table.redshift_rt.id
}

# Redshift Subnet Group (Multi-AZ)
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1a.id, aws_subnet.redshift_subnet_1b.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Redshift access from VPC"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "redshift-cluster-role"
  }
}

# Attach S3 Read Only Access policy
resource "aws_iam_role_policy_attachment" "redshift_s3_readonly" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Redshift Cluster (Multi-AZ with automated snapshots)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier        = "redshift-cluster-multiaz"
  database_name            = "production"
  master_username          = "admin"
  master_password          = "Admin123456!"
  node_type                = "dc2.large"
  cluster_type             = "multi-node"
  number_of_nodes          = 2

  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  iam_roles                    = [aws_iam_role.redshift_role.arn]

  publicly_accessible          = false
  encrypted                    = true
  enhanced_vpc_routing         = true

  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:05:00-sun:06:00"

  skip_final_snapshot       = true
  final_snapshot_identifier = "redshift-final-snapshot-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"

  tags = {
    Name        = "redshift-cluster-multiaz"
    Environment = "production"
  }
}

# Outputs
output "redshift_cluster_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_cluster_id" {
  description = "Redshift cluster identifier"
  value       = aws_redshift_cluster.redshift_cluster.id
}

output "redshift_cluster_database_name" {
  description = "Redshift database name"
  value       = aws_redshift_cluster.redshift_cluster.database_name
}

