# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    description = "Redshift access"
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "redshift-cluster-role"
  }
}

resource "aws_iam_role_policy_attachment" "redshift_s3_read" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier     = "redshift-cluster"
  database_name          = "mydb"
  master_username        = "admin"
  master_password        = "Admin123456!"
  node_type              = "dc2.large"
  cluster_type           = "multi-node"
  number_of_nodes        = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  iam_roles              = [aws_iam_role.redshift_role.arn]
  publicly_accessible    = true
  skip_final_snapshot    = true

  tags = {
    Name = "redshift-cluster"
  }
}

# Redshift Endpoint Access
resource "aws_redshift_endpoint_access" "redshift_endpoint" {
  endpoint_name      = "redshift-endpoint"
  subnet_group_name  = aws_redshift_subnet_group.redshift_subnet_group.name
  cluster_identifier = aws_redshift_cluster.redshift_cluster.cluster_identifier
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

output "redshift_cluster_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_cluster_id" {
  description = "Redshift cluster identifier"
  value       = aws_redshift_cluster.redshift_cluster.id
}

output "redshift_endpoint_address" {
  description = "Redshift managed endpoint address"
  value       = aws_redshift_endpoint_access.redshift_endpoint.address
}

output "redshift_endpoint_port" {
  description = "Redshift managed endpoint port"
  value       = aws_redshift_endpoint_access.redshift_endpoint.port
}
```

