terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Example metric alarms that will be used in the composite alarm
resource "aws_cloudwatch_metric_alarm" "cpu_high" {
  alarm_name          = "cpu-utilization-high"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "This metric monitors ec2 cpu utilization"

  dimensions = {
    InstanceId = "i-1234567890abcdef0"
  }
}

resource "aws_cloudwatch_metric_alarm" "memory_high" {
  alarm_name          = "memory-utilization-high"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "MemoryUtilization"
  namespace           = "CWAgent"
  period              = 300
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "This metric monitors memory utilization"

  dimensions = {
    InstanceId = "i-1234567890abcdef0"
  }
}

# Composite Alarm
resource "aws_cloudwatch_composite_alarm" "example" {
  alarm_name          = "example-composite-alarm"
  alarm_description   = "Composite alarm that monitors CPU and Memory utilization"
  actions_enabled     = true

  alarm_actions = [
    "arn:aws:sns:us-east-1:123456789012:example-topic"
  ]

  ok_actions = [
    "arn:aws:sns:us-east-1:123456789012:example-topic"
  ]

  insufficient_data_actions = [
    "arn:aws:sns:us-east-1:123456789012:example-topic"
  ]

  # Alarm rule using boolean logic
  # Triggers when BOTH CPU and Memory alarms are in ALARM state
  alarm_rule = "ALARM(${aws_cloudwatch_metric_alarm.cpu_high.alarm_name}) AND ALARM(${aws_cloudwatch_metric_alarm.memory_high.alarm_name})"

  # Alternative alarm rules examples:
  # OR condition: alarm_rule = "ALARM(${aws_cloudwatch_metric_alarm.cpu_high.alarm_name}) OR ALARM(${aws_cloudwatch_metric_alarm.memory_high.alarm_name})"
  # Complex condition: alarm_rule = "(ALARM(alarm1) OR ALARM(alarm2)) AND NOT ALARM(alarm3)"

  actions_suppressor {
    alarm            = "suppressor-alarm-name"
    extension_period = 60
    wait_period      = 60
  }

  tags = {
    Name        = "example-composite-alarm"
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

output "composite_alarm_arn" {
  description = "ARN of the composite alarm"
  value       = aws_cloudwatch_composite_alarm.example.arn
}

output "composite_alarm_name" {
  description = "Name of the composite alarm"
  value       = aws_cloudwatch_composite_alarm.example.alarm_name
}

