terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "table_name" {
  description = "Name of the DynamoDB table"
  type        = string
  default     = "my-dynamodb-table"
}

variable "index_name" {
  description = "Global secondary index name (optional)"
  type        = string
  default     = null
}

# DynamoDB Table (example - replace with your existing table or remove if already exists)
resource "aws_dynamodb_table" "main" {
  name           = var.table_name
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  attribute {
    name = "status"
    type = "S"
  }

  global_secondary_index {
    name            = "status-index"
    hash_key        = "status"
    projection_type = "ALL"
  }

  tags = {
    Name        = var.table_name
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# DynamoDB Contributor Insights for the table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.main.name

  tags = {
    Name        = "${var.table_name}-contributor-insights"
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# DynamoDB Contributor Insights for a specific index (optional)
resource "aws_dynamodb_contributor_insights" "index_insights" {
  count = var.index_name != null ? 1 : 0

  table_name = aws_dynamodb_table.main.name
  index_name = var.index_name

  tags = {
    Name        = "${var.table_name}-${var.index_name}-contributor-insights"
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

output "table_contributor_insights_status" {
  description = "Status of Contributor Insights for the table"
  value       = aws_dynamodb_contributor_insights.table_insights.id
}

output "index_contributor_insights_status" {
  description = "Status of Contributor Insights for the index"
  value       = var.index_name != null ? aws_dynamodb_contributor_insights.index_insights[0].id : "N/A - No index specified"
}

output "dynamodb_table_name" {
  description = "Name of the DynamoDB table"
  value       = aws_dynamodb_table.main.name
}

output "dynamodb_table_arn" {
  description = "ARN of the DynamoDB table"
  value       = aws_dynamodb_table.main.arn
}

