terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"
  stream_enabled = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  tags = {
    Name        = "example-dynamodb-table"
    Environment = "production"
  }
}

# Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "IncomingRecords",
    "OutgoingBytes",
    "OutgoingRecords",
  ]

  tags = {
    Name        = "example-kinesis-stream"
    Environment = "production"
  }
}

# IAM Role for DynamoDB Kinesis Streaming
resource "aws_iam_role" "dynamodb_kinesis_role" {
  name = "dynamodb-kinesis-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "dynamodb-kinesis-role"
  }
}

# IAM Policy for Kinesis Write Access
resource "aws_iam_role_policy" "dynamodb_kinesis_policy" {
  name = "dynamodb-kinesis-streaming-policy"
  role = aws_iam_role.dynamodb_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords",
          "kinesis:DescribeStream"
        ]
