# Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "IncomingRecords",
    "OutgoingBytes",
    "OutgoingRecords",
  ]

  tags = {
    Name        = "example-kinesis-stream"
    Environment = "production"
  }
}

# IAM Role for DynamoDB Kinesis Streaming
resource "aws_iam_role" "dynamodb_kinesis_role" {
  name = "dynamodb-kinesis-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "dynamodb-kinesis-role"
  }
}

# IAM Policy for Kinesis Write Access
