terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary region provider
provider "aws" {
  alias  = "primary"
  region = "us-east-1"
}

# Secondary region provider for replica
provider "aws" {
  alias  = "secondary"
  region = "us-west-2"
}

# DynamoDB table in primary region
resource "aws_dynamodb_table" "primary" {
  provider         = aws.primary
  name             = "global-table-example"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "id"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  replica {
    region_name = "us-west-2"
  }

  tags = {
    Name        = "global-table-example"
    Environment = "production"
  }
}

# Output the table name and ARN
output "primary_table_name" {
  description = "Name of the primary DynamoDB table"
  value       = aws_dynamodb_table.primary.name
}

output "primary_table_arn" {
  description = "ARN of the primary DynamoDB table"
  value       = aws_dynamodb_table.primary.arn
}

output "table_id" {
  description = "ID of the DynamoDB table"
  value       = aws_dynamodb_table.primary.id
}

