terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for SageMaker Domain
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sagemaker-vpc"
  }
}

# Subnets
resource "aws_subnet" "sagemaker_subnet" {
  count             = 2
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "sagemaker-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# IAM Role for SageMaker Domain
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-domain-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Domain
resource "aws_sagemaker_domain" "main" {
  domain_name = "sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = aws_subnet.sagemaker_subnet[*].id

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    sharing_settings {
      notebook_output_option = "Allowed"
    }
  }

  tags = {
    Name = "sagemaker-domain"
  }
}

# User Profile (optional but commonly used with Domain)
resource "aws_sagemaker_user_profile" "default" {
  domain_id         = aws_sagemaker_domain.main.id
  user_profile_name = "default-user"

  user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn
  }
}

output "sagemaker_domain_id" {
  value       = aws_sagemaker_domain.main.id
  description = "The ID of the SageMaker Domain"
}

output "sagemaker_domain_arn" {
  value       = aws_sagemaker_domain.main.arn
  description = "The ARN of the SageMaker Domain"
}

output "sagemaker_domain_url" {
  value       = aws_sagemaker_domain.main.url
  description = "The URL of the SageMaker Domain"
}

