  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "sagemaker-subnet"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# SageMaker Domain
resource "aws_sagemaker_domain" "main" {
  domain_name = "sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_domain_role.arn
  }
}

# SageMaker Space
resource "aws_sagemaker_space" "main" {
  domain_id  = aws_sagemaker_domain.main.id
  space_name = "my-sagemaker-space"

  space_settings {
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type        = "system"
        sagemaker_image_arn  = "arn:aws:sagemaker:us-east-1:081325390199:image/jupyter-server-3"
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type       = "ml.t3.medium"
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:081325390199:image/datascience-1.0"
      }
    }
  }

  tags = {
    Name        = "my-sagemaker-space"
    Environment = "dev"
  }
}

output "sagemaker_space_id" {
  value       = aws_sagemaker_space.main.id
  description = "The ID of the SageMaker Space"
}

output "sagemaker_space_arn" {
  value       = aws_sagemaker_space.main.arn
  description = "The ARN of the SageMaker Space"
}

output "sagemaker_domain_id" {
  value       = aws_sagemaker_domain.main.id
  description = "The ID of the SageMaker Domain"
}
```

