# IAM role for SageMaker Pipeline execution
resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
  role       = aws_iam_role.sagemaker_pipeline_role.name
}

resource "aws_iam_role_policy" "sagemaker_pipeline_policy" {
  name = "sagemaker-pipeline-additional-policy"
  role = aws_iam_role.sagemaker_pipeline_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# SageMaker Pipeline
resource "aws_sagemaker_pipeline" "ml_pipeline" {
  pipeline_name         = "my-ml-pipeline"
  pipeline_display_name = "My ML Pipeline"
  role_arn              = aws_iam_role.sagemaker_pipeline_role.arn

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name        = "ProcessingInstanceType"
        Type        = "String"
        DefaultValue = "ml.m5.xlarge"
      },
      {
        Name        = "ProcessingInstanceCount"
        Type        = "Integer"
        DefaultValue = 1
      },
      {
        Name        = "TrainingInstanceType"
        Type        = "String"
        DefaultValue = "ml.m5.xlarge"
      },
      {
        Name        = "InputDataUrl"
        Type        = "String"
        DefaultValue = "s3://my-bucket/input-data/"
      },
      {
        Name        = "ModelApprovalStatus"
        Type        = "String"
        DefaultValue = "PendingManualApproval"
      }
    ]
    Steps = [
      {
        Name = "ProcessingStep"
        Type = "Processing"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceType   = { Get = "Parameters.ProcessingInstanceType" }
              InstanceCount  = { Get = "Parameters.ProcessingInstanceCount" }
              VolumeSizeInGB = 30
            }
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
          ProcessingInputs = [
            {
              InputName = "input-1"
              S3Input = {
                S3Uri                  = { Get = "Parameters.InputDataUrl" }
                LocalPath             = "/opt/ml/processing/input"
                S3DataType            = "S3Prefix"
                S3InputMode           = "File"
                S3DataDistributionType = "FullyReplicated"
              }
            }
          ]
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "train"
                S3Output = {
                  S3Uri       = "s3://my-bucket/processed/train"
                  LocalPath   = "/opt/ml/processing/train"
                  S3UploadMode = "EndOfJob"
                }
              },
              {
                OutputName = "test"
                S3Output = {
                  S3Uri       = "s3://my-bucket/processed/test"
                  LocalPath   = "/opt/ml/processing/test"
                  S3UploadMode = "EndOfJob"
                }
              }
            ]
          }
        }
      },
      {
        Name = "TrainingStep"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage     = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.2-1"
            TrainingInputMode = "File"
          }
          OutputDataConfig = {
            S3OutputPath = "s3://my-bucket/model-artifacts"
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
          ResourceConfig = {
            InstanceType   = { Get = "Parameters.TrainingInstanceType" }
            InstanceCount  = 1
            VolumeSizeInGB = 30
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri      = { Get = "Steps.ProcessingStep.ProcessingOutputConfig.Outputs['train'].S3Output.S3Uri" }
                  S3DataDistributionType = "FullyReplicated"
                }
              }
            }
          ]
          HyperParameters = {
            objective        = "reg:squarederror"
            num_round        = "50"
            max_depth        = "5"
            eta              = "0.2"
            gamma            = "4"
            min_child_weight = "6"
            subsample        = "0.7"
          }
        }
        DependsOn = ["ProcessingStep"]
      },
      {
        Name = "CreateModelStep"
        Type = "Model"
        Arguments = {
          ExecutionRoleArn = aws_iam_role.sagemaker_pipeline_role.arn
          PrimaryContainer = {
            Image        = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.2-1"
            ModelDataUrl = { Get = "Steps.TrainingStep.ModelArtifacts.S3ModelArtifacts" }
          }
        }
        DependsOn = ["TrainingStep"]
      },
      {
        Name = "RegisterModelStep"
        Type = "RegisterModel"
        Arguments = {
          ModelPackageGroupName = "my-model-package-group"
          ModelApprovalStatus   = { Get = "Parameters.ModelApprovalStatus" }
          InferenceSpecification = {
            Containers = [
              {
                Image        = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.2-1"
                ModelDataUrl = { Get = "Steps.TrainingStep.ModelArtifacts.S3ModelArtifacts" }
              }
            ]
            SupportedContentTypes = ["text/csv"]
            SupportedResponseMIMETypes = ["text/csv"]
          }
        }
        DependsOn = ["TrainingStep"]
      }
    ]
  })

  tags = {
    Name        = "my-ml-pipeline"
    Environment = "development"
  }
}

output "pipeline_arn" {
  description = "ARN of the SageMaker Pipeline"
  value       = aws_sagemaker_pipeline.ml_pipeline.arn
}

output "pipeline_name" {
  description = "Name of the SageMaker Pipeline"
  value       = aws_sagemaker_pipeline.ml_pipeline.pipeline_name
}

