          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# S3 Bucket for Model Artifacts
resource "aws_s3_bucket" "sagemaker_bucket" {
  bucket = "sagemaker-model-artifacts-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "sagemaker_bucket_versioning" {
  bucket = aws_s3_bucket.sagemaker_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# SageMaker Model
resource "aws_sagemaker_model" "model" {
  name               = "sagemaker-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image          = "382416733822.dkr.ecr.us-east-1.amazonaws.com/xgboost:latest"
    model_data_url = "s3://${aws_s3_bucket.sagemaker_bucket.bucket}/model.tar.gz"
  }
}

# SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "endpoint_config" {
  name = "sagemaker-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.model.name
    initial_instance_count = 1
    instance_type          = "ml.m5.large"
    initial_variant_weight = 1.0
  }

  tags = {
    Name        = "sagemaker-endpoint-config"
    Environment = "production"
  }
}

# SageMaker Endpoint
resource "aws_sagemaker_endpoint" "endpoint" {
  name                 = "sagemaker-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.endpoint_config.name

  tags = {
    Name        = "sagemaker-endpoint"
    Environment = "production"
  }
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "endpoint_name" {
  description = "Name of the SageMaker endpoint"
  value       = aws_sagemaker_endpoint.endpoint.name
}

output "endpoint_arn" {
  description = "ARN of the SageMaker endpoint"
  value       = aws_sagemaker_endpoint.endpoint.arn
}

output "model_name" {
  description = "Name of the SageMaker model"
  value       = aws_sagemaker_model.model.name
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket for model artifacts"
  value       = aws_s3_bucket.sagemaker_bucket.bucket
}
```

