  }
}

provider "aws" {
  region = "us-east-1"
}

# Create ElastiCache User Group
resource "aws_elasticache_user_group" "example" {
  engine        = "REDIS"
  user_group_id = "example-user-group"
  user_ids      = [aws_elasticache_user.default.user_id, aws_elasticache_user.example.user_id]

  lifecycle {
    ignore_changes = [user_ids]
  }
}

# Default user (required)
resource "aws_elasticache_user" "default" {
  user_id       = "default"
  user_name     = "default"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  authentication_mode {
    type = "no-password-required"
  }
}

# Example user with password authentication
resource "aws_elasticache_user" "example" {
  user_id       = "example-user-id"
  user_name     = "exampleuser"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  authentication_mode {
    type      = "password"
    passwords = ["YourSecurePassword123!"]
  }
}

# Example user with IAM authentication (Redis 7.0+)
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-user-id"
  user_name     = "iamusername"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  authentication_mode {
    type = "iam"
  }
}

# Subnet group for the cluster
resource "aws_elasticache_subnet_group" "example" {
  name       = "example-subnet-group"
  subnet_ids = [aws_subnet.example.id]
}

# VPC and Subnet for the cluster
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "example-vpc"
  }
}

resource "aws_subnet" "example" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "example-subnet"
  }
}

# ElastiCache Replication Group with User Group
resource "aws_elasticache_replication_group" "example" {
  replication_group_id = "example-redis-cluster"
  description          = "Redis cluster with user authentication"
  engine               = "redis"
  engine_version       = "7.0"
  node_type            = "cache.t3.micro"
  num_cache_clusters   = 1
  port                 = 6379

  subnet_group_name = aws_elasticache_subnet_group.example.name
  user_group_ids    = [aws_elasticache_user_group.example.user_group_id]

  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  automatic_failover_enabled = false

  tags = {
    Name = "example-redis"
  }
}

# Outputs
output "redis_endpoint" {
  value       = aws_elasticache_replication_group.example.primary_endpoint_address
  description = "Redis primary endpoint"
}

output "user_password_auth_id" {
  value       = aws_elasticache_user.example.user_id
  description = "User ID for password authentication"
}

output "user_iam_auth_id" {
  value       = aws_elasticache_user.iam_user.user_id
  description = "User ID for IAM authentication"
}

