# IAM Role for ElastiCache IAM Authentication
resource "aws_iam_role" "elasticache_iam_role" {
  name = "elasticache-iam-auth-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      },
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
      }
    ]
  })
}

# IAM Policy for ElastiCache Access
resource "aws_iam_policy" "elasticache_iam_policy" {
  name        = "elasticache-iam-auth-policy"
  description = "Policy for ElastiCache IAM authentication"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect"
        ]
        Resource = [
          "arn:aws:elasticache:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:user:*"
        ]
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "elasticache_policy_attachment" {
  role       = aws_iam_role.elasticache_iam_role.name
  policy_arn = aws_iam_policy.elasticache_iam_policy.arn
}

# ElastiCache Replication Group (Redis 6.x+ with IAM auth enabled)
resource "aws_elasticache_replication_group" "redis_with_iam" {
  replication_group_id       = "redis-iam-auth"
  description                = "Redis cluster with IAM authentication enabled"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  parameter_group_name       = "default.redis7"
  port                       = 6379
  transit_encryption_enabled = true
  at_rest_encryption_enabled = true
  auth_token_enabled         = false

  # IAM authentication requires Redis 7.0+ and transit encryption
  user_group_ids = [aws_elasticache_user_group.iam_user_group.id]

  tags = {
    Name = "redis-with-iam-auth"
  }
}

# ElastiCache User with IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-enabled-user"
  user_name     = "iam-user"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  # Enable IAM authentication
  authentication_mode {
    type = "iam"
  }

  tags = {
    Name = "iam-authenticated-user"
  }
}

# Default user (required for user group)
resource "aws_elasticache_user" "default_user" {
  user_id       = "default-user"
  user_name     = "default"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  authentication_mode {
    type = "iam"
  }
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "iam_user_group" {
  user_group_id = "iam-user-group"
  engine        = "REDIS"
  user_ids      = [aws_elasticache_user.default_user.user_id, aws_elasticache_user.iam_user.user_id]

  tags = {
    Name = "iam-user-group"
  }
}

# Data sources
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Outputs
output "replication_group_id" {
  value       = aws_elasticache_replication_group.redis_with_iam.id
  description = "ElastiCache replication group ID"
}

output "primary_endpoint" {
  value       = aws_elasticache_replication_group.redis_with_iam.primary_endpoint_address
  description = "Primary endpoint for Redis cluster"
}

output "iam_user_id" {
  value       = aws_elasticache_user.iam_user.user_id
  description = "IAM-authenticated ElastiCache user ID"
}

output "iam_role_arn" {
  value       = aws_iam_role.elasticache_iam_role.arn
  description = "IAM role ARN for ElastiCache authentication"
}

