```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and Networking
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"

  tags = {
    Name = "msk-subnet-3"
  }
}

resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "msk_kms_key" {
  description = "KMS key for MSK cluster encryption"

  tags = {
    Name = "msk-kms-key"
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster-logs"
  retention_in_days = 7

  tags = {
    Name = "msk-log-group"
  }
}

# S3 Bucket for logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "msk-logs-bucket"
  }
}

resource "aws_s3_bucket_public_access_block" "msk_logs_bucket_pab" {
  bucket = aws_s3_bucket.msk_logs_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "msk-firehose-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# S3 Bucket for Firehose
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "msk-firehose-logs-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "msk-firehose-bucket"
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_bucket_pab" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-log-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn

    buffering_size     = 5
    buffering_interval = 300
    compression_format = "GZIP"
  }

  tags = {
    Name = "msk-firehose"
  }
}

# MSK Cluster Configuration
resource "aws_msk_configuration" "msk_config" {
  name              = "msk-cluster-config"
  kafka_versions    = ["3.5.1"]
  server_properties = <<PROPERTIES
auto.create.topics.enable = true
delete.topic.enable = true
PROPERTIES
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = [
      aws_subnet.msk_subnet_1.id,
      aws_subnet.msk_subnet_2.id,
      aws_subnet.msk_subnet_3.id
    ]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "msk-broker-logs/"
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  tags = {
    Name = "msk-cluster"
  }
}

# S3 Bucket for MSK Connect Custom Plugin
resource "aws_s3_bucket" "msk_connect_plugin_bucket" {
  bucket = "msk-connect-plugin-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "msk-connect-plugin-bucket"
  }
}

resource "aws_s3_bucket_public_access_block" "msk_connect_plugin_bucket_pab" {
  bucket = aws_s3_bucket.msk_connect_plugin_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload debezium.zip to S3 (assumes file exists locally)
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_plugin_bucket.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip"
  etag   = filemd5("debezium.zip")

  tags = {
    Name = "debezium-plugin"
  }
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-connector-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect_plugin_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }

  description = "Debezium connector plugin for MSK Connect"
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = aws_msk_cluster.msk_cluster.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:*Topic*",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData"
        ]
        Resource = "arn:aws:kafka:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:topic/${aws_msk_cluster.msk_cluster.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:AlterGroup",
          "kafka-cluster:DescribeGroup"
        ]
        Resource = "arn:aws:kafka:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:group/${aws_msk_cluster.msk_cluster.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect_plugin_bucket.arn,
          "${aws_s3_bucket.msk_connect_plugin_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for MSK Connect
resource "aws_cloudwatch_log_group" "msk_connect_log_group" {
  name              = "/aws/mskconnect/connector-logs"
  retention_in_days = 7

  tags = {
    Name = "msk-connect-log-group"
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-msk-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2

      scale_in_policy {
        cpu_utilization_percentage = 20
      }

      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "localhost"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "dbz"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
    "database.history.kafka.topic"   = "schema-changes.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls

      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets = [
          aws_subnet.msk_subnet_1.id,
          aws_subnet.msk_subnet_2.id,
          aws_subnet.msk_subnet_3.id
        ]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_connect_log_group.name
      }
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  depends_on = [
    aws_msk_cluster.msk_cluster,
    aws_mskconnect_custom_plugin.debezium_plugin
  ]
}

# Data sources
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Outputs
output "msk_cluster_arn" {
  description = "ARN of the MSK cluster"
  value       = aws_msk_cluster.msk_cluster.arn
}

output "msk_cluster_bootstrap_brokers_tls" {
  description = "TLS connection host:port pairs"
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
}

output "msk_connect_plugin_arn" {
  description = "ARN of the MSK Connect custom plugin"
  value       = aws_mskconnect_custom_plugin.debezium_plugin.arn
}

output "msk_connect_connector_arn" {
  description = "ARN of the MSK Connect connector"
  value       = aws_mskconnect_connector.debezium_connector.arn
}
```

