terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "aurora-private-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "aurora-private-subnet-2"
  }
}

resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "Aurora DB subnet group"
  }
}

# Security Group
resource "aws_security_group" "aurora" {
  name        = "aurora-security-group"
  description = "Security group for Aurora PostgreSQL cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
    description = "PostgreSQL access from VPC"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "aurora-sg"
  }
}

# Random password for master user
resource "random_password" "master" {
  length  = 16
  special = true
}

# Aurora PostgreSQL Cluster
resource "aws_rds_cluster" "postgresql" {
  cluster_identifier      = "aurora-postgresql-cluster"
  engine                  = "aurora-postgresql"
  engine_version          = "15.4"
  database_name           = "mydb"
  master_username         = "dbadmin"
  master_password         = random_password.master.result
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  vpc_security_group_ids  = [aws_security_group.aurora.id]
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"
  skip_final_snapshot     = true
  storage_encrypted       = true

  tags = {
    Name = "aurora-postgresql-cluster"
  }
}

# Aurora PostgreSQL Cluster Instances
resource "aws_rds_cluster_instance" "postgresql_instance_1" {
  identifier          = "aurora-postgresql-instance-1"
  cluster_identifier  = aws_rds_cluster.postgresql.id
  instance_class      = "db.t3.medium"
  engine              = aws_rds_cluster.postgresql.engine
  engine_version      = aws_rds_cluster.postgresql.engine_version
  publicly_accessible = false

  tags = {
    Name = "aurora-postgresql-instance-1"
  }
}

resource "aws_rds_cluster_instance" "postgresql_instance_2" {
  identifier          = "aurora-postgresql-instance-2"
  cluster_identifier  = aws_rds_cluster.postgresql.id
  instance_class      = "db.t3.medium"
  engine              = aws_rds_cluster.postgresql.engine
  engine_version      = aws_rds_cluster.postgresql.engine_version
  publicly_accessible = false

  tags = {
    Name = "aurora-postgresql-instance-2"
  }
}

# Outputs
output "cluster_endpoint" {
  description = "Writer endpoint for the cluster"
  value       = aws_rds_cluster.postgresql.endpoint
}

output "reader_endpoint" {
  description = "Reader endpoint for the cluster"
  value       = aws_rds_cluster.postgresql.reader_endpoint
}

output "cluster_identifier" {
  description = "The cluster identifier"
  value       = aws_rds_cluster.postgresql.cluster_identifier
}

output "database_name" {
  description = "The database name"
  value       = aws_rds_cluster.postgresql.database_name
}

output "master_username" {
  description = "The master username"
  value       = aws_rds_cluster.postgresql.master_username
  sensitive   = true
}

output "master_password" {
  description = "The master password"
  value       = random_password.master.result
  sensitive   = true
}
