terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Get available availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC for RDS cluster
resource "aws_vpc" "mysql_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "mysql-cluster-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "mysql_igw" {
  vpc_id = aws_vpc.mysql_vpc.id

  tags = {
    Name = "mysql-cluster-igw"
  }
}

# Subnets in each availability zone
resource "aws_subnet" "mysql_subnet" {
  count                   = length(data.aws_availability_zones.available.names)
  vpc_id                  = aws_vpc.mysql_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.mysql_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "mysql-subnet-${data.aws_availability_zones.available.names[count.index]}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = aws_subnet.mysql_subnet[*].id

  tags = {
    Name = "mysql-cluster-subnet-group"
  }
}

# Security Group
resource "aws_security_group" "mysql_sg" {
  name        = "mysql-cluster-sg"
  description = "Security group for MySQL cluster"
  vpc_id      = aws_vpc.mysql_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-cluster-sg"
  }
}

# RDS Aurora MySQL Cluster
resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier      = "mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.04.0"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "ChangeMeToSecurePassword123!"
  db_subnet_group_name    = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.mysql_sg.id]
  storage_encrypted       = true
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"
  skip_final_snapshot     = true

  tags = {
    Name = "mysql-cluster"
  }
}

# RDS Aurora MySQL Cluster Instances (one per availability zone with 100GB storage)
resource "aws_rds_cluster_instance" "mysql_instance" {
  count                = length(data.aws_availability_zones.available.names)
  identifier           = "mysql-instance-${count.index + 1}"
  cluster_identifier   = aws_rds_cluster.mysql_cluster.id
  instance_class       = "db.r5.large"
  engine               = aws_rds_cluster.mysql_cluster.engine
  engine_version       = aws_rds_cluster.mysql_cluster.engine_version
  db_subnet_group_name = aws_db_subnet_group.mysql_subnet_group.name
  publicly_accessible  = false
  availability_zone    = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "mysql-instance-${data.aws_availability_zones.available.names[count.index]}"
  }
}

# Output cluster endpoint
output "cluster_endpoint" {
  description = "MySQL cluster endpoint"
  value       = aws_rds_cluster.mysql_cluster.endpoint
}

output "cluster_reader_endpoint" {
  description = "MySQL cluster reader endpoint"
  value       = aws_rds_cluster.mysql_cluster.reader_endpoint
}

output "cluster_instances" {
  description = "MySQL cluster instance endpoints"
  value       = aws_rds_cluster_instance.mysql_instance[*].endpoint
}

