terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for DAX cluster
resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_dynamodb_access" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Security group for DAX cluster
resource "aws_security_group" "dax_sg" {
  name        = "dax-cluster-sg"
  description = "Security group for DAX cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-cluster-sg"
  }
}

# VPC for DAX cluster
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# Subnets for DAX cluster
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-2"
  }
}

# DAX subnet group
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name       = "dax-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  description = "Subnet group for DAX cluster"
}

# DAX parameter group
resource "aws_dax_parameter_group" "dax_parameter_group" {
  name        = "dax-parameter-group"
  description = "Parameter group for DAX cluster"

  parameters {
    name  = "query-ttl-millis"
    value = "300000"
  }

  parameters {
    name  = "record-ttl-millis"
    value = "300000"
  }
}

# DAX cluster
resource "aws_dax_cluster" "main" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.t3.small"
  replication_factor = 3

  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_sg.id]
  parameter_group_name = aws_dax_parameter_group.dax_parameter_group.name

  description = "DAX cluster for DynamoDB acceleration"

  tags = {
    Name        = "my-dax-cluster"
    Environment = "production"
  }
}

# Outputs
output "dax_cluster_arn" {
  description = "ARN of the DAX cluster"
  value       = aws_dax_cluster.main.arn
}

output "dax_cluster_endpoint" {
  description = "Configuration endpoint of the DAX cluster"
  value       = aws_dax_cluster.main.configuration_endpoint
}

output "dax_cluster_nodes" {
  description = "List of node objects including address, port and availability zone"
  value       = aws_dax_cluster.main.nodes
}

