terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table with TTL enabled
resource "aws_dynamodb_table" "data_expiration_table" {
  name           = "data-expiration-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  ttl {
    enabled        = true
    attribute_name = "expiration_time"
  }

  tags = {
    Name        = "DataExpirationTable"
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# Example: Lambda function to insert items with custom TTL
resource "aws_iam_role" "lambda_role" {
  name = "data-expiration-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_dynamodb_policy" {
  name = "lambda-dynamodb-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem",
          "dynamodb:DeleteItem",
          "dynamodb:Query",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.data_expiration_table.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Output the table name and TTL attribute
output "dynamodb_table_name" {
  description = "Name of the DynamoDB table with TTL enabled"
  value       = aws_dynamodb_table.data_expiration_table.name
}

output "ttl_attribute_name" {
  description = "Name of the TTL attribute field"
  value       = aws_dynamodb_table.data_expiration_table.ttl[0].attribute_name
}

output "table_arn" {
  description = "ARN of the DynamoDB table"
  value       = aws_dynamodb_table.data_expiration_table.arn
}
```

