provider "aws" {
  region = "us-east-1"
}

# First VPC
resource "aws_vpc" "vpc_1" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc-1"
  }
}

# Second VPC
resource "aws_vpc" "vpc_2" {
  cidr_block           = "10.2.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc-2"
  }
}

# Subnet in VPC 1
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.vpc_1.id
  cidr_block        = "10.1.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "subnet-vpc-1"
  }
}

# Subnet in VPC 2
resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.vpc_2.id
  cidr_block        = "10.2.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "subnet-vpc-2"
  }
}

# VPC Peering Connection
resource "aws_vpc_peering_connection" "vpc_peering" {
  vpc_id      = aws_vpc.vpc_1.id
  peer_vpc_id = aws_vpc.vpc_2.id
  auto_accept = true

  tags = {
    Name = "vpc-1-to-vpc-2-peering"
  }
}

# Route table for VPC 1
resource "aws_route_table" "vpc_1_rt" {
  vpc_id = aws_vpc.vpc_1.id

  tags = {
    Name = "vpc-1-route-table"
  }
}

# Route table for VPC 2
resource "aws_route_table" "vpc_2_rt" {
  vpc_id = aws_vpc.vpc_2.id

  tags = {
    Name = "vpc-2-route-table"
  }
}

# Route from VPC 1 to VPC 2 via peering connection
resource "aws_route" "vpc_1_to_vpc_2" {
  route_table_id            = aws_route_table.vpc_1_rt.id
  destination_cidr_block    = aws_vpc.vpc_2.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

# Route from VPC 2 to VPC 1 via peering connection
resource "aws_route" "vpc_2_to_vpc_1" {
  route_table_id            = aws_route_table.vpc_2_rt.id
  destination_cidr_block    = aws_vpc.vpc_1.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

# Associate route table with subnet in VPC 1
resource "aws_route_table_association" "vpc_1_rta" {
  subnet_id      = aws_subnet.subnet_1.id
  route_table_id = aws_route_table.vpc_1_rt.id
}

# Associate route table with subnet in VPC 2
resource "aws_route_table_association" "vpc_2_rta" {
  subnet_id      = aws_subnet.subnet_2.id
  route_table_id = aws_route_table.vpc_2_rt.id
}

# Outputs
output "vpc_1_id" {
  description = "ID of VPC 1"
  value       = aws_vpc.vpc_1.id
}

output "vpc_2_id" {
  description = "ID of VPC 2"
  value       = aws_vpc.vpc_2.id
}

output "peering_connection_id" {
  description = "ID of the VPC peering connection"
  value       = aws_vpc_peering_connection.vpc_peering.id
}

output "vpc_1_cidr" {
  description = "CIDR block of VPC 1"
  value       = aws_vpc.vpc_1.cidr_block
}

output "vpc_2_cidr" {
  description = "CIDR block of VPC 2"
  value       = aws_vpc.vpc_2.cidr_block
}

