# Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom" {
  family      = "neptune1.3"
  name        = "neptune-custom-parameter-group"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "neptune-custom-parameter-group"
  }
}

# Neptune DB Parameter Group
resource "aws_neptune_parameter_group" "custom" {
  family      = "neptune1.3"
  name        = "neptune-custom-db-parameter-group"
  description = "Custom DB parameter group for Neptune instances"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "neptune-custom-db-parameter-group"
  }
}

# Neptune Subnet Group
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier                   = "neptune-cluster"
  engine                              = "neptune"
  engine_version                      = "1.3.2.1"
  backup_retention_period             = 7
  preferred_backup_window             = "03:00-04:00"
  preferred_maintenance_window        = "mon:04:00-mon:05:00"
  skip_final_snapshot                 = true
  neptune_subnet_group_name           = aws_neptune_subnet_group.main.name
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.name
  vpc_security_group_ids              = [aws_security_group.neptune.id]
  apply_immediately                   = true
  storage_encrypted                   = true

  tags = {
    Name = "neptune-cluster"
  }
}

# Neptune Instance
resource "aws_neptune_cluster_instance" "main" {
  count                        = 1
  cluster_identifier           = aws_neptune_cluster.main.id
  engine                       = "neptune"
  instance_class               = "db.t3.medium"
  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name
  apply_immediately            = true

  tags = {
    Name = "neptune-instance-${count.index + 1}"
  }
}

# Security Group for Neptune
resource "aws_security_group" "neptune" {
  name        = "neptune-security-group"
  description = "Security group for Neptune cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [var.allowed_cidr_block]
    description = "Neptune port"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Variables
variable "vpc_id" {
  description = "VPC ID for Neptune cluster"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for Neptune subnet group"
  type        = list(string)
}

variable "allowed_cidr_block" {
  description = "CIDR block allowed to connect to Neptune"
  type        = string
  default     = "10.0.0.0/16"
}

# Outputs
output "neptune_cluster_endpoint" {
  description = "Neptune cluster endpoint"
  value       = aws_neptune_cluster.main.endpoint
}

output "neptune_cluster_reader_endpoint" {
  description = "Neptune cluster reader endpoint"
  value       = aws_neptune_cluster.main.reader_endpoint
}

output "neptune_cluster_id" {
  description = "Neptune cluster identifier"
  value       = aws_neptune_cluster.main.id
}

output "neptune_cluster_port" {
  description = "Neptune cluster port"
  value       = aws_neptune_cluster.main.port
}
