provider "aws" {
  region = "us-east-1" # Chime Voice Connectors are only available in us-east-1
}

resource "aws_chime_voice_connector" "connector_1" {
  name               = "voice-connector-1"
  require_encryption = true
  aws_region         = "us-east-1"
}

resource "aws_chime_voice_connector" "connector_2" {
  name               = "voice-connector-2"
  require_encryption = true
  aws_region         = "us-east-1"
}

resource "aws_chime_voice_connector_group" "main" {
  name = "voice-connector-group"

  connector {
    voice_connector_id = aws_chime_voice_connector.connector_1.id
    priority           = 1
  }

  connector {
    voice_connector_id = aws_chime_voice_connector.connector_2.id
    priority           = 2
  }
}

output "voice_connector_1_id" {
  description = "ID of the first Voice Connector"
  value       = aws_chime_voice_connector.connector_1.id
}

output "voice_connector_2_id" {
  description = "ID of the second Voice Connector"
  value       = aws_chime_voice_connector.connector_2.id
}

output "voice_connector_group_id" {
  description = "ID of the Voice Connector Group"
  value       = aws_chime_voice_connector_group.main.id
}

output "voice_connector_group_name" {
  description = "Name of the Voice Connector Group"
  value       = aws_chime_voice_connector_group.main.name
}

