extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Chime Voice Connector to write to Kinesis
resource "aws_iam_role" "chime_kinesis_role" {
  name = "chime-voice-connector-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "voiceconnector.chime.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Chime to write to Kinesis
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "chime-kinesis-write-policy"
  role = aws_iam_role.chime_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.media_stream.arn
      }
    ]
  })
}

# Kinesis Data Stream for media streaming
resource "aws_kinesis_stream" "media_stream" {
  name             = "chime-media-stream"
  shard_count      = 2
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "IncomingRecords",
    "OutgoingBytes",
    "OutgoingRecords"
  ]

  tags = {
    Name        = "chime-media-stream"
    Environment = "production"
  }
}

# Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "my-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"

  tags = {
    Name        = "main-voice-connector"
    Environment = "production"
  }
}

# Chime Voice Connector Streaming Configuration
resource "aws_chime_voice_connector_streaming" "main" {
  voice_connector_id = aws_chime_voice_connector.main.id
  disabled           = false
  data_retention     = 24

  streaming_notification_targets = ["EventBridge"]

  media_insights_configuration {
    disabled               = false
    configuration_arn      = aws_chimesdkmediapipelines_media_insights_pipeline_configuration.main.arn
  }
}

# Chime SDK Media Pipelines - Media Insights Pipeline Configuration
resource "aws_chimesdkmediapipelines_media_insights_pipeline_configuration" "main" {
  name                     = "media-insights-config"
  resource_access_role_arn = aws_iam_role.chime_kinesis_role.arn

  elements {
    type = "KinesisDataStreamSink"
    kinesis_data_stream_sink_configuration {
      insights_target = aws_kinesis_stream.media_stream.arn
    }
  }

  tags = {
    Name        = "media-insights-configuration"
    Environment = "production"
  }
}

# Outputs
output "voice_connector_id" {
  description = "The ID of the Chime Voice Connector"
  value       = aws_chime_voice_connector.main.id
}

output "voice_connector_outbound_host_name" {
  description = "The outbound host name for the Voice Connector"
  value       = aws_chime_voice_connector.main.outbound_host_name
}

output "kinesis_stream_name" {
  description = "The name of the Kinesis stream"
  value       = aws_kinesis_stream.media_stream.name
}

output "kinesis_stream_arn" {
  description = "The ARN of the Kinesis stream"
  value       = aws_kinesis_stream.media_stream.arn
}

