  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security Group
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "redshift-role"
  }
}

resource "aws_iam_role_policy_attachment" "redshift_s3_read" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# SNS Topic for Event Notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-event-notifications"

  tags = {
    Name = "redshift-events"
  }
}

resource "aws_sns_topic_subscription" "redshift_events_email" {
  topic_arn = aws_sns_topic.redshift_events.arn
  protocol  = "email"
  endpoint  = "admin@example.com"
}

# Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "redshift-cluster-1"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "MySecurePassword123!" # Change this to a secure password
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  iam_roles                    = [aws_iam_role.redshift_role.arn]
  publicly_accessible          = false
  encrypted                    = true
  enhanced_vpc_routing         = true
  automated_snapshot_retention_period = 7
  skip_final_snapshot          = true

  tags = {
    Name        = "redshift-cluster"
    Environment = "production"
  }
}

# Redshift Event Subscription
resource "aws_redshift_event_subscription" "cluster_events" {
  name          = "redshift-cluster-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.main.id]

  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  enabled = true

  tags = {
    Name = "redshift-cluster-events"
  }
}

resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster-parameter-group"

  event_categories = [
    "configuration"
  ]

  enabled = true

  tags = {
    Name = "redshift-parameter-group-events"
  }
}

resource "aws_redshift_event_subscription" "snapshot_events" {
  name          = "redshift-snapshot-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster-snapshot"

  event_categories = [
    "monitoring"
  ]

  enabled = true

  tags = {
    Name = "redshift-snapshot-events"
  }
}

# Outputs
output "redshift_cluster_id" {
  description = "The Redshift cluster ID"
  value       = aws_redshift_cluster.main.id
}

output "redshift_cluster_endpoint" {
  description = "The connection endpoint"
  value       = aws_redshift_cluster.main.endpoint
}

output "redshift_cluster_port" {
  description = "The port the cluster responds on"
  value       = aws_redshift_cluster.main.port
}

output "sns_topic_arn" {
