  }
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "Redshift VPC"
  }
}

# Subnets
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "Redshift Subnet 1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "Redshift Subnet 2"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift Security Group"
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier        = "redshift-cluster"
  database_name             = "mydb"
  master_username           = "admin"
  master_password           = "MyPassword123!"
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  publicly_accessible       = false
  skip_final_snapshot       = true

  tags = {
    Name = "Redshift Cluster"
  }
}

# Redshift Event Subscription
resource "aws_redshift_event_subscription" "redshift_event_subscription" {
  name          = "redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.redshift_cluster.id]

  severity = "INFO"

  event_categories = [
