  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_cluster_id" {
  description = "Redshift cluster identifier"
  value       = aws_redshift_cluster.redshift_cluster.id
}

output "sns_topic_arn" {
  description = "SNS topic ARN for Redshift events"
  value       = aws_sns_topic.redshift_events.arn
}

output "event_subscription_id" {
  description = "Redshift event subscription ID"
  value       = aws_redshift_event_subscription.redshift_event_subscription.id
}

