provider "aws" {
  region = "us-east-1"
}

# Create VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create subnets
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Create subnet group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Create security group
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# Create IAM role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "redshift-cluster-role"
  }
}

# Attach S3 read only policy to the role
resource "aws_iam_role_policy_attachment" "redshift_s3_policy" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Create Redshift parameter group
resource "aws_redshift_parameter_group" "redshift_pg" {
  name        = "redshift-parameter-group"
  family      = "redshift-1.0"
  description = "Custom Redshift parameter group"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "max_cursor_result_set_size"
    value = "default"
  }

  tags = {
    Name = "redshift-parameter-group"
  }
}

# Create SNS topic for event notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-events-topic"

  tags = {
    Name = "redshift-events-topic"
  }
}

# Create SNS topic subscription (email example)
resource "aws_sns_topic_subscription" "redshift_events_email" {
  topic_arn = aws_sns_topic.redshift_events.arn
  protocol  = "email"
  endpoint  = "admin@example.com"
}

# Create Redshift event subscription for parameter group
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster-parameter-group"
  source_ids  = [aws_redshift_parameter_group.redshift_pg.id]

  severity = "INFO"

  event_categories = [
    "configuration"
  ]

  enabled = true

  tags = {
    Name = "redshift-parameter-group-events"
  }
}

# Create Redshift event subscription for cluster
resource "aws_redshift_event_subscription" "cluster_events" {
  name          = "redshift-cluster-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.sample_cluster.id]

  severity = "INFO"

  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  enabled = true

  tags = {
    Name = "redshift-cluster-events"
  }
}

# Create Redshift cluster
resource "aws_redshift_cluster" "sample_cluster" {
  cluster_identifier  = "sample-redshift-cluster"
  database_name       = "sampledb"
  master_username     = "admin"
  master_password     = "Admin123456!"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  port                = 5439
  publicly_accessible = false

  # Network configuration
  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  cluster_parameter_group_name = aws_redshift_parameter_group.redshift_pg.name

  # IAM role
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Backup and maintenance
  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:05:00-sun:06:00"
  skip_final_snapshot                 = true

  # Encryption
  encrypted = true

  # Logging
  logging {
    enable        = true
    bucket_name   = aws_s3_bucket.redshift_logs.id
    s3_key_prefix = "redshift-logs/"
  }

  tags = {
    Name        = "sample-redshift-cluster"
    Environment = "development"
  }

  depends_on = [
    aws_iam_role_policy_attachment.redshift_s3_policy
  ]
}

# Create S3 bucket for Redshift logs
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "redshift-logs-bucket-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "redshift-logs-bucket"
  }
}

resource "aws_s3_bucket_ownership_controls" "redshift_logs" {
  bucket = aws_s3_bucket.redshift_logs.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "redshift_logs" {
  depends_on = [aws_s3_bucket_ownership_controls.redshift_logs]

  bucket = aws_s3_bucket.redshift_logs.id
  acl    = "log-delivery-write"
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "redshift_cluster_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.sample_cluster.endpoint
}

output "redshift_cluster_id" {
  description = "Redshift cluster identifier"
  value       = aws_redshift_cluster.sample_cluster.id
}

output "redshift_parameter_group_name" {
  description = "Redshift parameter group name"
  value       = aws_redshift_parameter_group.redshift_pg.name
}

output "sns_topic_arn" {
  description = "SNS topic ARN for Redshift events"
  value       = aws_sns_topic.redshift_events.arn
}

