provider "aws" {
  region = "us-east-1"
}

# SNS Topic for Redshift events
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-parameter-group-events"
}

# Redshift Cluster Parameter Group
resource "aws_redshift_parameter_group" "main" {
  name   = "redshift-parameter-group"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_cursor_result_set_size"
    value = "default"
  }

  tags = {
    Name = "redshift-parameter-group"
  }
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_1.id, aws_subnet.redshift_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# VPC for Redshift
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Subnets for Redshift
resource "aws_subnet" "redshift_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "redshift-cluster"
  database_name       = "mydb"
  master_username     = "adminuser"
  master_password     = "AdminPassword123!"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  cluster_parameter_group_name = aws_redshift_parameter_group.main.name

  skip_final_snapshot = true
  publicly_accessible = false

  tags = {
    Name = "redshift-cluster"
  }
}

# Redshift Event Subscription for Parameter Group events
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-events"
  sns_topic_arn = aws_sns_topic.redshift_events.arn
  source_type   = "cluster-parameter-group"
  source_ids    = [aws_redshift_parameter_group.main.id]

  event_categories = [
    "configuration"
  ]

  enabled = true

  tags = {
    Name = "redshift-parameter-group-event-subscription"
  }
}

