  value       = aws_s3_object.test_pdf.key
  description = "S3 object key for the PDF file"
}

output "pdf_s3_uri" {
  value       = "s3://${aws_s3_bucket.pdf_bucket.id}/${aws_s3_object.test_pdf.key}"
  description = "S3 URI of the uploaded PDF"
}

