provider "aws" {
  region = "us-east-1"
}

resource "aws_kms_key" "s3_encryption_key" {
  description             = "KMS key for S3 bucket encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name        = "s3-encryption-key"
    Environment = "production"
  }
}

resource "aws_kms_alias" "s3_encryption_key_alias" {
  name          = "alias/s3-encryption-key"
  target_key_id = aws_kms_key.s3_encryption_key.key_id
}

resource "aws_s3_bucket" "encrypted_bucket" {
  bucket = "my-encrypted-bucket-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "EncryptedBucket"
    Environment = "production"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "bucket_encryption" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
    }
    bucket_key_enabled = true
  }
}

data "aws_caller_identity" "current" {}

output "bucket_name" {
  description = "Name of the S3 bucket"
  value       = aws_s3_bucket.encrypted_bucket.id
}

output "kms_key_id" {
  description = "ID of the KMS key"
  value       = aws_kms_key.s3_encryption_key.id
}

output "kms_key_arn" {
  description = "ARN of the KMS key"
  value       = aws_kms_key.s3_encryption_key.arn
}

