extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "github_token" {
  description = "GitHub personal access token"
  type        = string
  sensitive   = true
}

variable "course_name" {
  description = "Name of the course"
  type        = string
  default     = "cs-course"
}

# S3 bucket for storing grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "${var.course_name}-grading-results-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "${var.course_name}-codebuild-artifacts-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.course_name}-autograder"
  retention_in_days = 30
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.course_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.course_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "${aws_cloudwatch_log_group.codebuild_logs.arn}",
          "${aws_cloudwatch_log_group.codebuild_logs.arn}:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.codebuild_artifacts.arn}/*",
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.codebuild_artifacts.arn,
          aws_s3_bucket.grading_results.arn
        ]
      }
    ]
  })
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name                    = "${var.course_name}-github-token"
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = var.github_token
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "${var.course_name}-autograder"
  description   = "Autograding system for ${var.course_name}"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 60

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    path     = "artifacts/"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = aws_secretsmanager_secret.github_token.arn
      type  = "SECRETS_MANAGER"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "autograder"
    }
  }

  source {
    type            = "NO_SOURCE"
    buildspec = yamlencode({
      version = 0.2
      phases = {
        install = {
          runtime-versions = {
            python = "3.11"
            nodejs = "18"
          }
          commands = [
            "echo Installing dependencies...",
            "pip install pytest pylint flake8"
          ]
        }
        pre_build = {
          commands = [
            "echo Cloning student repository...",
            "git clone https://$GITHUB_TOKEN@github.com/$REPO_OWNER/$REPO_NAME.git student_code",
            "cd student_code",
            "git checkout $COMMIT_SHA || git checkout main || git checkout master"
          ]
        }
        build = {
          commands = [
            "echo Running autograder...",
            "cd student_code",
            "chmod +x run_tests.sh || true",
            "./run_tests.sh > /tmp/grading_output.txt 2>&1 || pytest . > /tmp/grading_output.txt 2>&1 || echo 'No tests found' > /tmp/grading_output.txt",
            "pylint **/*.py > /tmp/linting_output.txt 2>&1 || true",
            "echo Test execution completed"
          ]
        }
        post_build = {
          commands = [
            "echo Uploading grading results...",
            "TIMESTAMP=$(date +%Y%m%d-%H%M%S)",
            "RESULT_FILE="results/$REPO_OWNER/$REPO_NAME/$TIMESTAMP/grading_report.json"",
            "mkdir -p /tmp/results",
            "cat > /tmp/results/grading_report.json <<EOF",
            "{",
            "  "student": "$REPO_OWNER",",
            "  "repository": "$REPO_NAME",",
            "  "commit": "$COMMIT_SHA",",
            "  "timestamp": "$TIMESTAMP",",
            "  "test_output": "$(cat /tmp/grading_output.txt | base64 -w 0)",",
            "  "lint_output": "$(cat /tmp/linting_output.txt | base64 -w 0)"",
            "}",
            "EOF",
            "aws s3 cp /tmp/results/grading_report.json s3://$RESULTS_BUCKET/$RESULT_FILE",
            "cat /tmp/grading_output.txt",
            "echo Grading complete. Results uploaded to s3://$RESULTS_BUCKET/$RESULT_FILE"
          ]
        }
      }
    })
  }

  cache {
    type  = "LOCAL"
    modes = ["LOCAL_SOURCE_CACHE"]
  }
}

# DynamoDB table for tracking grading submissions
