data "archive_file" "lambda_trigger" {
  type        = "zip"
  output_path = "lambda_trigger.zip"

  source {
    content = <<-EOF
import json
import boto3
import os
import time

codebuild = boto3.client('codebuild')
dynamodb = boto3.resource('dynamodb')

def handler(event, context):
    """
    Trigger CodeBuild autograder for a student submission
    Expected event: {
      "repo_owner": "student-github-username",
      "repo_name": "assignment-repository",
      "commit_sha": "git-commit-hash",
      "student_id": "student-id"
    }
    """

    repo_owner = event.get('repo_owner')
    repo_name = event.get('repo_name')
    commit_sha = event.get('commit_sha', 'main')
    student_id = event.get('student_id', repo_owner)

    project_name = os.environ['CODEBUILD_PROJECT']
    table_name = os.environ['DYNAMODB_TABLE']

    # Record submission in DynamoDB
    table = dynamodb.Table(table_name)
    submission_id = f"{student_id}-{repo_name}-{int(time.time())}"

    table.put_item(
        Item={
            'SubmissionId': submission_id,
            'Timestamp': int(time.time()),
            'StudentId': student_id,
            'RepoOwner': repo_owner,
            'RepoName': repo_name,
            'CommitSha': commit_sha,
            'Status': 'STARTED'
        }
    )

    # Start CodeBuild project
    response = codebuild.start_build(
        projectName=project_name,
        environmentVariablesOverride=[
            {
                'name': 'REPO_OWNER',
                'value': repo_owner,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'REPO_NAME',
                'value': repo_name,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'COMMIT_SHA',
                'value': commit_sha,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'STUDENT_ID',
                'value': student_id,
                'type': 'PLAINTEXT'
            }
        ]
    )

    build_id = response['build']['id']

    # Update DynamoDB with build ID
    table.update_item(
        Key={
            'SubmissionId': submission_id,
            'Timestamp': int(time.time())
        },
        UpdateExpression='SET BuildId = :build_id',
        ExpressionAttributeValues={
            ':build_id': build_id
        }
    )

    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Autograder started successfully',
            'submission_id': submission_id,
            'build_id': build_id
        })
    }
EOF
    filename = "index.py"
  }
}

