        Item={
            'SubmissionId': submission_id,
            'Timestamp': int(time.time()),
            'StudentId': student_id,
            'RepoOwner': repo_owner,
            'RepoName': repo_name,
            'CommitSha': commit_sha,
            'Status': 'STARTED'
        }
    )

    # Start CodeBuild project
    response = codebuild.start_build(
        projectName=project_name,
        environmentVariablesOverride=[
            {
                'name': 'REPO_OWNER',
                'value': repo_owner,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'REPO_NAME',
                'value': repo_name,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'COMMIT_SHA',
                'value': commit_sha,
                'type': 'PLAINTEXT'
            },
            {
                'name': 'STUDENT_ID',
                'value': student_id,
                'type': 'PLAINTEXT'
            }
        ]
    )

    build_id = response['build']['id']

    # Update DynamoDB with build ID
    table.update_item(
        Key={
            'SubmissionId': submission_id,
            'Timestamp': int(time.time())
        },
        UpdateExpression='SET BuildId = :build_id',
        ExpressionAttributeValues={
            ':build_id': build_id
        }
    )

    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Autograder started successfully',
            'submission_id': submission_id,
            'build_id': build_id
        })
    }
EOF
    filename = "index.py"
  }
}

# API Gateway for triggering autograder via HTTP
resource "aws_apigatewayv2_api" "autograder_api" {
  name          = "${var.course_name}-autograder-api"
  protocol_type = "HTTP"
