resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for test cases and grading scripts
resource "aws_s3_bucket" "test_cases" {
  bucket = "${var.course_name}-test-cases-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "test_cases" {
  bucket = aws_s3_bucket.test_cases.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "test_cases" {
