resource "aws_codebuild_project" "autograder" {
  name          = "${var.course_name}-autograder"
  description   = "Autograding system for ${var.course_name}"
  build_timeout = 30
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.id
    packaging = "ZIP"
