      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.id
    }

    environment_variable {
      name  = "TEST_CASES_BUCKET"
      value = aws_s3_bucket.test_cases.id
    }

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.submissions.name
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/placeholder/student-repo.git"
    git_clone_depth = 1
    buildspec       = file("${path.module}/buildspec.yml")
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.course_name}-autograder"
      stream_name = "build-logs"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  tags = {
    Name = "${var.course_name}-autograder"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.course_name}-autograder"
  retention_in_days = 30
}

