}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "course_name" {
  description = "Name of the course"
  type        = string
  default     = "cs101"
}

# S3 Bucket for storing grading results and artifacts
resource "aws_s3_bucket" "grading_results" {
  bucket = "${var.course_name}-autograder-results-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "${var.course_name}-codebuild-artifacts-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for test cases and grading scripts
resource "aws_s3_bucket" "test_cases" {
  bucket = "${var.course_name}-test-cases-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "test_cases" {
  bucket = aws_s3_bucket.test_cases.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "test_cases" {
  bucket = aws_s3_bucket.test_cases.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# DynamoDB table for tracking submissions and grading status
resource "aws_dynamodb_table" "submissions" {
  name           = "${var.course_name}-submissions"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "submission_id"
  range_key      = "timestamp"

  attribute {
    name = "submission_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "N"
  }

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "status"
    type = "S"
  }

  global_secondary_index {
    name            = "student-index"
    hash_key        = "student_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  global_secondary_index {
    name            = "status-index"
    hash_key        = "status"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Name = "${var.course_name}-submissions"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.course_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.course_name}-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.codebuild_artifacts.arn}/*",
          "${aws_s3_bucket.grading_results.arn}/*",
          "${aws_s3_bucket.test_cases.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.codebuild_artifacts.arn,
          aws_s3_bucket.grading_results.arn,
          aws_s3_bucket.test_cases.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem"
        ]
        Resource = aws_dynamodb_table.submissions.arn
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild Project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "${var.course_name}-autograder"
  description   = "Autograding system for ${var.course_name}"
  build_timeout = 30
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.id
    packaging = "ZIP"
    name      = "grading-artifacts"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:7.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode            = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.id
    }

    environment_variable {
      name  = "TEST_CASES_BUCKET"
      value = aws_s3_bucket.test_cases.id
    }

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.submissions.name
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/placeholder/student-repo.git"
    git_clone_depth = 1
    buildspec       = file("${path.module}/buildspec.yml")
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.course_name}-autograder"
      stream_name = "build-logs"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  tags = {
    Name = "${var.course_name}-autograder"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.course_name}-autograder"
  retention_in_days = 30
}

# SNS Topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "${var.course_name}-grading-notifications"
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "${var.course_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild",
          "codebuild:BatchGetBuilds"
        ]
        Resource = aws_codebuild_project.autograder.arn
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem",
          "dynamodb:Query"
        ]
        Resource = [
          aws_dynamodb_table.submissions.arn,
          "${aws_dynamodb_table.submissions.arn}/index/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.grading_notifications.arn
      }
    ]
  })
}

# Lambda function to trigger autograding
resource "aws_lambda_function" "trigger_grading" {
  filename      = "lambda_trigger.zip"
  function_name = "${var.course_name}-trigger-grading"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      DYNAMODB_TABLE    = aws_dynamodb_table.submissions.name
      SNS_TOPIC_ARN     = aws_sns_topic.grading_notifications.arn
    }
  }
}

# Lambda function to process grading results
resource "aws_lambda_function" "process_results" {
  filename      = "lambda_process.zip"
  function_name = "${var.course_name}-process-results"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  environment {
    variables = {
      RESULTS_BUCKET = aws_s3_bucket.grading_results.id
      DYNAMODB_TABLE = aws_dynamodb_table.submissions.name
      SNS_TOPIC_ARN  = aws_sns_topic.grading_notifications.arn
    }
  }
}

# EventBridge Rule for CodeBuild state changes
resource "aws_cloudwatch_event_rule" "codebuild_state_change" {
  name        = "${var.course_name}-codebuild-state-change"
  description = "Capture CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
      build-status = ["SUCCEEDED", "FAILED", "STOPPED"]
    }
  })
}

resource "aws_cloudwatch_event_target" "process_results_target" {
  rule      = aws_cloudwatch_event_rule.codebuild_state_change.name
  target_id = "ProcessResults"
  arn       = aws_lambda_function.process_results.arn
}

resource "aws_lambda_permission" "allow_eventbridge_process" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.process_results.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.codebuild_state_change.arn
}

# API Gateway for submission endpoint
resource "aws_apigatewayv2_api" "grading_api" {
  name          = "${var.course_name}-grading-api"
  protocol_type = "HTTP"
  description   = "API for submitting code for grading"

  cors_configuration {
    allow_origins = ["*"]
    allow_methods = ["POST", "GET", "OPTIONS"]
    allow_headers = ["content-type", "authorization"]
    max_age       = 300
  }
}

resource "aws_apigatewayv2_stage" "grading_api_stage" {
  api_id      = aws_apigatewayv2_api.grading_api.id
  name        = "prod"
  auto_deploy = true

  access_log_settings {
    destination_arn = aws_cloudwatch_log_group.api_logs.arn
    format = jsonencode({
      requestId      = "$context.requestId"
      ip             = "$context.identity.sourceIp"
      requestTime    = "$context.requestTime"
      httpMethod     = "$context.httpMethod"
      routeKey       = "$context.routeKey"
      status         = "$context.status"
      protocol       = "$context.protocol"
      responseLength = "$context.responseLength"
    })
  }
}

resource "aws_cloudwatch_log_group" "api_logs" {
  name              = "/aws/apigateway/${var.course_name}-grading-api"
  retention_in_days = 14
}

resource "aws_apigatewayv2_integration" "trigger_grading_integration" {
  api_id           = aws_apigatewayv2_api.grading_api.id
  integration_type = "AWS_PROXY"
  integration_uri  = aws_lambda_function.trigger_grading.invoke_arn
  payload_format_version = "2.0"
}

resource "aws_apigatewayv2_route" "submit_route" {
  api_id    = aws_apigatewayv2_api.grading_api.id
  route_key = "POST /submit"
  target    = "integrations/${aws_apigatewayv2_integration.trigger_grading_integration.id}"
}

resource "aws_lambda_permission" "allow_apigateway_trigger" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_grading.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.grading_api.execution_arn}/*/*"
}

# CloudWatch Dashboard for monitoring
resource "aws_cloudwatch_dashboard" "grading_dashboard" {
  dashboard_name = "${var.course_name}-autograder-dashboard"

  dashboard_body = jsonencode({
    widgets = [
      {
        type = "metric"
        properties = {
          metrics = [
            ["AWS/CodeBuild", "Builds", { stat = "Sum" }],
            [".", "SuccessfulBuilds", { stat = "Sum" }],
            [".", "FailedBuilds", { stat = "Sum" }]
          ]
          period = 300
          stat   = "Sum"
          region = var.aws_region
          title  = "CodeBuild Metrics"
        }
      },
      {
        type = "metric"
        properties = {
          metrics = [
            ["AWS/Lambda", "Invocations", { stat = "Sum" }],
            [".", "Errors", { stat = "Sum" }],
            [".", "Duration", { stat = "Average" }]
          ]
          period = 300
          stat   = "Sum"
          region = var.aws_region
          title  = "Lambda Metrics"
        }
      }
    ]
  })
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "grading_results_bucket" {
  description = "S3 bucket for grading results"
  value       = aws_s3_bucket.grading_results.id
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}

output "api_endpoint" {
  description = "API Gateway endpoint for submissions"
  value       = aws_apigatewayv2_stage.grading_api_stage.invoke_url
}

output "submissions_table" {
  description = "DynamoDB table for submissions"
  value       = aws_dynamodb_table.submissions.name
}

output "sns_topic_arn" {
  description = "SNS topic for grading notifications"
  value       = aws_sns_topic.grading_notifications.arn
}
