```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region for resources"
  type        = string
  default     = "us-east-1"
}

variable "project_name" {
  description = "Project name prefix"
  type        = string
  default     = "cs-autograder"
}

# S3 bucket for grading outputs
resource "aws_s3_bucket" "grading_outputs" {
  bucket = "${var.project_name}-outputs-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "${var.project_name}-outputs"
    Environment = "production"
    Purpose     = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "grading_outputs_versioning" {
  bucket = aws_s3_bucket.grading_outputs.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_outputs_encryption" {
  bucket = aws_s3_bucket.grading_outputs.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "grading_outputs_block" {
  bucket = aws_s3_bucket.grading_outputs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket for CodeBuild cache
resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "${var.project_name}-cache-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "${var.project_name}-cache"
    Environment = "production"
    Purpose     = "codebuild-cache"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "codebuild_cache_lifecycle" {
  bucket = aws_s3_bucket.codebuild_cache.id

  rule {
    id     = "expire-cache"
    status = "Enabled"

    expiration {
      days = 7
    }
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.project_name}-codebuild-role"
  }
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.project_name}-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.grading_outputs.arn,
          "${aws_s3_bucket.grading_outputs.arn}/*",
          aws_s3_bucket.codebuild_cache.arn,
          "${aws_s3_bucket.codebuild_cache.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases",
          "codebuild:BatchPutCodeCoverages"
        ]
        Resource = [
          "arn:aws:codebuild:${var.aws_region}:${data.aws_caller_identity.current.account_id}:report-group/${var.project_name}-*"
        ]
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.project_name}-autograder"
  retention_in_days = 30

  tags = {
    Name = "${var.project_name}-codebuild-logs"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "${var.project_name}-autograder"
  description   = "Autograding system for CS course student submissions"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "GRADING_OUTPUTS_BUCKET"
      value = aws_s3_bucket.grading_outputs.bucket
    }

    environment_variable {
      name  = "AWS_DEFAULT_REGION"
      value = var.aws_region
    }

    environment_variable {
      name  = "TIMEOUT_SECONDS"
      value = "300"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-logs"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-BUILDSPEC
      version: 0.2

      phases:
        pre_build:
          commands:
            - echo "Starting autograder at $(date)"
            - export SUBMISSION_ID=$(echo $CODEBUILD_RESOLVED_SOURCE_VERSION | cut -c1-7)
            - export STUDENT_ID=$(echo $CODEBUILD_WEBHOOK_TRIGGER | cut -d'/' -f2)
            - echo "Processing submission $SUBMISSION_ID for student $STUDENT_ID"

        build:
          commands:
            - echo "Running autograder tests..."
            - mkdir -p /tmp/grading-results
            - |
              # Example grading commands - customize based on your needs
              # Run unit tests, linters, or other grading scripts
              if [ -f "test.sh" ]; then
                bash test.sh > /tmp/grading-results/test_output.txt 2>&1 || true
              fi

              # Generate grading report
              echo "Grading completed at $(date)" > /tmp/grading-results/report.txt
              echo "Submission: $SUBMISSION_ID" >> /tmp/grading-results/report.txt

        post_build:
          commands:
            - echo "Uploading grading results to S3..."
            - TIMESTAMP=$(date +%Y%m%d-%H%M%S)
            - RESULT_KEY="results/${STUDENT_ID:-unknown}/${SUBMISSION_ID}-${TIMESTAMP}"
            - aws s3 cp /tmp/grading-results/ s3://${GRADING_OUTPUTS_BUCKET}/${RESULT_KEY}/ --recursive
            - echo "Results uploaded to s3://${GRADING_OUTPUTS_BUCKET}/${RESULT_KEY}/"
            - echo "Autograding completed successfully"

      artifacts:
        files:
          - '**/*'
        base-directory: /tmp/grading-results
        name: grading-results-$SUBMISSION_ID
    BUILDSPEC
  }

  source_version = "main"

  tags = {
    Name        = "${var.project_name}-autograder"
    Environment = "production"
  }
}

# SNS topic for build notifications (optional)
resource "aws_sns_topic" "build_notifications" {
  name = "${var.project_name}-build-notifications"

  tags = {
    Name = "${var.project_name}-notifications"
  }
}

# CloudWatch Event Rule to trigger notifications
resource "aws_cloudwatch_event_rule" "codebuild_state_change" {
  name        = "${var.project_name}-build-state-change"
  description = "Capture CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
      build-status = ["FAILED", "SUCCEEDED", "STOPPED"]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.codebuild_state_change.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.build_notifications.arn
}

resource "aws_sns_topic_policy" "build_notifications_policy" {
  arn = aws_sns_topic.build_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.build_notifications.arn
      }
    ]
  })
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "grading_outputs_bucket_name" {
  description = "Name of the S3 bucket storing grading outputs"
  value       = aws_s3_bucket.grading_outputs.id
}

output "grading_outputs_bucket_arn" {
  description = "ARN of the S3 bucket storing grading outputs"
  value       = aws_s3_bucket.grading_outputs.arn
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "codebuild_project_arn" {
  description = "ARN of the CodeBuild project"
  value       = aws_codebuild_project.autograder.arn
}

output "sns_topic_arn" {
  description = "ARN of the SNS topic for build notifications"
  value       = aws_sns_topic.build_notifications.arn
}

output "cloudwatch_log_group_name" {
  description = "Name of the CloudWatch log group"
  value       = aws_cloudwatch_log_group.codebuild_logs.name
}
```

