terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "course_name" {
  description = "Name of the course"
  type        = string
  default     = "cs101"
}

variable "github_token_secret_arn" {
  description = "ARN of the Secrets Manager secret containing GitHub token"
  type        = string
}

# VPC for isolated execution environment
resource "aws_vpc" "autograding_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostings  = true
  enable_dns_support   = true

  tags = {
    Name = "${var.course_name}-autograding-vpc"
  }
}

# Private subnets for CodeBuild (no internet access)
resource "aws_subnet" "private_subnet_a" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.aws_region}a"

  tags = {
    Name = "${var.course_name}-private-subnet-a"
  }
}

resource "aws_subnet" "private_subnet_b" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.aws_region}b"

  tags = {
    Name = "${var.course_name}-private-subnet-b"
  }
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "${var.course_name}-codebuild-sg"
  description = "Security group for autograding CodeBuild - no internet access"
  vpc_id      = aws_vpc.autograding_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Allow traffic only within VPC"
  }

  tags = {
    Name = "${var.course_name}-codebuild-sg"
  }
}

# VPC Endpoints for AWS services (CodeBuild needs these without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograding_vpc.id
  service_name      = "com.amazonaws.${var.aws_region}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private_rt.id]

  tags = {
    Name = "${var.course_name}-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograding_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.course_name}-logs-endpoint"
  }
}

resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograding_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.course_name}-codebuild-endpoint"
  }
}

resource "aws_vpc_endpoint" "secretsmanager" {
  vpc_id              = aws_vpc.autograding_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.secretsmanager"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.course_name}-secretsmanager-endpoint"
  }
}

# Security group for VPC endpoints
resource "aws_security_group" "vpc_endpoints_sg" {
  name        = "${var.course_name}-vpc-endpoints-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograding_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Allow HTTPS from VPC"
  }

  tags = {
    Name = "${var.course_name}-vpc-endpoints-sg"
  }
}

# Route table for private subnets
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograding_vpc.id

  tags = {
    Name = "${var.course_name}-private-rt"
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_subnet_a.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_subnet_b.id
  route_table_id = aws_route_table.private_rt.id
}

# S3 bucket for storing grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "${var.course_name}-grading-results-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.course_name}-grading-results"
  }
}

resource "aws_s3_bucket_versioning" "grading_results_versioning" {
  bucket = aws_s3_bucket.grading_results.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_results_encryption" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "${var.course_name}-codebuild-artifacts-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.course_name}-codebuild-artifacts"
  }
}

resource "aws_s3_bucket_versioning" "codebuild_artifacts_versioning" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "codebuild_artifacts_encryption" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# DynamoDB table for storing grading records
resource "aws_dynamodb_table" "grading_records" {
  name           = "${var.course_name}-grading-records"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "student_id"
  range_key      = "submission_timestamp"

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "submission_timestamp"
    type = "N"
  }

  attribute {
    name = "assignment_id"
    type = "S"
  }

  global_secondary_index {
    name            = "AssignmentIndex"
    hash_key        = "assignment_id"
    range_key       = "submission_timestamp"
    projection_type = "ALL"
  }

  tags = {
    Name = "${var.course_name}-grading-records"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.course_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.course_name}-codebuild-role"
  }
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.course_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.course_name}-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.codebuild_artifacts.arn}/*",
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.codebuild_artifacts.arn,
          aws_s3_bucket.grading_results.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem"
        ]
        Resource = aws_dynamodb_table.grading_records.arn
      },
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = var.github_token_secret_arn
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.course_name}-autograding"
  retention_in_days = 30

  tags = {
    Name = "${var.course_name}-codebuild-logs"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding" {
  name          = "${var.course_name}-autograding"
  description   = "Autograding system for ${var.course_name}"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "GRADING_RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.grading_records.name
    }

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token_secret_arn
      type  = "SECRETS_MANAGER"
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      status      = "ENABLED"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo "Installing dependencies..."
            - pip install -r requirements.txt || true
        pre_build:
          commands:
            - echo "Preparing test environment..."
            - export STUDENT_ID=$STUDENT_ID
            - export ASSIGNMENT_ID=$ASSIGNMENT_ID
            - export SUBMISSION_TIMESTAMP=$(date +%s)
        build:
          commands:
            - echo "Running autograding tests..."
            - python autograder.py > results.json || true
        post_build:
          commands:
            - echo "Recording results..."
            - |
              aws s3 cp results.json s3://$GRADING_RESULTS_BUCKET/$STUDENT_ID/$ASSIGNMENT_ID/$SUBMISSION_TIMESTAMP/results.json
            - |
              SCORE=$(cat results.json | jq -r '.score')
              TOTAL=$(cat results.json | jq -r '.total')
              aws dynamodb put-item \n                --table-name $DYNAMODB_TABLE \n                --item "{"student_id": {"S": "$STUDENT_ID"}, "submission_timestamp": {"N": "$SUBMISSION_TIMESTAMP"}, "assignment_id": {"S": "$ASSIGNMENT_ID"}, "score": {"N": "$SCORE"}, "total": {"N": "$TOTAL"}, "status": {"S": "COMPLETED"}}"
            - echo "Grading complete - Score $SCORE out of $TOTAL"
      artifacts:
        files:
          - results.json
    EOT
  }

  tags = {
    Name = "${var.course_name}-autograding"
  }
}

# Lambda function to trigger CodeBuild
resource "aws_iam_role" "lambda_trigger_role" {
  name = "${var.course_name}-lambda-trigger-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.course_name}-lambda-trigger-role"
  }
}

resource "aws_iam_role_policy" "lambda_trigger_policy" {
  name = "${var.course_name}-lambda-trigger-policy"
  role = aws_iam_role.lambda_trigger_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograding.arn
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem"
        ]
        Resource = aws_dynamodb_table.grading_records.arn
      }
    ]
  })
}

resource "aws_lambda_function" "trigger_autograding" {
  filename         = "lambda_trigger.zip"
  function_name    = "${var.course_name}-trigger-autograding"
  role            = aws_iam_role.lambda_trigger_role.arn
  handler         = "index.handler"
  source_code_hash = fileexists("lambda_trigger.zip") ? filebase64sha256("lambda_trigger.zip") : null
  runtime         = "python3.11"
  timeout         = 30

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding.name
      DYNAMODB_TABLE    = aws_dynamodb_table.grading_records.name
    }
  }

  tags = {
    Name = "${var.course_name}-trigger-autograding"
  }
}

# API Gateway for triggering submissions
resource "aws_apigatewayv2_api" "autograding_api" {
  name          = "${var.course_name}-autograding-api"
  protocol_type = "HTTP"

  tags = {
    Name = "${var.course_name}-autograding-api"
  }
}

resource "aws_apigatewayv2_integration" "lambda_integration" {
  api_id           = aws_apigatewayv2_api.autograding_api.id
  integration_type = "AWS_PROXY"
  integration_uri  = aws_lambda_function.trigger_autograding.invoke_arn
}

resource "aws_apigatewayv2_route" "submit_route" {
  api_id    = aws_apigatewayv2_api.autograding_api.id
  route_key = "POST /submit"
  target    = "integrations/${aws_apigatewayv2_integration.lambda_integration.id}"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.autograding_api.id
  name        = "$default"
  auto_deploy = true

  tags = {
    Name = "${var.course_name}-default-stage"
  }
}

resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_autograding.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.autograding_api.execution_arn}/*/*"
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "api_endpoint" {
  description = "API Gateway endpoint for submitting assignments"
  value       = aws_apigatewayv2_api.autograding_api.api_endpoint
}

output "grading_results_bucket" {
  description = "S3 bucket for grading results"
  value       = aws_s3_bucket.grading_results.bucket
}

output "grading_records_table" {
  description = "DynamoDB table for grading records"
  value       = aws_dynamodb_table.grading_records.name
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograding.name
}

output "vpc_id" {
  description = "VPC ID for the autograding system"
  value       = aws_vpc.autograding_vpc.id
}

