response:
```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "course_name" {
  description = "Name of the computer science course"
  type        = string
  default     = "cs101"
}

# S3 Bucket for storing grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "${var.course_name}-grading-results-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "${var.course_name}-codebuild-artifacts-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# VPC for isolated CodeBuild execution
resource "aws_vpc" "autograding_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${var.course_name}-autograding-vpc"
  }
}

# Private subnets for CodeBuild (no internet access)
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "${var.course_name}-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "${var.course_name}-private-subnet-2"
  }
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "${var.course_name}-codebuild-sg"
  description = "Security group for CodeBuild autograding - no internet access"
  vpc_id      = aws_vpc.autograding_vpc.id

  # Allow outbound to VPC endpoints only
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograding_vpc.cidr_block]
    description = "Allow HTTPS to VPC endpoints"
  }

  tags = {
    Name = "${var.course_name}-codebuild-sg"
  }
}

# VPC Endpoints for AWS services (to allow CodeBuild to access AWS services without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograding_vpc.id
  service_name      = "com.amazonaws.${var.aws_region}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private.id]

  tags = {
    Name = "${var.course_name}-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograding_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.course_name}-logs-endpoint"
  }
}

resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograding_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.course_name}-codebuild-endpoint"
  }
}

# Security group for VPC endpoints
resource "aws_security_group" "vpc_endpoints_sg" {
  name        = "${var.course_name}-vpc-endpoints-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograding_vpc.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.codebuild_sg.id]
    description     = "Allow HTTPS from CodeBuild"
  }

  tags = {
    Name = "${var.course_name}-vpc-endpoints-sg"
  }
}

# Route table for private subnets (no internet gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograding_vpc.id

  tags = {
    Name = "${var.course_name}-private-rt"
  }
}

resource "aws_route_table_association" "private_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private.id
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.course_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.course_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.course_name}-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.grading_results.arn}/*",
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          aws_s3_bucket.codebuild_artifacts.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.course_name}-autograding"
  retention_in_days = 30
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding" {
  name          = "${var.course_name}-autograding"
  description   = "Autograding system for ${var.course_name}"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "GRADING_RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }

    environment_variable {
      name  = "COURSE_NAME"
      value = var.course_name
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-logs"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/placeholder/student-submissions.git"
    git_clone_depth = 1
    buildspec       = file("${path.module}/buildspec.yml")
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "${var.course_name}-autograding"
  }
}

# DynamoDB table for tracking submissions and results
resource "aws_dynamodb_table" "submissions" {
  name           = "${var.course_name}-submissions"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "submission_id"
  range_key      = "timestamp"

  attribute {
    name = "submission_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "N"
  }

  attribute {
    name = "student_id"
    type = "S"
  }

  global_secondary_index {
    name            = "StudentIndex"
    hash_key        = "student_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  tags = {
    Name = "${var.course_name}-submissions"
  }
}

# Lambda function to trigger CodeBuild and record results
resource "aws_iam_role" "lambda_role" {
  name = "${var.course_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "${var.course_name}-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild",
          "codebuild:BatchGetBuilds"
        ]
        Resource = aws_codebuild_project.autograding.arn
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem",
          "dynamodb:Query"
        ]
        Resource = [
          aws_dynamodb_table.submissions.arn,
          "${aws_dynamodb_table.submissions.arn}/index/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.grading_results.arn}/*"
      }
    ]
  })
}

resource "aws_lambda_function" "trigger_autograding" {
  filename      = "lambda_function.zip"
  function_name = "${var.course_name}-trigger-autograding"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 300

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding.name
      DYNAMODB_TABLE    = aws_dynamodb_table.submissions.name
      RESULTS_BUCKET    = aws_s3_bucket.grading_results.bucket
    }
  }
}

# Lambda function to process grading results
resource "aws_lambda_function" "process_results" {
  filename      = "results_processor.zip"
  function_name = "${var.course_name}-process-results"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  environment {
    variables = {
      DYNAMODB_TABLE = aws_dynamodb_table.submissions.name
      RESULTS_BUCKET = aws_s3_bucket.grading_results.bucket
    }
  }
}

# EventBridge rule to trigger result processing when CodeBuild completes
resource "aws_cloudwatch_event_rule" "codebuild_complete" {
  name        = "${var.course_name}-codebuild-complete"
  description = "Trigger when CodeBuild autograding completes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      build-status = ["SUCCEEDED", "FAILED", "STOPPED"]
      project-name = [aws_codebuild_project.autograding.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "process_results" {
  rule      = aws_cloudwatch_event_rule.codebuild_complete.name
  target_id = "ProcessResults"
  arn       = aws_lambda_function.process_results.arn
}

resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.process_results.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.codebuild_complete.arn
}

# SNS topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "${var.course_name}-grading-notifications"
}

resource "aws_sns_topic_subscription" "grading_email" {
  topic_arn = aws_sns_topic.grading_notifications.arn
  protocol  = "email"
  endpoint  = "instructor@example.com"
}

# IAM policy to allow Lambda to publish to SNS
