resource "aws_dynamodb_table" "grading_jobs" {
  name           = "${var.project_name}-grading-jobs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "JobId"
  range_key      = "SubmissionTimestamp"

  attribute {
    name = "JobId"
    type = "S"
  }

  attribute {
