}

resource "aws_lambda_permission" "allow_s3" {
  statement_id  = "AllowExecutionFromS3"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.submission_processor.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.submissions.arn
}

# Lambda deployment package placeholder
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os
      from datetime import datetime

      codebuild = boto3.client('codebuild')
      dynamodb = boto3.resource('dynamodb')
      sns = boto3.client('sns')

      def handler(event, context):
          table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])

          for record in event['Records']:
              bucket = record['s3']['bucket']['name']
              key = record['s3']['object']['key']

              # Extract student info from key
              job_id = f"{datetime.now().strftime('%Y%m%d-%H%M%S')}-{key.split('/')[-1]}"

              # Start CodeBuild
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT'],
                  environmentVariablesOverride=[
                      {'name': 'SUBMISSION_KEY', 'value': key},
                      {'name': 'SUBMISSION_BUCKET', 'value': bucket},
                      {'name': 'JOB_ID', 'value': job_id}
                  ]
              )

              # Record in DynamoDB
              table.put_item(
                  Item={
                      'JobId': job_id,
                      'SubmissionTimestamp': int(datetime.now().timestamp()),
                      'StudentId': key.split('/')[1] if len(key.split('/')) > 1 else 'unknown',
                      'Status': 'STARTED',
                      'BuildId': response['build']['id'],
                      'S3Key': key
                  }
              )

          return {'statusCode': 200, 'body': json.dumps('Processing initiated')}
    EOF
    filename = "index.py"
  }
}

