  value       = aws_vpc.autograder_vpc.id
}

output "security_group_id" {
  description = "Security group ID blocking internet access"
  value       = aws_security_group.autograder_sg.id
}

output "dynamodb_table_name" {
  description = "DynamoDB table for grading jobs"
  value       = aws_dynamodb_table.grading_jobs.name
}

output "sns_topic_arn" {
  description = "SNS topic for notifications"
  value       = aws_sns_topic.grading_notifications.arn
}

