resource "aws_subnet" "autograder_private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "${var.project_name}-private-subnet"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security group that blocks all outbound internet access
resource "aws_security_group" "autograder_sg" {
  name        = "${var.project_name}-sg"
  description = "Security group for autograder - blocks all outbound internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow outbound to VPC endpoints only
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "HTTPS to VPC endpoints only"
  }

  tags = {
    Name = "${var.project_name}-sg"
  }
}

# VPC Endpoints for AWS services (no internet gateway needed)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.${var.aws_region}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private_rt.id]

  tags = {
    Name = "${var.project_name}-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-codebuild-endpoint"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-logs-endpoint"
  }
}

resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "${var.project_name}-vpc-endpoint-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "HTTPS from VPC"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound"
  }

  tags = {
    Name = "${var.project_name}-vpc-endpoint-sg"
  }
}

# Route table for private subnet (no internet gateway route)
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "${var.project_name}-private-rt"
  }
}

resource "aws_route_table_association" "private_rta" {
  subnet_id      = aws_subnet.autograder_private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# S3 bucket for student submissions
resource "aws_s3_bucket" "submissions" {
  bucket = "${var.project_name}-submissions-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.project_name}-submissions"
  }
}

resource "aws_s3_bucket_versioning" "submissions" {
  bucket = aws_s3_bucket.submissions.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "submissions" {
  bucket = aws_s3_bucket.submissions.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket for grading results/outputs
resource "aws_s3_bucket" "results" {
  bucket = "${var.project_name}-results-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.project_name}-results"
  }
}

resource "aws_s3_bucket_versioning" "results" {
  bucket = aws_s3_bucket.results.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "results" {
  bucket = aws_s3_bucket.results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket for CodeBuild artifacts/cache
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "${var.project_name}-artifacts-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.project_name}-artifacts"
  }
}

resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.project_name}-codebuild-role"
  }
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.project_name}*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.submissions.arn,
          "${aws_s3_bucket.submissions.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Resource = [
          aws_s3_bucket.results.arn,
          "${aws_s3_bucket.results.arn}/*",
          aws_s3_bucket.codebuild_artifacts.arn,
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.project_name}"
  retention_in_days = 30

  tags = {
    Name = "${var.project_name}-codebuild-logs"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "${var.project_name}-project"
  description   = "Autograding system for CS course submissions"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.results.bucket
    packaging = "ZIP"
    name      = "grading-results"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results.bucket
    }

    environment_variable {
      name  = "SUBMISSIONS_BUCKET"
      value = aws_s3_bucket.submissions.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-logs"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOF
      version: 0.2
      phases:
        install:
          commands:
            - echo "Installing dependencies..."
        pre_build:
          commands:
            - echo "Preparing autograder environment..."
            - echo "Student code execution environment is isolated with no internet access"
        build:
          commands:
            - echo "Running autograder tests..."
            - echo "Executing student submission..."
            - |
              # Example grading logic
              TIMESTAMP=$(date +%Y%m%d-%H%M%S)
              echo "Grading started at $TIMESTAMP" > grading-report.txt
              echo "Running test cases..." >> grading-report.txt
              # Add actual test execution here
        post_build:
          commands:
            - echo "Uploading grading results..."
            - aws s3 cp grading-report.txt s3://${aws_s3_bucket.results.bucket}/results/$CODEBUILD_BUILD_ID/
      artifacts:
        files:
          - '**/*'
        name: grading-results
    EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "${var.project_name}-codebuild"
  }
}

data "aws_caller_identity" "current" {}

# DynamoDB table for tracking grading jobs and metadata
resource "aws_dynamodb_table" "grading_jobs" {
  name           = "${var.project_name}-grading-jobs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "JobId"
  range_key      = "SubmissionTimestamp"

  attribute {
    name = "JobId"
    type = "S"
  }

  attribute {
    name = "SubmissionTimestamp"
    type = "N"
  }

  attribute {
    name = "StudentId"
    type = "S"
  }

  global_secondary_index {
    name            = "StudentIdIndex"
    hash_key        = "StudentId"
    range_key       = "SubmissionTimestamp"
    projection_type = "ALL"
  }

  tags = {
    Name = "${var.project_name}-grading-jobs"
  }
}

# SNS topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "${var.project_name}-notifications"

  tags = {
    Name = "${var.project_name}-notifications"
  }
}

# Lambda execution role for processing submissions
resource "aws_iam_role" "lambda_role" {
  name = "${var.project_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.project_name}-lambda-role"
  }
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "${var.project_name}-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.submissions.arn}/*",
          "${aws_s3_bucket.results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild",
          "codebuild:BatchGetBuilds"
        ]
        Resource = aws_codebuild_project.autograder.arn
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem",
          "dynamodb:Query"
        ]
        Resource = [
          aws_dynamodb_table.grading_jobs.arn,
          "${aws_dynamodb_table.grading_jobs.arn}/index/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.grading_notifications.arn
      }
    ]
  })
}

# Lambda function to trigger CodeBuild on S3 upload
resource "aws_lambda_function" "submission_processor" {
  filename      = "lambda_function.zip"
  function_name = "${var.project_name}-submission-processor"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      DYNAMODB_TABLE    = aws_dynamodb_table.grading_jobs.name
      SNS_TOPIC_ARN     = aws_sns_topic.grading_notifications.arn
      RESULTS_BUCKET    = aws_s3_bucket.results.bucket
    }
  }

  tags = {
    Name = "${var.project_name}-submission-processor"
  }
}

# S3 bucket notification to trigger Lambda
resource "aws_s3_bucket_notification" "submission_notification" {
  bucket = aws_s3_bucket.submissions.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.submission_processor.arn
    events              = ["s3:ObjectCreated:*"]
    filter_prefix       = "submissions/"
  }

  depends_on = [aws_lambda_permission.allow_s3]
}

resource "aws_lambda_permission" "allow_s3" {
  statement_id  = "AllowExecutionFromS3"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.submission_processor.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.submissions.arn
}

# Lambda deployment package placeholder
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os
      from datetime import datetime

      codebuild = boto3.client('codebuild')
      dynamodb = boto3.resource('dynamodb')
      sns = boto3.client('sns')

      def handler(event, context):
          table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])

          for record in event['Records']:
              bucket = record['s3']['bucket']['name']
              key = record['s3']['object']['key']

              # Extract student info from key
              job_id = f"{datetime.now().strftime('%Y%m%d-%H%M%S')}-{key.split('/')[-1]}"

              # Start CodeBuild
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT'],
                  environmentVariablesOverride=[
                      {'name': 'SUBMISSION_KEY', 'value': key},
                      {'name': 'SUBMISSION_BUCKET', 'value': bucket},
                      {'name': 'JOB_ID', 'value': job_id}
                  ]
              )

              # Record in DynamoDB
              table.put_item(
                  Item={
                      'JobId': job_id,
                      'SubmissionTimestamp': int(datetime.now().timestamp()),
                      'StudentId': key.split('/')[1] if len(key.split('/')) > 1 else 'unknown',
                      'Status': 'STARTED',
                      'BuildId': response['build']['id'],
                      'S3Key': key
                  }
              )

          return {'statusCode': 200, 'body': json.dumps('Processing initiated')}
    EOF
    filename = "index.py"
  }
}

# Outputs
output "submissions_bucket_name" {
  description = "S3 bucket for student submissions"
  value       = aws_s3_bucket.submissions.bucket
}

output "results_bucket_name" {
  description = "S3 bucket for grading results"
  value       = aws_s3_bucket.results.bucket
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "VPC ID for autograder"
  value       = aws_vpc.autograder_vpc.id
}

output "security_group_id" {
  description = "Security group ID blocking internet access"
  value       = aws_security_group.autograder_sg.id
}

output "dynamodb_table_name" {
  description = "DynamoDB table for grading jobs"
  value       = aws_dynamodb_table.grading_jobs.name
}

output "sns_topic_arn" {
  description = "SNS topic for notifications"
  value       = aws_sns_topic.grading_notifications.arn
}
```

