terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "project_name" {
  description = "Project name for resource naming"
  type        = string
  default     = "cat-images-app"
}

# S3 bucket for storing cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "${var.project_name}-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_cors_configuration" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "PUT", "POST"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

# IAM role for Lambda functions
resource "aws_iam_role" "lambda_role" {
  name = "${var.project_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_s3_policy" {
  name = "${var.project_name}-lambda-s3-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lambda function for uploading cat images
resource "aws_lambda_function" "upload_cat_image" {
  filename         = "upload_lambda.zip"
  function_name    = "${var.project_name}-upload"
  role            = aws_iam_role.lambda_role.arn
  handler         = "index.handler"
  source_code_hash = fileexists("upload_lambda.zip") ? filebase64sha256("upload_lambda.zip") : null
  runtime         = "python3.11"
  timeout         = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# Lambda function for getting random cat image
resource "aws_lambda_function" "get_random_cat" {
  filename         = "get_random_lambda.zip"
  function_name    = "${var.project_name}-get-random"
  role            = aws_iam_role.lambda_role.arn
  handler         = "index.handler"
  source_code_hash = fileexists("get_random_lambda.zip") ? filebase64sha256("get_random_lambda.zip") : null
  runtime         = "python3.11"
  timeout         = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# CloudWatch Log Groups
resource "aws_cloudwatch_log_group" "upload_lambda_logs" {
  name              = "/aws/lambda/${aws_lambda_function.upload_cat_image.function_name}"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_group" "get_random_lambda_logs" {
  name              = "/aws/lambda/${aws_lambda_function.get_random_cat.function_name}"
  retention_in_days = 7
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "${var.project_name}-api"
  description = "API for cat images upload and retrieval"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

# API Gateway Resource - /upload
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# API Gateway Method - POST /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "upload_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload.id
  http_method = aws_api_gateway_method.upload_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.upload_cat_image.invoke_arn
}

# API Gateway Resource - /random
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# API Gateway Method - GET /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "random_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.get_random_cat.invoke_arn
}

# Lambda permissions for API Gateway
resource "aws_lambda_permission" "apigw_upload" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat_image.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "apigw_random" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# API Gateway Deployment
resource "aws_api_gateway_deployment" "cat_api" {
  depends_on = [
    aws_api_gateway_integration.upload_lambda,
    aws_api_gateway_integration.random_lambda
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_method.upload_post.id,
      aws_api_gateway_integration.upload_lambda.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.random_lambda.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

# API Gateway Stage
resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "api_endpoint" {
  description = "API Gateway endpoint URL"
  value       = aws_api_gateway_stage.prod.invoke_url
}

output "upload_endpoint" {
  description = "Upload endpoint URL"
  value       = "${aws_api_gateway_stage.prod.invoke_url}/upload"
}

output "random_endpoint" {
  description = "Random cat image endpoint URL"
  value       = "${aws_api_gateway_stage.prod.invoke_url}/random"
}

output "s3_bucket_name" {
  description = "S3 bucket name for cat images"
  value       = aws_s3_bucket.cat_images.id
}

