data "archive_file" "get_random_lambda" {
  type        = "zip"
  output_path = "get_random_lambda.zip"

  source {
    content  = <<EOF
import json
import boto3
import base64
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

def handler(event, context):
    try:
        bucket_name = os.environ['BUCKET_NAME']
        table_name = os.environ['DYNAMODB_TABLE']
        table = dynamodb.Table(table_name)

        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': 'No cat images found'})
            }

        random_item = random.choice(items)
        s3_key = random_item['s3_key']

        s3_object = s3.get_object(Bucket=bucket_name, Key=s3_key)
        image_data = s3_object['Body'].read()
        encoded_image = base64.b64encode(image_data).decode('utf-8')

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({
                'image_id': random_item['image_id'],
                'filename': random_item['filename'],
                'content_type': random_item['content_type'],
                'upload_timestamp': random_item['upload_timestamp'],
                'image': encoded_image
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "index.py"
  }
}

