      DYNAMODB_TABLE = aws_dynamodb_table.cat_images_metadata.name
    }
  }
}

resource "aws_cloudwatch_log_group" "get_random_lambda" {
  name              = "/aws/lambda/${aws_lambda_function.get_random_cat_image.function_name}"
  retention_in_days = 7
}

# Archive Lambda function code - Upload
data "archive_file" "upload_lambda" {
  type        = "zip"
  output_path = "upload_lambda.zip"

  source {
    content  = <<EOF
import json
import boto3
import base64
import uuid
import time
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

def handler(event, context):
    try:
        bucket_name = os.environ['BUCKET_NAME']
        table_name = os.environ['DYNAMODB_TABLE']
        table = dynamodb.Table(table_name)

        body = json.loads(event.get('body', '{}'))

        if 'image' not in body:
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': 'No image data provided'})
            }

        image_data = base64.b64decode(body['image'])
        image_id = str(uuid.uuid4())
        content_type = body.get('content_type', 'image/jpeg')
        filename = body.get('filename', f'{image_id}.jpg')

        s3_key = f'cats/{image_id}/{filename}'

        s3.put_object(
            Bucket=bucket_name,
            Key=s3_key,
            Body=image_data,
            ContentType=content_type
        )

        timestamp = int(time.time())
        table.put_item(
            Item={
                'image_id': image_id,
                'upload_timestamp': timestamp,
                's3_key': s3_key,
                'filename': filename,
                'content_type': content_type
            }
        )

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({
                'message': 'Image uploaded successfully',
                'image_id': image_id,
                'timestamp': timestamp
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "index.py"
  }
}

# Archive Lambda function code - Get Random
data "archive_file" "get_random_lambda" {
  type        = "zip"
  output_path = "get_random_lambda.zip"

  source {
    content  = <<EOF
import json
import boto3
import base64
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

def handler(event, context):
    try:
        bucket_name = os.environ['BUCKET_NAME']
        table_name = os.environ['DYNAMODB_TABLE']
        table = dynamodb.Table(table_name)

        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': 'No cat images found'})
            }

        random_item = random.choice(items)
        s3_key = random_item['s3_key']

        s3_object = s3.get_object(Bucket=bucket_name, Key=s3_key)
        image_data = s3_object['Body'].read()
        encoded_image = base64.b64encode(image_data).decode('utf-8')

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({
                'image_id': random_item['image_id'],
                'filename': random_item['filename'],
                'content_type': random_item['content_type'],
                'upload_timestamp': random_item['upload_timestamp'],
                'image': encoded_image
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "index.py"
  }
}

