# Lambda function code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
import json
import boto3
import base64
import uuid
import random
from datetime import datetime

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('cat-images-metadata')
BUCKET_NAME = '${aws_s3_bucket.cat_images.id}'

def lambda_handler(event, context):
    http_method = event.get('httpMethod', '')
    path = event.get('path', '')

    if http_method == 'POST' and path == '/upload':
        return upload_cat_image(event)
    elif http_method == 'GET' and path == '/random':
        return get_random_cat_image(event)
    else:
        return {
            'statusCode': 400,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': 'Invalid request'})
        }

def upload_cat_image(event):
    try:
        body = json.loads(event.get('body', '{}'))
        image_data = body.get('imageData')
        filename = body.get('filename', 'cat.jpg')

        if not image_data:
            return {
                'statusCode': 400,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'error': 'No image data provided'})
            }

        image_id = str(uuid.uuid4())
        image_bytes = base64.b64decode(image_data)

        s3_key = f'cats/{image_id}/{filename}'
        s3.put_object(
            Bucket=BUCKET_NAME,
            Key=s3_key,
            Body=image_bytes,
            ContentType='image/jpeg'
        )

        table.put_item(
            Item={
                'imageId': image_id,
                's3Key': s3_key,
                'filename': filename,
                'uploadedAt': datetime.utcnow().isoformat()
            }
        )

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'message': 'Image uploaded successfully',
                'imageId': image_id
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }

def get_random_cat_image(event):
    try:
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'error': 'No cat images found'})
            }

        random_item = random.choice(items)
        s3_key = random_item['s3Key']

        s3_object = s3.get_object(Bucket=BUCKET_NAME, Key=s3_key)
        image_data = base64.b64encode(s3_object['Body'].read()).decode('utf-8')

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'imageId': random_item['imageId'],
                'filename': random_item['filename'],
                'imageData': image_data,
                'uploadedAt': random_item['uploadedAt']
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "lambda_function.py"
  }
}

