  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_execution_role" {
  name = "eventbridge_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda function
resource "aws_lambda_function" "scheduled_function" {
  filename      = "lambda_function.zip"
  function_name = "daily_scheduled_function"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  source_code_hash = filebase64sha256("lambda_function.zip")
}

# EventBridge rule to trigger daily at 07:00 UTC
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-07am-utc-schedule"
  description         = "Trigger Lambda function daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge target pointing to Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "TargetLambdaFunction"
  arn       = aws_lambda_function.scheduled_function.arn
}

# Permission for EventBridge to invoke Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule.arn
}

# Output the Lambda function name
output "lambda_function_name" {
  value       = aws_lambda_function.scheduled_function.function_name
  description = "Name of the scheduled Lambda function"
}

# Output the EventBridge rule name
output "eventbridge_rule_name" {
  value       = aws_cloudwatch_event_rule.daily_schedule.name
  description = "Name of the EventBridge rule"
}

