  region = "us-east-1"
}

# S3 bucket for video content storage
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-platform-content-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "Video Streaming Content"
    Environment = "Production"
  }
}

# Block public access to S3 bucket
resource "aws_s3_bucket_public_access_block" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable versioning for the S3 bucket
resource "aws_s3_bucket_versioning" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket policy for CloudFront OAC
resource "aws_s3_bucket_policy" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontServicePrincipal"
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_streaming.arn
          }
        }
      }
    ]
  })
}

# CloudFront Origin Access Control
resource "aws_cloudfront_origin_access_control" "video_streaming" {
  name                              = "video-streaming-oac"
  description                       = "Origin Access Control for Video Streaming Platform"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront cache policy for video streaming
resource "aws_cloudfront_cache_policy" "video_streaming" {
  name        = "video-streaming-cache-policy"
  comment     = "Cache policy optimized for video streaming"
  default_ttl = 86400
  max_ttl     = 31536000
  min_ttl     = 0

  parameters_in_cache_key_and_forwarded_to_origin {
    cookies_config {
      cookie_behavior = "none"
    }

    headers_config {
      header_behavior = "whitelist"
      headers {
        items = ["Origin", "Access-Control-Request-Method", "Access-Control-Request-Headers"]
      }
    }

    query_strings_config {
      query_string_behavior = "none"
    }

    enable_accept_encoding_gzip   = true
    enable_accept_encoding_brotli = true
  }
}

# CloudFront origin request policy
resource "aws_cloudfront_origin_request_policy" "video_streaming" {
  name    = "video-streaming-origin-request-policy"
  comment = "Origin request policy for video streaming"

  cookies_config {
    cookie_behavior = "none"
  }

  headers_config {
    header_behavior = "whitelist"
    headers {
      items = ["Origin", "Access-Control-Request-Method", "Access-Control-Request-Headers"]
    }
  }

  query_strings_config {
    query_string_behavior = "none"
  }
}

# CloudFront response headers policy for CORS
resource "aws_cloudfront_response_headers_policy" "video_streaming" {
  name    = "video-streaming-response-headers-policy"
  comment = "Response headers policy for video streaming with CORS"

  cors_config {
    access_control_allow_credentials = false

    access_control_allow_headers {
      items = ["*"]
    }

    access_control_allow_methods {
      items = ["GET", "HEAD", "OPTIONS"]
    }

    access_control_allow_origins {
      items = ["*"]
    }

    access_control_max_age_sec = 3600
    origin_override            = true
  }

  security_headers_config {
    strict_transport_security {
      access_control_max_age_sec = 31536000
      include_subdomains         = true
      preload                    = true
      override                   = true
    }

    content_type_options {
      override = true
    }

    frame_options {
      frame_option = "DENY"
      override     = true
    }

    xss_protection {
      mode_block = true
      protection = true
      override   = true
    }

    referrer_policy {
      referrer_policy = "strict-origin-when-cross-origin"
      override        = true
    }
  }
}

# CloudFront distribution
resource "aws_cloudfront_distribution" "video_streaming" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Video Streaming Platform Distribution"
  default_root_object = "index.html"
  price_class         = "PriceClass_All"
  aliases             = ["streaming.${aws_route53_zone.main.name}"]

  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id                = "S3-${aws_s3_bucket.video_content.id}"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_streaming.id
  }

  default_cache_behavior {
    allowed_methods            = ["GET", "HEAD", "OPTIONS"]
    cached_methods             = ["GET", "HEAD"]
    target_origin_id           = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy     = "redirect-to-https"
    compress                   = true
    cache_policy_id            = aws_cloudfront_cache_policy.video_streaming.id
    origin_request_policy_id   = aws_cloudfront_origin_request_policy.video_streaming.id
    response_headers_policy_id = aws_cloudfront_response_headers_policy.video_streaming.id
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.cloudfront.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.cloudfront_logs.bucket_domain_name
    prefix          = "cloudfront/"
  }

  tags = {
    Name        = "Video Streaming Distribution"
    Environment = "Production"
  }

  depends_on = [aws_acm_certificate_validation.cloudfront]
}

# S3 bucket for CloudFront logs
resource "aws_s3_bucket" "cloudfront_logs" {
  bucket = "video-streaming-cloudfront-logs-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "CloudFront Logs"
    Environment = "Production"
  }
}

# S3 bucket ownership controls for logs
resource "aws_s3_bucket_ownership_controls" "cloudfront_logs" {
  bucket = aws_s3_bucket.cloudfront_logs.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# S3 bucket ACL for CloudFront logs
resource "aws_s3_bucket_acl" "cloudfront_logs" {
  bucket = aws_s3_bucket.cloudfront_logs.id
  acl    = "private"

  depends_on = [aws_s3_bucket_ownership_controls.cloudfront_logs]
}

# Route 53 hosted zone
resource "aws_route53_zone" "main" {
  name = "videostreaming.example.com"

  tags = {
    Name        = "Video Streaming Platform"
    Environment = "Production"
  }
}

# Route 53 record for CloudFront distribution
resource "aws_route53_record" "cloudfront" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "streaming.${aws_route53_zone.main.name}"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_streaming.domain_name
    zone_id                = aws_cloudfront_distribution.video_streaming.hosted_zone_id
    evaluate_target_health = false
  }
}

# Route 53 record for CloudFront distribution (IPv6)
resource "aws_route53_record" "cloudfront_ipv6" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "streaming.${aws_route53_zone.main.name}"
  type    = "AAAA"

  alias {
    name                   = aws_cloudfront_distribution.video_streaming.domain_name
    zone_id                = aws_cloudfront_distribution.video_streaming.hosted_zone_id
    evaluate_target_health = false
  }
}

# ACM certificate for CloudFront (must be in us-east-1)
resource "aws_acm_certificate" "cloudfront" {
  domain_name       = "streaming.${aws_route53_zone.main.name}"
  validation_method = "DNS"

  subject_alternative_names = [
    "*.streaming.${aws_route53_zone.main.name}"
  ]

  lifecycle {
    create_before_destroy = true
  }

  tags = {
    Name        = "CloudFront Certificate"
    Environment = "Production"
  }
}

# Route 53 record for ACM certificate validation
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cloudfront.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.main.zone_id
}

# ACM certificate validation
resource "aws_acm_certificate_validation" "cloudfront" {
  certificate_arn         = aws_acm_certificate.cloudfront.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

# Data source for current AWS account ID
data "aws_caller_identity" "current" {}

# Outputs
output "cloudfront_distribution_id" {
  description = "ID of the CloudFront distribution"
  value       = aws_cloudfront_distribution.video_streaming.id
}

output "cloudfront_domain_name" {
  description = "Domain name of the CloudFront distribution"
  value       = aws_cloudfront_distribution.video_streaming.domain_name
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket for video content"
  value       = aws_s3_bucket.video_content.id
}

output "route53_zone_id" {
  description = "ID of the Route 53 hosted zone"
  value       = aws_route53_zone.main.zone_id
}

output "route53_name_servers" {
  description = "Name servers for the Route 53 hosted zone"
  value       = aws_route53_zone.main.name_servers
}

output "streaming_url" {
  description = "URL for the video streaming platform"
  value       = "https://streaming.${aws_route53_zone.main.name}"
}

output "cloudfront_oac_id" {
  description = "ID of the CloudFront Origin Access Control"
  value       = aws_cloudfront_origin_access_control.video_streaming.id
}

