# VPC Data Source
data "aws_vpc" "selected" {
  id = var.vpc_id
}

# Subnets for DB Subnet Group
data "aws_subnets" "database" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.selected.id]
  }

  tags = {
    Tier = "database"
  }
}

# KMS Key for RDS Encryption
resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgresql-kms-key"
  }
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-postgresql"
  target_key_id = aws_kms_key.rds.key_id
}

# DB Subnet Group
resource "aws_db_subnet_group" "postgresql" {
  name       = "postgresql-subnet-group"
  subnet_ids = data.aws_subnets.database.ids

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_postgresql" {
  name        = "rds-postgresql-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = data.aws_vpc.selected.id

  ingress {
    description = "PostgreSQL access from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.selected.cidr_block]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgresql-sg"
  }
}

# Custom PostgreSQL Parameter Group
resource "aws_db_parameter_group" "postgresql" {
  name   = "custom-postgresql-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  parameter {
    name  = "log_duration"
    value = "1"
  }

  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements"
  }

  tags = {
    Name = "custom-postgresql-parameter-group"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgresql" {
  identifier     = "postgresql-rds-instance"
  engine         = "postgres"
  engine_version = "15.4"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type          = "gp3"
  storage_encrypted     = true
  kms_key_id            = aws_kms_key.rds.arn

  db_name  = var.database_name
  username = var.database_username
  password = var.database_password

  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.postgresql.name
  vpc_security_group_ids = [aws_security_group.rds_postgresql.id]
  parameter_group_name   = aws_db_parameter_group.postgresql.name

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "mon:04:00-mon:05:00"

  skip_final_snapshot       = false
  final_snapshot_identifier = "postgresql-final-snapshot-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"
  deletion_protection       = true

  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]

  tags = {
    Name        = "PostgreSQL RDS Instance"
    Environment = "production"
  }
}

# Variables
variable "vpc_id" {
  description = "VPC ID where RDS will be deployed"
  type        = string
}

variable "database_name" {
  description = "Name of the PostgreSQL database"
  type        = string
  default     = "mydb"
}

variable "database_username" {
  description = "Master username for PostgreSQL"
  type        = string
  default     = "postgres"
}

variable "database_password" {
  description = "Master password for PostgreSQL"
  type        = string
  sensitive   = true
}

# Outputs
output "rds_endpoint" {
  description = "RDS instance endpoint"
  value       = aws_db_instance.postgresql.endpoint
}

output "rds_arn" {
  description = "RDS instance ARN"
  value       = aws_db_instance.postgresql.arn
}

output "security_group_id" {
  description = "Security group ID for RDS"
  value       = aws_security_group.rds_postgresql.id
}

output "kms_key_id" {
  description = "KMS key ID used for encryption"
  value       = aws_kms_key.rds.id
}
