terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region for resources"
  type        = string
  default     = "us-east-1"
}

variable "db_username" {
  description = "Master username for the database"
  type        = string
  default     = "postgres"
  sensitive   = true
}

variable "db_password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "vpc_id" {
  description = "VPC ID where RDS will be deployed"
  type        = string
}

variable "public_subnet_ids" {
  description = "List of public subnet IDs for RDS"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "CIDR blocks allowed to access the database"
  type        = list(string)
  default     = ["0.0.0.0/0"]
}

variable "db_name" {
  description = "Initial database name"
  type        = string
  default     = "airbyte_test"
}

variable "environment" {
  description = "Environment name"
  type        = string
  default     = "test"
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "airbyte-rds-postgres-"
  description = "Security group for Airbyte test RDS PostgreSQL"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "airbyte-rds-postgres-sg"
    Environment = var.environment
    Purpose     = "airbyte-connector-testing"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name_prefix = "airbyte-rds-subnet-"
  description = "Subnet group for Airbyte test RDS"
  subnet_ids  = var.public_subnet_ids

  tags = {
    Name        = "airbyte-rds-subnet-group"
    Environment = var.environment
    Purpose     = "airbyte-connector-testing"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# DB Parameter Group for PostgreSQL 15
resource "aws_db_parameter_group" "postgres15" {
  name_prefix = "airbyte-postgres15-"
  family      = "postgres15"
  description = "Parameter group for Airbyte test PostgreSQL 15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  tags = {
    Name        = "airbyte-postgres15-params"
    Environment = var.environment
    Purpose     = "airbyte-connector-testing"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier_prefix = "airbyte-test-postgres-"

  # Engine configuration
  engine               = "postgres"
  engine_version       = "15.5"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  max_allocated_storage = 100
  storage_type         = "gp3"
  storage_encrypted    = true

  # Database configuration
  db_name  = var.db_name
  username = var.db_username
  password = var.db_password
  port     = 5432

  # Network configuration
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true

  # Parameter and option groups
  parameter_group_name = aws_db_parameter_group.postgres15.name

  # Backup configuration
  backup_retention_period = 7
  backup_window          = "03:00-04:00"
  maintenance_window     = "mon:04:00-mon:05:00"

  # Monitoring and logging
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  monitoring_interval             = 60
  monitoring_role_arn            = aws_iam_role.rds_monitoring.arn

  # High availability and maintenance
  multi_az               = false
  auto_minor_version_upgrade = true
  apply_immediately      = true

  # Deletion protection
  deletion_protection = false
  skip_final_snapshot = true
  final_snapshot_identifier = null

  # Performance Insights
  performance_insights_enabled    = true
  performance_insights_retention_period = 7

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = var.environment
    Purpose     = "airbyte-connector-testing"
    Engine      = "PostgreSQL-15"
  }
}

# IAM Role for Enhanced Monitoring
resource "aws_iam_role" "rds_monitoring" {
  name_prefix = "airbyte-rds-monitoring-"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
