provider "aws" {
  region = "us-east-1"
}

# Generate SSH key pair
resource "tls_private_key" "lightsail_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create Lightsail SSH key pair
resource "aws_lightsail_key_pair" "main" {
  name       = "lightsail-ssh-key"
  public_key = tls_private_key.lightsail_key.public_key_openssh
}

# Create Lightsail instance
resource "aws_lightsail_instance" "main" {
  name              = "lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2023"
  bundle_id         = "nano_3_0"
  key_pair_name     = aws_lightsail_key_pair.main.name

  tags = {
    Environment = "Development"
    ManagedBy   = "Terraform"
  }
}

# Output the private key (save this securely)
output "private_key_pem" {
  value     = tls_private_key.lightsail_key.private_key_pem
  sensitive = true
}

# Output the instance details
output "instance_public_ip" {
  value = aws_lightsail_instance.main.public_ip_address
}

output "instance_username" {
  value = aws_lightsail_instance.main.username
}

output "ssh_connection_command" {
  value = "ssh -i lightsail-key.pem ${aws_lightsail_instance.main.username}@${aws_lightsail_instance.main.public_ip_address}"
}

