terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_lightsail_instance" "mysql_server" {
  name              = "mysql-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "ubuntu_20_04"
  bundle_id         = "micro_2_0"

  user_data = <<-EOF
              #!/bin/bash
              apt-get update
              apt-get install -y mysql-server

              # Configure MySQL to listen on all interfaces
              sed -i 's/bind-address.*/bind-address = 0.0.0.0/' /etc/mysql/mysql.conf.d/mysqld.cnf

              # Start and enable MySQL
              systemctl start mysql
              systemctl enable mysql

              # Secure MySQL installation (set root password)
              mysql -e "ALTER USER 'root'@'localhost' IDENTIFIED WITH mysql_native_password BY 'YourStrongPassword123!';"
              mysql -e "DELETE FROM mysql.user WHERE User='';"
              mysql -e "DELETE FROM mysql.user WHERE User='root' AND Host NOT IN ('localhost', '127.0.0.1', '::1');"
              mysql -e "DROP DATABASE IF EXISTS test;"
              mysql -e "DELETE FROM mysql.db WHERE Db='test' OR Db='test\_%';"
              mysql -e "FLUSH PRIVILEGES;"

              # Create a sample database
              mysql -u root -pYourStrongPassword123! -e "CREATE DATABASE sample_db;"
              mysql -u root -pYourStrongPassword123! -e "CREATE USER 'dbuser'@'%' IDENTIFIED BY 'DbPassword123!';"
              mysql -u root -pYourStrongPassword123! -e "GRANT ALL PRIVILEGES ON sample_db.* TO 'dbuser'@'%';"
              mysql -u root -pYourStrongPassword123! -e "FLUSH PRIVILEGES;"
              EOF

  tags = {
    Name        = "MySQL-Database-Server"
    Environment = "Development"
    Purpose     = "MySQL-Database"
  }
}

resource "aws_lightsail_instance_public_ports" "mysql_ports" {
  instance_name = aws_lightsail_instance.mysql_server.name

  port_info {
    protocol  = "tcp"
    from_port = 22
    to_port   = 22
    cidrs     = ["0.0.0.0/0"]
  }

  port_info {
    protocol  = "tcp"
    from_port = 3306
    to_port   = 3306
    cidrs     = ["0.0.0.0/0"]
  }
}

output "instance_public_ip" {
  description = "Public IP address of the Lightsail instance"
  value       = aws_lightsail_instance.mysql_server.public_ip_address
}

output "instance_private_ip" {
  description = "Private IP address of the Lightsail instance"
  value       = aws_lightsail_instance.mysql_server.private_ip_address
}

output "mysql_connection_string" {
  description = "MySQL connection information"
  value       = "mysql -h ${aws_lightsail_instance.mysql_server.public_ip_address} -u dbuser -p sample_db"
}

