terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket
resource "aws_s3_bucket" "lightsail_bucket" {
  bucket = "lightsail-access-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM Role for Lightsail Instance
resource "aws_iam_role" "lightsail_s3_role" {
  name = "lightsail-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lightsail.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 Access
resource "aws_iam_role_policy" "lightsail_s3_policy" {
  name = "lightsail-s3-access-policy"
  role = aws_iam_role.lightsail_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.lightsail_bucket.arn,
          "${aws_s3_bucket.lightsail_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Lightsail Instance
resource "aws_lightsail_instance" "server" {
  name              = "lightsail-server"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2023"
  bundle_id         = "nano_3_0"

  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y aws-cli

    # Configure AWS credentials using instance metadata
    mkdir -p /root/.aws

    # Create a script to assume the role and configure credentials
    cat > /usr/local/bin/configure-s3-access.sh << 'SCRIPT'
    #!/bin/bash
    ROLE_ARN="${aws_iam_role.lightsail_s3_role.arn}"
    SESSION_NAME="lightsail-s3-session"

    CREDENTIALS=$(aws sts assume-role --role-arn $ROLE_ARN --role-session-name $SESSION_NAME --output json)

    export AWS_ACCESS_KEY_ID=$(echo $CREDENTIALS | jq -r .Credentials.AccessKeyId)
    export AWS_SECRET_ACCESS_KEY=$(echo $CREDENTIALS | jq -r .Credentials.SecretAccessKey)
    export AWS_SESSION_TOKEN=$(echo $CREDENTIALS | jq -r .Credentials.SessionToken)
    SCRIPT

    chmod +x /usr/local/bin/configure-s3-access.sh
  EOF

  tags = {
    Name = "Lightsail-S3-Access"
  }
}

# Output the bucket name and role ARN
output "s3_bucket_name" {
  value       = aws_s3_bucket.lightsail_bucket.id
  description = "Name of the S3 bucket"
}

output "iam_role_arn" {
  value       = aws_iam_role.lightsail_s3_role.arn
  description = "ARN of the IAM role for S3 access"
}

output "lightsail_instance_name" {
  value       = aws_lightsail_instance.server.name
  description = "Name of the Lightsail instance"
}

output "lightsail_public_ip" {
  value       = aws_lightsail_instance.server.public_ip_address
  description = "Public IP address of the Lightsail instance"
}
```

