provider "aws" {
  region = "us-east-1"
}

# S3 bucket for content origin
resource "aws_s3_bucket" "lightsail_origin" {
  bucket = "my-lightsail-distribution-origin"
}

# S3 bucket ownership controls
resource "aws_s3_bucket_ownership_controls" "lightsail_origin" {
  bucket = aws_s3_bucket.lightsail_origin.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# S3 bucket public access block
resource "aws_s3_bucket_public_access_block" "lightsail_origin" {
  bucket = aws_s3_bucket.lightsail_origin.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# S3 bucket ACL
resource "aws_s3_bucket_acl" "lightsail_origin" {
  depends_on = [
    aws_s3_bucket_ownership_controls.lightsail_origin,
    aws_s3_bucket_public_access_block.lightsail_origin,
  ]

  bucket = aws_s3_bucket.lightsail_origin.id
  acl    = "public-read"
}

# S3 bucket policy to allow Lightsail access
resource "aws_s3_bucket_policy" "lightsail_origin" {
  bucket = aws_s3_bucket.lightsail_origin.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.lightsail_origin.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.lightsail_origin]
}

# Upload sample content to S3
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.lightsail_origin.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from Lightsail Distribution!</h1></body></html>"
  content_type = "text/html"
  acl          = "public-read"

  depends_on = [aws_s3_bucket_acl.lightsail_origin]
}

# Lightsail Distribution with S3 origin
resource "aws_lightsail_distribution" "cdn" {
  name      = "my-lightsail-distribution"
  bundle_id = "small_1_0"

  origin {
    name          = "my-s3-origin"
    region_name   = aws_s3_bucket.lightsail_origin.region
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "default"
    }

    forwarded_query_strings {
      option = false
    }
  }

  is_enabled = true
}

# Attach S3 bucket to Lightsail Distribution
resource "aws_lightsail_bucket" "distribution_bucket" {
  name      = "my-lightsail-bucket"
  bundle_id = "small_1_0"
}

resource "aws_lightsail_bucket_access_key" "bucket_key" {
  bucket_name = aws_lightsail_bucket.distribution_bucket.id
}

# Output important information
output "distribution_domain_name" {
  description = "The domain name of the Lightsail distribution"
  value       = aws_lightsail_distribution.cdn.domain_name
}

output "s3_bucket_name" {
  description = "The name of the S3 bucket used as origin"
  value       = aws_s3_bucket.lightsail_origin.id
}

output "s3_bucket_regional_domain_name" {
  description = "The regional domain name of the S3 bucket"
  value       = aws_s3_bucket.lightsail_origin.bucket_regional_domain_name
}

output "distribution_status" {
  description = "The status of the Lightsail distribution"
  value       = aws_lightsail_distribution.cdn.status
}

