terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a Lightsail instance to serve as the origin
resource "aws_lightsail_instance" "origin" {
  name              = "lightsail-origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  tags = {
    Name        = "Lightsail Origin Instance"
    Environment = "production"
  }
}

# Create a static IP for the instance
resource "aws_lightsail_static_ip" "origin" {
  name = "lightsail-origin-static-ip"
}

# Attach static IP to the instance
resource "aws_lightsail_static_ip_attachment" "origin" {
  static_ip_name = aws_lightsail_static_ip.origin.name
  instance_name  = aws_lightsail_instance.origin.name
}

# Open HTTPS port for the instance
resource "aws_lightsail_instance_public_ports" "origin" {
  instance_name = aws_lightsail_instance.origin.name

  port_info {
    protocol  = "tcp"
    from_port = 443
    to_port   = 443
  }

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }
}

# Create a Lightsail Distribution with the instance as origin
resource "aws_lightsail_distribution" "main" {
  name      = "lightsail-cdn-distribution"
  bundle_id = "small_1_0"

  origin {
    name          = aws_lightsail_instance.origin.name
    region_name   = aws_lightsail_instance.origin.availability_zone
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "default"
    }

    forwarded_query_strings {
      option = false
    }
  }

  cache_behavior {
    path     = "/static/*"
    behavior = "cache"
  }

  cache_behavior {
    path     = "/api/*"
    behavior = "dont-cache"
  }

  is_enabled = true

  tags = {
    Name        = "Lightsail CDN Distribution"
    Environment = "production"
  }
}

# Output values
output "instance_public_ip" {
  description = "Public IP address of the Lightsail instance"
  value       = aws_lightsail_static_ip.origin.ip_address
}

output "instance_name" {
  description = "Name of the Lightsail instance"
  value       = aws_lightsail_instance.origin.name
}

output "distribution_domain_name" {
  description = "Domain name of the Lightsail distribution"
  value       = aws_lightsail_distribution.main.domain_name
}

output "distribution_id" {
  description = "ID of the Lightsail distribution"
  value       = aws_lightsail_distribution.main.id
}

output "distribution_status" {
  description = "Status of the Lightsail distribution"
  value       = aws_lightsail_distribution.main.status
}

