    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Glacier Vault
resource "aws_glacier_vault" "main" {
  name = "terraform-glacier-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "allow-glacier-access"
        Effect = "Allow"
        Principal = {
          AWS = data.aws_caller_identity.current.account_id
        }
        Action = [
          "glacier:InitiateJob",
          "glacier:GetJobOutput"
        ]
        Resource = "arn:aws:glacier:us-east-1:${data.aws_caller_identity.current.account_id}:vaults/terraform-glacier-vault"
      }
    ]
  })

  tags = {
    Name        = "terraform-glacier-vault"
    Environment = "production"
  }
}

# SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"

  tags = {
    Name = "glacier-notifications"
  }
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# IAM Role for Data Lifecycle Manager
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "dlm-lifecycle-role"
  }
}

# IAM Policy for DLM
resource "aws_iam_role_policy" "dlm_lifecycle_policy" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeInstances",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:EnableFastSnapshotRestores",
          "ec2:DescribeFastSnapshotRestores",
          "ec2:DisableFastSnapshotRestores",
          "ec2:CopySnapshot",
          "ec2:ModifySnapshotAttribute",
          "ec2:DescribeSnapshotAttribute"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*::snapshot/*"
      },
      {
        Effect = "Allow"
        Action = [
          "events:PutRule",
          "events:DeleteRule",
          "events:DescribeRule",
          "events:EnableRule",
          "events:DisableRule",
          "events:PutTargets",
          "events:RemoveTargets"
        ]
        Resource = "arn:aws:events:*:*:rule/AwsDataLifecycleRule.managed-cwe.*"
      }
    ]
  })
}

# DLM Lifecycle Policy for EBS Snapshots
resource "aws_dlm_lifecycle_policy" "snapshot_policy" {
  description        = "DLM lifecycle policy for EBS snapshots"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Daily snapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
      }

      retain_rule {
        count = 14
      }

      tags_to_add = {
        SnapshotCreator = "DLM"
        GlacierVault    = aws_glacier_vault.main.name
      }

      copy_tags = true
    }

    target_tags = {
      Backup = "true"
    }
  }

  tags = {
    Name        = "dlm-snapshot-policy"
    Environment = "production"
  }
}

# S3 Bucket for transition to Glacier (as S3 Glacier is a storage class)
resource "aws_s3_bucket" "glacier_transition" {
  bucket = "terraform-glacier-transition-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "glacier-transition-bucket"
    Environment = "production"
  }
}

# S3 Bucket Lifecycle Configuration to transition to Glacier
resource "aws_s3_bucket_lifecycle_configuration" "glacier_transition" {
  bucket = aws_s3_bucket.glacier_transition.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 365
    }
  }
}

# S3 Bucket Versioning
resource "aws_s3_bucket_versioning" "glacier_transition" {
  bucket = aws_s3_bucket.glacier_transition.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Output values
output "glacier_vault_arn" {
  description = "ARN of the Glacier vault"
  value       = aws_glacier_vault.main.arn
}

output "glacier_vault_name" {
  description = "Name of the Glacier vault"
  value       = aws_glacier_vault.main.name
}

output "dlm_policy_arn" {
  description = "ARN of the DLM lifecycle policy"
  value       = aws_dlm_lifecycle_policy.snapshot_policy.arn
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket with Glacier transition"
  value       = aws_s3_bucket.glacier_transition.id
}

output "sns_topic_arn" {
  description = "ARN of the SNS topic for Glacier notifications"
  value       = aws_sns_topic.glacier_notifications.arn
}

