provider "aws" {
  region = "us-east-1"
}

# S3 Glacier Vault
resource "aws_glacier_vault" "main" {
  name = "terraform-glacier-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "allow-glacier-access"
        Effect = "Allow"
        Principal = {
          AWS = data.aws_caller_identity.current.account_id
        }
        Action = [
          "glacier:InitiateJob",
          "glacier:GetJobOutput"
        ]
        Resource = "arn:aws:glacier:us-east-1:${data.aws_caller_identity.current.account_id}:vaults/terraform-glacier-vault"
      }
    ]
  })

  tags = {
    Name        = "terraform-glacier-vault"
    Environment = "production"
  }
}

# SNS Topic for Glacier notifications
