        SnapshotCreator = "DLM"
        GlacierVault    = aws_glacier_vault.main.name
      }

      copy_tags = true
    }

    target_tags = {
      Backup = "true"
    }
  }

  tags = {
    Name        = "dlm-snapshot-policy"
    Environment = "production"
  }
}

# S3 Bucket for transition to Glacier (as S3 Glacier is a storage class)
resource "aws_s3_bucket" "glacier_transition" {
  bucket = "terraform-glacier-transition-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "glacier-transition-bucket"
    Environment = "production"
  }
}

