resource "aws_glacier_vault_lock" "main" {
  vault_name              = aws_glacier_vault.main.name
  complete_lock           = true
  ignore_deletion_error   = false

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyDeleteArchive"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action = [
          "glacier:DeleteArchive"
        ]
