resource "aws_lb" "gateway" {
  name               = "gateway-load-balancer"
  load_balancer_type = "gateway"

  subnet_mapping {
    subnet_id = aws_subnet.gwlb_subnet_1.id
  }

  subnet_mapping {
    subnet_id = aws_subnet.gwlb_subnet_2.id
  }

  enable_cross_zone_load_balancing = true

  tags = {
    Name = "gateway-load-balancer"
  }
}

# Target Group for Gateway Load Balancer
resource "aws_lb_target_group" "gateway_tg" {
  name     = "gateway-tg"
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled  = true
    port     = 80
    protocol = "HTTP"
  }

  tags = {
    Name = "gateway-target-group"
  }
}

# Gateway Load Balancer Listener
resource "aws_lb_listener" "gateway_listener" {
  load_balancer_arn = aws_lb.gateway.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gateway_tg.arn
  }
}

# VPC Endpoint Service for Gateway Load Balancer
resource "aws_vpc_endpoint_service" "gwlb_endpoint_service" {
  acceptance_required        = false
  gateway_load_balancer_arns = [aws_lb.gateway.arn]

  tags = {
    Name = "gwlb-endpoint-service"
  }
}

# Outputs
output "gateway_load_balancer_arn" {
  description = "ARN of the Gateway Load Balancer"
  value       = aws_lb.gateway.arn
}

output "gateway_load_balancer_dns" {
  description = "DNS name of the Gateway Load Balancer"
  value       = aws_lb.gateway.dns_name
}

output "target_group_arn" {
  description = "ARN of the Target Group"
  value       = aws_lb_target_group.gateway_tg.arn
}

output "endpoint_service_name" {
  description = "Service name of the VPC Endpoint Service"
  value       = aws_vpc_endpoint_service.gwlb_endpoint_service.service_name
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  security_groups = [ aws_security_group.instance-sg.id ]
}

resource "aws_lb" "test" {
  load_balancer_type = "gateway"
  subnet_mapping {
    subnet_id = module.vpc.public_subnets[0]
  }
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = module.vpc.vpc_id

  health_check {
    port     = 80
    protocol = "HTTP"
  }
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

