  description = "PostgreSQL SSL mode"
  type        = string
  default     = "require"
}

# Configure PostgreSQL for minimal memory usage
resource "postgresql_extension" "pg_stat_statements" {
  name     = "pg_stat_statements"
  database = "postgres"
}

# Optimized configuration for minimal memory usage
resource "null_resource" "postgresql_memory_optimization" {
  provisioner "local-exec" {
    command = <<-EOT
      psql -h ${var.postgresql_host} -p ${var.postgresql_port} -U ${var.postgresql_username} -d postgres <<EOF
      -- Shared memory settings (minimal)
      ALTER SYSTEM SET shared_buffers = '128MB';

      -- Working memory (minimal per operation)
      ALTER SYSTEM SET work_mem = '4MB';
      ALTER SYSTEM SET maintenance_work_mem = '64MB';

      -- WAL settings (minimal)
      ALTER SYSTEM SET wal_buffers = '4MB';
      ALTER SYSTEM SET max_wal_size = '1GB';
      ALTER SYSTEM SET min_wal_size = '80MB';

      -- Connection settings (reduced)
      ALTER SYSTEM SET max_connections = '20';

      -- Query planner memory
      ALTER SYSTEM SET effective_cache_size = '256MB';

      -- Temporary file settings
      ALTER SYSTEM SET temp_buffers = '8MB';

      -- Autovacuum memory optimization
      ALTER SYSTEM SET autovacuum_work_mem = '32MB';
      ALTER SYSTEM SET autovacuum_max_workers = '2';

      -- Background writer (minimal)
      ALTER SYSTEM SET bgwriter_lru_maxpages = '100';

      -- Logging (minimal overhead)
      ALTER SYSTEM SET log_min_duration_statement = '1000';
      ALTER SYSTEM SET log_line_prefix = '%t ';
      ALTER SYSTEM SET log_statement = 'none';

      -- Disable unnecessary features
      ALTER SYSTEM SET track_activities = 'on';
      ALTER SYSTEM SET track_counts = 'on';
      ALTER SYSTEM SET track_io_timing = 'off';

      -- Reload configuration
      SELECT pg_reload_conf();
      EOF
    EOT

    environment = {
      PGPASSWORD = var.postgresql_password
    }
  }

  triggers = {
    always_run = timestamp()
  }
}

output "postgresql_memory_configuration" {
  description = "PostgreSQL memory optimization settings applied"
  value = {
    shared_buffers          = "128MB"
    work_mem                = "4MB"
    maintenance_work_mem    = "64MB"
    effective_cache_size    = "256MB"
    max_connections         = "20"
    wal_buffers            = "4MB"
    temp_buffers           = "8MB"
    autovacuum_work_mem    = "32MB"
    total_estimated_memory = "~512MB"
  }
}
```

