terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "snapshot_identifier" {
  description = "The identifier of the DB snapshot to restore from"
  type        = string
}

variable "db_instance_identifier" {
  description = "The identifier for the RDS instance"
  type        = string
  default     = "restored-rds-instance"
}

variable "db_instance_class" {
  description = "The instance class for the RDS instance"
  type        = string
  default     = "db.t3.micro"
}

variable "vpc_id" {
  description = "VPC ID where the RDS instance will be launched"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB subnet group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "CIDR blocks allowed to access the RDS instance"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

variable "publicly_accessible" {
  description = "Whether the RDS instance should be publicly accessible"
  type        = bool
  default     = false
}

variable "multi_az" {
  description = "Enable Multi-AZ deployment"
  type        = bool
  default     = false
}

variable "tags" {
  description = "Tags to apply to resources"
  type        = map(string)
  default = {
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "${var.db_instance_identifier}-subnet-group"
  subnet_ids = var.subnet_ids

  tags = merge(
    var.tags,
    {
      Name = "${var.db_instance_identifier}-subnet-group"
    }
  )
}

resource "aws_security_group" "rds" {
  name        = "${var.db_instance_identifier}-sg"
  description = "Security group for RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    description = "Allow MySQL/Aurora access"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  ingress {
    description = "Allow PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(
    var.tags,
    {
      Name = "${var.db_instance_identifier}-sg"
    }
  )
}

resource "aws_db_instance" "from_snapshot" {
  identifier             = var.db_instance_identifier
  snapshot_identifier    = var.snapshot_identifier
  instance_class         = var.db_instance_class
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  publicly_accessible    = var.publicly_accessible
  multi_az               = var.multi_az
  skip_final_snapshot    = true
  copy_tags_to_snapshot  = true

  tags = merge(
    var.tags,
    {
      Name = var.db_instance_identifier
    }
  )
}

output "rds_instance_id" {
  description = "The ID of the RDS instance"
  value       = aws_db_instance.from_snapshot.id
}

output "rds_instance_endpoint" {
  description = "The connection endpoint"
  value       = aws_db_instance.from_snapshot.endpoint
}

output "rds_instance_arn" {
  description = "The ARN of the RDS instance"
  value       = aws_db_instance.from_snapshot.arn
}

output "rds_instance_address" {
  description = "The hostname of the RDS instance"
  value       = aws_db_instance.from_snapshot.address
}

output "rds_instance_port" {
  description = "The port of the RDS instance"
  value       = aws_db_instance.from_snapshot.port
}

