extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "db_identifier" {
  description = "Database identifier"
  type        = string
  default     = "restored-database"
}

variable "db_instance_class" {
  description = "Database instance class"
  type        = string
  default     = "db.t3.medium"
}

variable "s3_bucket_name" {
  description = "S3 bucket containing the database backup"
  type        = string
}

variable "s3_ingestion_role_arn" {
  description = "IAM role ARN for S3 import"
  type        = string
}

variable "allocated_storage" {
  description = "Allocated storage in GB"
  type        = number
  default     = 100
}

variable "engine" {
  description = "Database engine (mysql or postgres)"
  type        = string
  default     = "mysql"
}

variable "engine_version" {
  description = "Database engine version"
  type        = string
  default     = "8.0"
}

variable "db_username" {
  description = "Master username for the database"
  type        = string
  default     = "admin"
}

variable "db_password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "vpc_id" {
  description = "VPC ID for the database"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the database subnet group"
  type        = list(string)
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "${var.db_identifier}-sg"
  description = "Security group for RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    description = "MySQL/Aurora"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  ingress {
    description = "PostgreSQL"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.db_identifier}-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "${var.db_identifier}-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "${var.db_identifier}-subnet-group"
  }
}

# IAM Role for S3 Import
resource "aws_iam_role" "rds_s3_import_role" {
  name = "${var.db_identifier}-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.db_identifier}-s3-import-role"
  }
}

# IAM Policy for S3 Access
resource "aws_iam_role_policy" "rds_s3_import_policy" {
  name = "${var.db_identifier}-s3-import-policy"
  role = aws_iam_role.rds_s3_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      }
    ]
  })
}

# RDS Instance with S3 Import
resource "aws_db_instance" "restored_db" {
  identifier     = var.db_identifier
  engine         = var.engine
  engine_version = var.engine_version
  instance_class = var.db_instance_class

  allocated_storage     = var.allocated_storage
  storage_type          = "gp3"
  storage_encrypted     = true
  max_allocated_storage = var.allocated_storage * 2

  db_name  = "restoreddb"
  username = var.db_username
  password = var.db_password

  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "mon:04:00-mon:05:00"

  skip_final_snapshot       = true
  final_snapshot_identifier = "${var.db_identifier}-final-snapshot"

  # S3 Import Configuration
  s3_import {
    source_engine         = var.engine
    source_engine_version = var.engine_version
    bucket_name           = var.s3_bucket_name
    bucket_prefix         = "backup/"
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }

  depends_on = [
    aws_iam_role_policy.rds_s3_import_policy
  ]

  tags = {
    Name        = var.db_identifier
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

output "db_endpoint" {
  description = "Database endpoint"
  value       = aws_db_instance.restored_db.endpoint
}

output "db_arn" {
  description = "Database ARN"
  value       = aws_db_instance.restored_db.arn
}

output "db_name" {
  description = "Database name"
  value       = aws_db_instance.restored_db.db_name
}

output "db_port" {
  description = "Database port"
  value       = aws_db_instance.restored_db.port
}

